-- Poems batch 266
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('cf9a175a-da5c-4eb9-9645-ee3bb1bfbf01','入東林寺','董嗣杲','宋','宋诗','song-poetry','','[]','晴向過溪亭下留，拂碑慨想晉時流。',64,'全唐诗/poet.song.237000.json','["晴向過溪亭下留，拂碑慨想晉時流。", "雲生古樹蔦蘿雨，風捲脩廊松竹秋。", "登閣冷知山撲面，照池凉覺水澄眸。", "捻香禮遍逺公墓，僧舍乞茶談趙州。"]'),
('8c7fcf5e-5741-4589-8bc6-2ec45ade26a7','泊楊港  其一','董嗣杲','宋','宋诗','song-poetry','','[]','蒲帆發處渺回程，楊港漁家晚飯晴。',64,'全唐诗/poet.song.237000.json','["蒲帆發處渺回程，楊港漁家晚飯晴。", "日轉江空風勢緊，水浮樹秃雪枝明。", "饑腸戀酒垂涎覔，愁眼供詩就口成。", "天念奚嚢向艱澁，故令歲晚迓春行。"]'),
('539a96d2-1d77-4c60-8f70-d706a6069038','泊楊港  其二','董嗣杲','宋','宋诗','song-poetry','','[]','龍華寺北板橋平，幾户淮民結屋成。',64,'全唐诗/poet.song.237000.json','["龍華寺北板橋平，幾户淮民結屋成。", "屢向封疆窺版籍，獨遊淮海陋功名。", "去年過此曾尋勝，今日逢人似隔生。", "懐抱激昂無可制，埋篷心折聽江聲。"]'),
('8847a047-0839-4e42-823d-dac5a5c6e7ec','寓富池雙泉寺三首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','蟄龍潜介入寒？極目滄江浪不生。',63,'全唐诗/poet.song.237000.json','["蟄龍潜介入寒？極目滄江浪不生。", "沙渡觧舟人語衆，淮山縱火燒風鳴。", "身棲蕭寺蓬窗久，雪壓槃塘草店明。", "莫說此爲孤陋地，白雲流水助吟情。"]'),
('42381e5f-9212-42a8-abe3-067f50679c6e','寓富池雙泉寺三首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','丹楓葉葉委江塘，旅况空餘古錦嚢。',64,'全唐诗/poet.song.237000.json','["丹楓葉葉委江塘，旅况空餘古錦嚢。", "闕下有家勞夢寐，燈前無酒遣荒凉。", "陳蹤浮泛棲僧舍，往事消磨落客床。", "世態自應酬酢懶，已拚雙鬢受年光。"]'),
('61b33591-b10a-447f-8e23-8a027f4e5713','寓富池雙泉寺三首  其三','董嗣杲','宋','宋诗','song-poetry','','[]','晚來抱懶炙孤燈，臨水禪樓獨自登。',64,'全唐诗/poet.song.237000.json','["晚來抱懶炙孤燈，臨水禪樓獨自登。", "鳥道草深雲宛宛，魚湖波定月澄澄。", "詩聫呈佛方堪讀，俗語汚人不可譍。", "歸隠南峯峯下宅，縱談今日豈無僧。"]'),
('a62894a5-868f-4264-9eff-546a67ef046f','銀樹道上','董嗣杲','宋','宋诗','song-poetry','','[]','銀林驛路雪離披，行迹茫茫自苦悲。',64,'全唐诗/poet.song.237000.json','["銀林驛路雪離披，行迹茫茫自苦悲。", "不忍早梅經細雨，却欣折竹壓枯籬。", "身嫌出陸肩輿破，足涉沿溪口岸遲。", "荒店無人塵滿釜，豈堪獨力任晨炊。"]'),
('217f8da5-3980-4d5d-8406-23748c1f86f8','雪阻李家渡','董嗣杲','宋','宋诗','song-poetry','','[]','迹寄郵程冒冷雲，病身染透客衣塵。',64,'全唐诗/poet.song.237000.json','["迹寄郵程冒冷雲，病身染透客衣塵。", "欹傾茅店清眠雪，想像梅村逺醉春。", "樵子獨還衣缷濕，篙人相告酒賒頻。", "荒鷄唱斷天將曙，快觧孤篷野渡濵。"]'),
('4dca5c14-d227-4fe7-afe7-040caf07b92e','泊雷江','董嗣杲','宋','宋诗','song-poetry','','[]','沽酒難澆傀儡胸，風平浪息臥孤篷。',64,'全唐诗/poet.song.237000.json','["沽酒難澆傀儡胸，風平浪息臥孤篷。", "寒知僵艤雷江口，醒落狂吟雪店中。", "勞去有身侔病鶴，愁回無耳聽哀鴻。", "行人那比淮人逸，豆飯藜羮樂歲終。"]'),
('39a80bd5-818e-48fb-9242-11fd85aaa731','入廬山感興','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','古翠深中擁紫烟，幽行先酌石溪泉。',64,'全唐诗/poet.song.237000.json','["古翠深中擁紫烟，幽行先酌石溪泉。", "未能耕野安愚分，且樂遊山趁壯年。", "五色在前難障礙，連鑣來此可留連。", "杏花林裏閒風月，况有宗人演地仙。"]'),
('7363315c-631f-40cb-b9af-c9f1018a3695','廬山道中','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','疊疊蒼巒别是天，往來即是地行仙。',64,'全唐诗/poet.song.237000.json','["疊疊蒼巒别是天，往來即是地行仙。", "撥雲峰底落紅雨，冷翠谷中浮紫烟。", "樹色浄依山色古，樵聲清共瀑聲傳。", "逺公不作淵明醉，結社徒然懐白蓮。"]'),
('466854b7-2c6c-4ef9-8f79-f6e07a909a5a','馬頭渡','董嗣杲','宋','宋诗','song-poetry','','[]','幾回問渡野陰濃，趁早相呼艤短篷。',64,'全唐诗/poet.song.237000.json','["幾回問渡野陰濃，趁早相呼艤短篷。", "千里晚沈鴻翼信，片帆凉卸馬頭風。", "官坊酒濁秋旗破，客店人荒晚釜空。", "量取異鄉愁幾斛，只須傾瀉錦嚢中。"]'),
('7acc5446-98bb-4342-8aff-654e7f37ea1b','江城懐隠','董嗣杲','宋','宋诗','song-poetry','','[]','病身尚蟄灌嬰城，歸夢長懸醒復成。',64,'全唐诗/poet.song.237000.json','["病身尚蟄灌嬰城，歸夢長懸醒復成。", "衰鬢褵褷攙鶴痩，安書隔闊見鴻驚。", "山遥晴有侵簷色，樹秃秋無撼野聲。", "只欲養疴求退靜，棲遲泉石適歸情。"]'),
('65596240-6897-4f88-bbed-aef3791e5460','重過清虚庵','董嗣杲','宋','宋诗','song-poetry','','[]','絕境惟聞天籟音，山遊重綴壁龕吟。',64,'全唐诗/poet.song.237000.json','["絕境惟聞天籟音，山遊重綴壁龕吟。", "春生仙甕新篘酒，塵鎖書床舊調琴。", "丹井月空梧積滿，瑶臺雨漬蘚埋深。", "明朝襆被歸城市，萬叠蒼巒有夢尋。"]'),
('2116b4de-1922-409c-a8a3-c49c522c277e','晚過陳峰廨酒邉懐舊','董嗣杲','宋','宋诗','song-poetry','','[]','相過失喜晚炊香，同坐閒曹况味長。',64,'全唐诗/poet.song.237000.json','["相過失喜晚炊香，同坐閒曹况味長。", "江日下山雲半赤，淮柑離土葉全黄。", "殊鄉酒味聊濡口，弔古詩章易刺腸。", "憶得舊邀梅院醉，萬燈環錦閣新装。"]'),
('970769f0-4afe-4f9b-afc6-c7363a38e357','秋夜對雨','董嗣杲','宋','宋诗','song-poetry','','[]','對月飛觴往事休，胡床寂寞庾公樓。',64,'全唐诗/poet.song.237000.json','["對月飛觴往事休，胡床寂寞庾公樓。", "西風觧使蛩専夜，長日能無酒送愁。", "新鴈陣分離塞徼，殘螢火死落汀流。", "醉來獨臥梧窗下，靜聽胡琴撥怨秋。"]'),
('f16229b8-5332-47bc-b531-f8572a3506db','潯陽館晚歩','董嗣杲','宋','宋诗','song-poetry','','[]','獨下閒階信杖行，虚空萬籟挾秋聲。',64,'全唐诗/poet.song.237000.json','["獨下閒階信杖行，虚空萬籟挾秋聲。", "天連淮樹千章暗，月照廬峰九叠明。", "舊信傳訛寒鴈過，短生催老曉鷄鳴。", "可憂何止心頭事，戍接荆流尚甲兵。"]'),
('997f79ba-a9bb-4fa6-acb8-41a34bc9e4aa','廣濟縣','董嗣杲','宋','宋诗','song-poetry','','[]','雲罨廳簷草擁門，荻花掠岸雪紛紛。',64,'全唐诗/poet.song.237000.json','["雲罨廳簷草擁門，荻花掠岸雪紛紛。", "龍行費聖祠前雨，鴉聚甘王墓上雲。", "絕巘樹環孤市盡，亂溪水入大江分。", "邑民還有思蓴興，簾底琴聲寂不聞。"]'),
('db69e92c-4db2-438c-b80d-1e50e436ac87','蕪湖縣','董嗣杲','宋','宋诗','song-poetry','','[]','雲檣風柂艤江湄，客寄何心聽是非。',64,'全唐诗/poet.song.237000.json','["雲檣風柂艤江湄，客寄何心聽是非。", "國課轉虧商旅瘠，縣官頻易吏胥肥。", "花迷夜市燈初合，柳匝寒田水自圍。", "今古通津離别地，曉沙晴日出蟂磯。"]'),
('13a4d901-dbf8-4acf-9e73-68aa49c1671e','泊廬江縣界幾遭宼掠','董嗣杲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','酒興那如歸興濃，此行誰信破嚢空。',64,'全唐诗/poet.song.237000.json','["酒興那如歸興濃，此行誰信破嚢空。", "扁舟小艤廬江外，雨夜深埋虎穴中。", "獨客痛心無可說，何人料事偶相同。", "昏時抛過銅陵去，不管長江起北風。"]'),
('8364ea60-92ce-4561-ad70-a5e719a6a211','天池寺','董嗣杲','宋','宋诗','song-poetry','','[]','吳說天池兩字真，梵坊突兀鼓鐘聲。',64,'全唐诗/poet.song.237000.json','["吳說天池兩字真，梵坊突兀鼓鐘聲。", "聖燈逐夜朝文閣，雷火何年損相輪。", "足下有雲如隔世，眼前無地可容塵。", "追嚴不枉祠忠定，招得吟僧作主人。"]'),
('2e21d686-bde2-420b-8150-d20b07e79464','秋凉懐歸三首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','清幽自足倚繩床，雨過浮雲斂八荒。',64,'全唐诗/poet.song.237000.json','["清幽自足倚繩床，雨過浮雲斂八荒。", "雄郭西風鳴夜籟，太虚凉夜瀉秋光。", "槐花綴粉粘苔砌，桂子飄香入草堂。", "倦臥不知身是客，殘燈欲滅泣寒螿。"]'),
('d014e0e6-6605-4700-a9e2-aaa041121799','秋凉懐歸三首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','風凉贏得四肢清，泛寄誰知去就輕。',64,'全唐诗/poet.song.237000.json','["風凉贏得四肢清，泛寄誰知去就輕。", "臨水有亭秋更净，對花無酒月空明。", "鴈行愁落荒汀逺，梧葉寒填露井平。", "獨遶曲廊心汗漫，附書千里述羈情。"]'),
('c793e3a9-2856-4b66-844b-aa04c3bd7488','秋凉懐歸三首  其三','董嗣杲','宋','宋诗','song-poetry','','[]','元龍減盡舊時豪，尚落湓江枕怒濤。',64,'全唐诗/poet.song.237000.json','["元龍減盡舊時豪，尚落湓江枕怒濤。", "月下聽歌情浩蕩，燈前支病髪蕭騷。", "少年偶負投機愧，今日徒工煮字勞。", "歸興已濃秋思壮，垂虹亭上問三髙。"]'),
('d39875fc-4584-44ea-a001-a7de7458f7ed','回至興國宫望天池一簇雲氣中因楊道士留有賦','董嗣杲','宋','宋诗','song-poetry','','[]','迎面蒼巒潑黛濃，幾番回首想行踪。',64,'全唐诗/poet.song.237000.json','["迎面蒼巒潑黛濃，幾番回首想行踪。", "白雲擁海文殊閣，老水屯烟聖治峰。", "方别衲僧談夢寐，又逢羽士接從容。", "明朝還踏青虚路，重掬神泉聽亂鐘。"]'),
('2b078c2e-3fdc-4d79-a8c6-7f2910fe49ae','次韻重九','董嗣杲','宋','宋诗','song-poetry','','[]','懐古憑髙厭客身，秋深愁望隔江城。',64,'全唐诗/poet.song.237000.json','["懐古憑髙厭客身，秋深愁望隔江城。", "狂支靈運東山屐，醉漉淵明栗里巾。", "楚澤豈無餐菊友，漢宫還有佩茰人。", "今年不作風和雨，見得南山面目真。"]'),
('e3b8a9b4-68ce-4e25-95c7-69ea49382794','重歎','董嗣杲','宋','宋诗','song-poetry','','[]','心知天地厭羈留，癡坐忘言不點頭。',64,'全唐诗/poet.song.237000.json','["心知天地厭羈留，癡坐忘言不點頭。", "活脱世間泥塑様，癡貽江表陸沉羞。", "思仙廨竹招蒼鳳，學老溪梅縛翠虬。", "歲晚說歸何所待，厚顔安足恥時流。"]'),
('de2ba6e6-ee0f-46a3-956b-3047ec90e507','遊蛇崗嶺庵','董嗣杲','宋','宋诗','song-poetry','','[]','遊歷貪行入暮驚，蛇崗嶺北衲庵清。',64,'全唐诗/poet.song.237000.json','["遊歷貪行入暮驚，蛇崗嶺北衲庵清。", "西風掃葉秋初勁，野火燒空曉尚明。", "塵役未能抛白日，仙家不獨有青城。", "借眠熟睡全無夢，服了黄精體自輕。"]'),
('1ed64ade-9a6a-42fb-a62c-217006ab26db','寄湖口張監渡','董嗣杲','宋','宋诗','song-poetry','','[]','寂寞郵亭紫翠中，有懐不得逺相從。',64,'全唐诗/poet.song.237000.json','["寂寞郵亭紫翠中，有懐不得逺相從。", "渡頭幾發東西棹，西角長鳴上下鐘。", "江晚燕鴻秋信杳，野凉桑棗綠陰重。", "天空水濶雲查斷，收拾新詩寄興濃。"]'),
('13838b17-7ab8-40d6-be7e-bcd4df5a7421','寄周堂長','董嗣杲','宋','宋诗','song-poetry','','[]','回首大江秋水西，杖藜閒歩菊花籬。',64,'全唐诗/poet.song.237000.json','["回首大江秋水西，杖藜閒歩菊花籬。", "百年清白甕中酒，萬事安危枰上棊。", "夢入莊生迷蝶處，歌窮甯子飯牛時。", "西風徐榻獨棲慣，屋枕濓溪雲錦池。"]'),
('b4413418-2b78-4f2a-838a-1384036ad242','舟行不及遊九華','董嗣杲','宋','宋诗','song-poetry','','[]','下水風帆勢若浮，雪深且向貴池留。',64,'全唐诗/poet.song.237000.json','["下水風帆勢若浮，雪深且向貴池留。", "兩三漁艇有歌送，咫尺仙家無分遊。", "劍削山稜雲氣直，鏡涵江影日光流。", "神馳杜牧題詩處，客裏光陰别是愁。"]'),
('5a6aee63-02d5-4bed-8b0f-19d273254c13','和翟建大見寄','董嗣杲','宋','宋诗','song-poetry','','[]','鄉人誼槩如公少，彭澤辭歸過永興。',64,'全唐诗/poet.song.237000.json','["鄉人誼槩如公少，彭澤辭歸過永興。", "合向校讎爭地歩，屈於監當負聲稱。", "故家吳苑頻回首，新治淮山任曲肱。", "見說沍寒移足懶，只凴紅粉勝扶藤。"]'),
('7bbf2f3f-0970-413b-8c34-df76923e708b','訪三橋歩隠者','董嗣杲','宋','宋诗','song-poetry','','[]','翠竹蒼松貼屋牢，屋前徑狹長蓬蒿。',64,'全唐诗/poet.song.237000.json','["翠竹蒼松貼屋牢，屋前徑狹長蓬蒿。", "蒲團坐久侵肌薄，柏子焚來結氣髙。", "山雨濕蝸腥薜荔，野煙蔽鵲損櫻桃。", "終期脱跡相從去，參取玄微學鄭遨。"]'),
('96bbfc09-deb6-4f4f-b067-3c436eaaf1ae','過富池水軍寨統轄姚子雄公廨略棲遲且有約同上杭京','董嗣杲','宋','宋诗','song-poetry','','[]','春雲冷壓渡頭槎，春色晴翻浦際沙。',64,'全唐诗/poet.song.237000.json','["春雲冷壓渡頭槎，春色晴翻浦際沙。", "並浴鵁鶄依水柳，成圍蝴蝶舞江花。", "富池軍額無全籍，治邑農功有幾家。", "指日並馳天路去，莫揮客淚苦悲笳。"]'),
('714a4872-a73a-43e0-9bce-e2a93927a6fc','客寓無眠信口賦秋感','董嗣杲','宋','宋诗','song-poetry','','[]','赤楓又積灌城頭，如此江山不掩愁。',64,'全唐诗/poet.song.237000.json','["赤楓又積灌城頭，如此江山不掩愁。", "青眼無人同樂歲，白頭有句獨悲秋。", "詞章全拙知誰信，身世多虞謾自謀。", "籬角黄花消正色，北風更急莫登樓。"]'),
('2c77e06f-74d5-405f-ac0a-9225bf7e779c','客次狂吟','董嗣杲','宋','宋诗','song-poetry','','[]','野服支離號散仙，望晴閒倚柁樓前。',64,'全唐诗/poet.song.237000.json','["野服支離號散仙，望晴閒倚柁樓前。", "江山風月多尋酒，蘆荻汀洲幾泊船。", "水路愁疑孤障鴈，野廬清隔雨溪烟。", "來春不負笻枝去，楊柳橋西聽管絃。"]'),
('59092502-b2fb-4877-84cb-0d84425db77f','客久','董嗣杲','宋','宋诗','song-poetry','','[]','衣裳敝盡客遊闌，三月江城雨更寒。',64,'全唐诗/poet.song.237000.json','["衣裳敝盡客遊闌，三月江城雨更寒。", "小店有翁賒酒易，名園無主看花難。", "驅馳塵土身千里，荏苒光陰指一彈。", "種種舊愁歸杜宇，青山碧樹带愁看。"]'),
('132cd3f5-c1c1-4797-85d4-f6a47ece38a7','秋巖自山中見約','董嗣杲','宋','宋诗','song-poetry','','[]','九江驛裏見春風，幾度懐清隔曉鐘。',64,'全唐诗/poet.song.237000.json','["九江驛裏見春風，幾度懐清隔曉鐘。", "思白有人傷柳色，依劉無地感萍蹤。", "半生力學羞長劍，兩載心期信短笻。", "九疊屏髙有標致，逺公相約則吾從。"]'),
('8835bee2-2393-4687-b81a-4435039765cb','棠梨湖','董嗣杲','宋','宋诗','song-poetry','','[]','西城轉地有湖光，矮矮荆榛出土岡。',64,'全唐诗/poet.song.237000.json','["西城轉地有湖光，矮矮荆榛出土岡。", "爼豆零星傳野哭，舳艫聫絡急邊防。", "夾壕楊柳猶秋色，貼屋桃花自晚粧。", "芳草不除生意在，此名誰命謾華堂。"]'),
('a886b55c-a212-4fcb-a7a2-8b35fea210a5','泊接泥渡','董嗣杲','宋','宋诗','song-poetry','','[]','笑泊虚寒古渡沙，沉暉逺襯楚山霞。',64,'全唐诗/poet.song.237000.json','["笑泊虚寒古渡沙，沉暉逺襯楚山霞。", "江鄉酒薄難支日，客路詩多轉憶家。", "金彈耀林懸橘柚，翠綃縈浦泛蒹葭。", "船窗掩定身如石，籬落何人有菊花。"]'),
('2a52c508-1942-48e5-aea5-bf15878ec0ac','晚立接泥渡邊','董嗣杲','宋','宋诗','song-poetry','','[]','逍遥行樂立西風，多聽秋聲耳欲聾。',64,'全唐诗/poet.song.237000.json','["逍遥行樂立西風，多聽秋聲耳欲聾。", "供世難分心力異，浮家易感古今同。", "小花糝渡遺晴蓼，碎葉填津積冷楓。", "博望有槎撐不去，岸頭横卧樹心空。"]'),
('2d03600c-c1c5-44da-a7ad-071e5cc88da5','東林寺上方塔','董嗣杲','宋','宋诗','song-poetry','','[]','塵外乾坤豈易窺，上方尋勝短笻隨。',64,'全唐诗/poet.song.237000.json','["塵外乾坤豈易窺，上方尋勝短笻隨。", "病僧借榻山衣破，卧佛當門石塔危。", "亂竹迸階交密樹，荒苔沿壁纒疎枝。", "幅巾居士修行久，愛說浮光死戰時。"]'),
('f907521c-2daa-41d0-a190-37032b59958e','蘄城晚泊值雪','董嗣杲','宋','宋诗','song-poetry','','[]','鴈聲哀怨極淮天，際晚驚呼雪打船。',64,'全唐诗/poet.song.237000.json','["鴈聲哀怨極淮天，際晚驚呼雪打船。", "古驛魚稀誰撒網，虚沙馬過自隨鞭。", "人烟頑獷空多智，形勝丘墟又幾年。", "龍眼磯頭風浪惡，今宵歸興此方堅。"]'),
('801050cc-fb76-4491-965c-76d42079e6c9','壬戌元日二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','青燈挑雨曉光凝，歲律回壬萬象新。',64,'全唐诗/poet.song.237000.json','["青燈挑雨曉光凝，歲律回壬萬象新。", "心上痛懐松里友，客中忍視茗山春。", "誰横烟竹驚孤旅，自飲屠蘇笑八神。", "摺起朝衣羞老去，驅車猶冒路岐塵。"]'),
('7a469d72-607b-4de6-8a83-aae4ae728dd6','壬戌元日二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','萬里東風起楚皋，流年祗染鬢蕭騷。',64,'全唐诗/poet.song.237000.json','["萬里東風起楚皋，流年祗染鬢蕭騷。", "富池江口聽春雨，昭勇樓心看雪濤。", "薄俗苦無公可論，全身惟有隠方髙。", "故山猿鶴應相笑，抗走殊鄉實自勞。"]'),
('96045550-7665-49c0-9da7-cb8c903efdd4','富池客中寄范葯庄','董嗣杲','宋','宋诗','song-poetry','','[]','客子驚秋易斷魂，江塘落葉雨紛紛。',64,'全唐诗/poet.song.237000.json','["客子驚秋易斷魂，江塘落葉雨紛紛。", "蔽江雲勢山頭合，隔竹泉聲屋尾分。", "無日不宜閒問酒，有懐猶且强摛文。", "燈窗幾憶同居話，卷裏新篇可得聞。"]'),
('033ff28a-84a8-4b02-b344-6df929e55a30','寄楊雲静','董嗣杲','宋','宋诗','song-poetry','','[]','公藉椒塗成達宦，我傳草檄守清貧。',64,'全唐诗/poet.song.237000.json','["公藉椒塗成達宦，我傳草檄守清貧。", "閒曹奔走徒云仕，薄俸沾濡不逮親。", "飲水曲肱無此量，解衣推食有何人。", "凉風四壁蛩新咽，偏惱淹回獨客身。"]'),
('90adca18-0de4-4281-aa1e-d602d1f23d44','東林寺贈宜上人','董嗣杲','宋','宋诗','song-poetry','','[]','幽階苔蘚翠纎纎，屐齒沾濡逐步黏。',64,'全唐诗/poet.song.237000.json','["幽階苔蘚翠纎纎，屐齒沾濡逐步黏。", "曉澗迸泉迷杏塢，春風停雨暗茅簷。", "禪髙何待音聲悟，詩好争傳格律嚴。", "誰凂我師重主社，社中休更外陶潛。"]'),
('d62f1874-71d3-4cd1-b91c-51483c82cad5','寄冷翠谷葛秋巖','董嗣杲','宋','宋诗','song-poetry','','[]','入眼萬欲勇舍難，巖頭飄盡楓葉丹。',64,'全唐诗/poet.song.237000.json','["入眼萬欲勇舍難，巖頭飄盡楓葉丹。", "心憎湓浦户庭熱，身入廬峯毛骨寒。", "塵面只掬野泉洗，醉吟且呈泥佛看。", "幾多清話動人憶，夢落成圍蒼竹竿。"]'),
('43a7290a-c837-47ec-b7b0-2578bc3789ea','鏡禪人欲歸靈隠','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','袈裟裹定老禪翁，雲隔家鄉是幾重。',64,'全唐诗/poet.song.237000.json','["袈裟裹定老禪翁，雲隔家鄉是幾重。", "兩面廬山曾徧覽，三生天竺會相逢。", "揺凉竹箑收江羽，醒困茶甌瀹建龍。", "午借客床尋偃息，不知身在紫霄峯。"]'),
('3a20b874-2a9c-4cf5-8cf1-c671426d3aa5','贈羅漢院志逺上人','董嗣杲','宋','宋诗','song-poetry','','[]','披緇受業在淮南，不覺流年七十三。',64,'全唐诗/poet.song.237000.json','["披緇受業在淮南，不覺流年七十三。", "羅漢院中餘古柏，將軍墳上落枯杉。", "纒綿宿病逢奇藥，收拾頽年坐破龕。", "自說舊棲真佛境，羅田山裏毒龍潭。"]'),
('a1441e89-277a-4b6f-ba39-758b37917552','江城與秋巖同賦','董嗣杲','宋','宋诗','song-poetry','','[]','江柳青青暗古津，悲歌不獨是商人。',64,'全唐诗/poet.song.237000.json','["江柳青青暗古津，悲歌不獨是商人。", "愁生獨醉重闗晚，夢破相思故國春。", "聲迹衰遲難應世，山林枯朽易全身。", "歸期渺邈徒懐想，怨鳥花梢叫月頻。"]'),
('079d028a-28c5-4d28-8e4d-288b977c119f','蒙叟悟禪人俗舍在湖口縣予留江城聞其歸省且有書貺因寄二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','要識閒棲彼此輕，平江浪逺暮帆晴。',64,'全唐诗/poet.song.237000.json','["要識閒棲彼此輕，平江浪逺暮帆晴。", "青春晚處羈懐惡，白髮生時老眼明。", "花落無心尋笑傲，客鄉有日苦逢迎。", "雲包尚寄雙鍾下，若過吾廬祗半程。"]'),
('e59c1608-0dcb-4019-b31f-652ffa050e37','蒙叟悟禪人俗舍在湖口縣予留江城聞其歸省且有書貺因寄二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','富池歸去欲相從，幾想蒼雲碧樹東。',64,'全唐诗/poet.song.237000.json','["富池歸去欲相從，幾想蒼雲碧樹東。", "夜月庾樓懐抱在，春風陶徑夢魂通。", "前峯路斷鋤犂少，古渡征苛網罟空。", "難語數年牢落恨，千林如海夕陽紅。"]'),
('ba84141a-24bb-4de1-b367-635147454e46','留江城','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','灌城眠食嘆羈身，憑曉偏驚索鏡心。',64,'全唐诗/poet.song.237000.json','["灌城眠食嘆羈身，憑曉偏驚索鏡心。", "南紀山川秋望逺，西湖風月夜懐深。", "功名鬼妬投機罕，詩酒天嗔絕侣尋。", "陳跡自應遅料事，斷鴻信杳况雲陰。"]'),
('94184f97-78be-4698-9ed8-cda66dcbe211','贈封禺山翁','董嗣杲','宋','宋诗','song-poetry','','[]','鵓鴣鳴雨鶴吟風，可羡山中白髮翁。',64,'全唐诗/poet.song.237000.json','["鵓鴣鳴雨鶴吟風，可羡山中白髮翁。", "百事不聞天地閉，四窗常見水煙空。", "春時聚社尋屠伯，晴晝科書授學童。", "此外惟知安分去，鹿門真隠畧相同。"]'),
('b5a1068c-ead3-47e5-8564-e4b85d78e8fc','淫祀','董嗣杲','宋','宋诗','song-poetry','','[]','水泛牌頭五里亭，尚留破廟壓空坰。',64,'全唐诗/poet.song.237000.json','["水泛牌頭五里亭，尚留破廟壓空坰。", "松蘿陰覆鴉羣怪，里社聲傳土偶靈。", "幡裊欹竿三丈赤，溪分荒藻數叢青。", "頭陀强解愚夫卜，瓶缶花香带肉腥。"]'),
('42eecd93-3f77-4802-a03d-e9b479644fad','寓江州西城','董嗣杲','宋','宋诗','song-poetry','','[]','奔忙夢落富池程，歸托蘧廬戀灌城。',64,'全唐诗/poet.song.237000.json','["奔忙夢落富池程，歸托蘧廬戀灌城。", "有石醉乘新月坐，無家吟逐亂雲行。", "衣遺母線寒針在，燒起公山晚陣嗚。", "鄰屋酒香堪洗恨，擬栽松菊傚淵明。"]'),
('eae84386-b411-4aa8-86a7-63a3eae8375c','暑中訪平山坦上人','董嗣杲','宋','宋诗','song-poetry','','[]','遥遥殊積入山心，勇涉湖西且解襟。',64,'全唐诗/poet.song.237000.json','["遥遥殊積入山心，勇涉湖西且解襟。", "當暑行松探古跡，追凉踏蘚入晴林。", "信知浄境無三伏，猶幸慳囊有幾金。", "白酒青衣隨所遇，此來祗爲此僧尋。"]'),
('4b2e9342-195c-4f43-aef7-f511a54351ac','思歸','董嗣杲','宋','宋诗','song-poetry','','[]','秋老江城起戍塵，山收西日掩雲津。',64,'全唐诗/poet.song.237000.json','["秋老江城起戍塵，山收西日掩雲津。", "留連光景多無酒，俛仰風埃獨有身。", "曠野鴈填遺陣闊，虚沙船發落痕新。", "故園松菊猶三逕，夢過煙霞水石鄰。"]'),
('0715dc68-3efe-4327-89e0-21d098f4f5f7','晚過張分司園','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','偶乘意度過東鄰，芳艶多情媚柳津。',64,'全唐诗/poet.song.237000.json','["偶乘意度過東鄰，芳艶多情媚柳津。", "歡笑直邀雲際月，酣歌狂惜雨餘春。", "亭臺花木銷官酒，城郭風煙老客身。", "回首廬山圖畫裏，不知愁落軟紅塵。"]'),
('01ac21c4-4ac9-435f-9e9a-2f97fc0ac3f5','題濂溪書院','董嗣杲','宋','宋诗','song-poetry','','[]','逺徑溪流水自圓，光風霽月渺無邊。',64,'全唐诗/poet.song.237000.json','["逺徑溪流水自圓，光風霽月渺無邊。", "窗前生意休除草，堂上清風獨愛蓮。", "萬古共知歸有極，一塵不染見先天。", "未知涵味其中者，誰是元翁得正傳。"]'),
('9aac9a47-a9fd-49c3-b78d-e2c9c4225ade','登庾樓  其一','董嗣杲','宋','宋诗','song-poetry','','[]','重支瘦竹上危樓，凉襲綸巾羽扇秋。',64,'全唐诗/poet.song.237000.json','["重支瘦竹上危樓，凉襲綸巾羽扇秋。", "天地江山風浪起，汀洲蘆荻水煙浮。", "誰聽調夜琵琶苦，擬泛吟秋舴艋遊。", "喚得元規魂夢醒，何妨小作踞床留。"]'),
('9cd243ce-b89d-4753-96ad-bc42e2af3778','登庾樓  其二','董嗣杲','宋','宋诗','song-poetry','','[]','千年傳說庾公遊，逺戍秋塵障兩眸。',64,'全唐诗/poet.song.237000.json','["千年傳說庾公遊，逺戍秋塵障兩眸。", "往事未知誰可語，今朝聊復此登樓。", "淮山鳥去衝烟滅，楚澤帆歸带日收。", "閒客望窮江北晚，月明無賴幾沙洲。"]'),
('1ab04c30-2997-4c23-9255-8311e31e3179','顧城','董嗣杲','宋','宋诗','song-poetry','','[]','初聞春日水天迷，此際湖沙擁岸肥。',64,'全唐诗/poet.song.237000.json','["初聞春日水天迷，此際湖沙擁岸肥。", "炊甑有塵籼米腐，酒坊無壁紙旗飛。", "猿棲曉樹青藤瘦，雀啄冬畦白菜稀。", "寂寞旅懐禁得否，斷腔漁笛釣船歸。"]'),
('92c414b3-7c75-4f02-a220-48d38f6404da','新橋遇秋巖','董嗣杲','宋','宋诗','song-poetry','','[]','出郭看山眼便醒，故人相值說雲萍。',64,'全唐诗/poet.song.237000.json','["出郭看山眼便醒，故人相值說雲萍。", "了翁屋後晚煙碧，茂叔阡頭秋草青。", "絕壑雨過溪水響，髙峯月上谷雲停。", "烏巾漉酒菊花店，醉揀陶詩書紙屏。"]'),
('aeac9e66-bb22-40d9-ac52-b738ad7a7e77','富池客中','董嗣杲','宋','宋诗','song-poetry','','[]','捨舟遵陸幾程來，家事身謀兩未諧。',64,'全唐诗/poet.song.237000.json','["捨舟遵陸幾程來，家事身謀兩未諧。", "九地渺茫憐骨肉，四方軒豁暢襟懐。", "雨翻茶崦春離岳，風颭監旗曉渡淮。", "短景不延愁思逺，只堪長醉向茅柴。"]'),
('92dbf1a4-194f-46f3-8bdf-3be00f176bbb','舟上食菜粥甚美','董嗣杲','宋','宋诗','song-poetry','','[]','莫望池口浪接天，羈懐沉迷衾枕前。',64,'全唐诗/poet.song.237000.json','["莫望池口浪接天，羈懐沉迷衾枕前。", "老船蕩雪櫓聲澁，破釜煮粥蔬味便。", "烟鎖淮俗子城下，風生野坊僧樹巔。", "懶能登岸躡寒屐，因數杖頭無百錢。"]'),
('e458c811-2a00-4bec-96a7-7fd13aac0cd0','冷翠閣與秋巖同賦','董嗣杲','宋','宋诗','song-poetry','','[]','笑携琴冊上崑崙，分坐溪頭蘚石根。',64,'全唐诗/poet.song.237000.json','["笑携琴冊上崑崙，分坐溪頭蘚石根。", "崖樹有霜飛老葉，野泉無雨落秋痕。", "幾番閒借樵人屐，何許追尋隠者門。", "多種杏花依此住，要知董奉得仍孫。"]'),
('3dc26f0c-2e6b-4419-a1cd-0508e3bd17cb','江州重午二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','晴光遶砌看葵傾，獨恨無文弔屈平。',64,'全唐诗/poet.song.237000.json','["晴光遶砌看葵傾，獨恨無文弔屈平。", "梅溽潤衣身體倦，竹風入牖夢魂清。", "良辰美景須臾事，往古來今節序情。", "不信滄江傳競渡，彩旗畫鼓閙西城。"]'),
('23098a16-d308-4e7d-85cc-faba477358af','江州重午二首  其二','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蒲節殊鄉借楚誇，遶城社鼓不停撾。',64,'全唐诗/poet.song.237000.json','["蒲節殊鄉借楚誇，遶城社鼓不停撾。", "争歌神曲羞溪藻，遥送瘟船滚浪花。", "世上莫非兒戲事，江頭無奈客思家。", "西湖今夜笙歌月，凉擁紅蓮燦落霞。"]'),
('bcb24617-5cba-4b9e-ad30-030a72f690f9','懐潘宰留方家峪别業','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','想戀西湖賞物華，清依水石結生涯。',64,'全唐诗/poet.song.237000.json','["想戀西湖賞物華，清依水石結生涯。", "鳳凰山下泉縈草，燕子樓前雨壓花。", "翠枕謾欹聽夜雨，朱簾閒捲望朝霞。", "柳塘不遏東流住，腸斷江城尚寄家。"]'),
('9c785bdd-0213-4e98-975f-1de21c06f091','題冷翠谷道者庵','董嗣杲','宋','宋诗','song-poetry','','[]','萬計千謀濁世紛，蓮花峯下寂無聞。',64,'全唐诗/poet.song.237000.json','["萬計千謀濁世紛，蓮花峯下寂無聞。", "丹泉潄冷齒凝雪，翠谷虚凌身入雲。", "藤杖卓苔防險峻，石爐炷柏起氤氲。", "獨遊獨宿露寒夜，絕頂想多秋幾分。"]'),
('2e6c61a4-94d8-4de5-a50a-ae35bcb1af12','離江城遇雪','董嗣杲','宋','宋诗','song-poetry','','[]','頭上同雲密布饒，湓江門外揖華鑣。',64,'全唐诗/poet.song.237000.json','["頭上同雲密布饒，湓江門外揖華鑣。", "舟穿苦竹黄蘆去，帽任回風急雪飄。", "蹤跡幾年懐玉石，江山一夜變瓊瑶。", "旁人莫訝吟窮返，慷慨殊勝過灞橋。"]'),
('d8ea02cc-2e39-4f23-ace9-498f3e60a0e7','接泥渡頭再遇雪','董嗣杲','宋','宋诗','song-poetry','','[]','幾涉沙汀與水村，幾看雲物幻乾坤。',64,'全唐诗/poet.song.237000.json','["幾涉沙汀與水村，幾看雲物幻乾坤。", "渡頭衝雪哦詩老，船尾乘風破酒昏。", "未晚？聲先傍岸，乍晴江色逺侵門。", "白鷗無數西飛急，鳴落淮山不見痕。"]'),
('3110510c-1bb1-4f25-8480-ee713fba0a68','戲酬李勉之留江州懐琴窗之什','董嗣杲','宋','宋诗','song-poetry','','[]','當時兩别惜分雙，客了三吳客九江。',64,'全唐诗/poet.song.237000.json','["當時兩别惜分雙，客了三吳客九江。", "何處揮金曾駐馬，此身懐寶尚迷邦。", "水流歲月添新恨，塵撲簫絃失舊腔。", "柳下燕樓風雨外，夢魂多遶唾茸窗。"]'),
('33f173bc-d4ed-4228-be96-2b1b531e87b8','漫興二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','倚竹欹巾望逺天，脱鞋自在取髙眠。',64,'全唐诗/poet.song.237000.json','["倚竹欹巾望逺天，脱鞋自在取髙眠。", "無情歲月催雙鬢，有様文章委少年。", "吟卷亂抛幽枕畔，客床寒對短燈前。", "沈迷謾想華胥樂，還有癡兒鄙孝先。"]'),
('1b4554be-4814-45aa-9291-8ee89f5c2401','漫興二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','浮名浮利有傳訛，薏苡囊疑馬伏波。',64,'全唐诗/poet.song.237000.json','["浮名浮利有傳訛，薏苡囊疑馬伏波。", "鏡裏鬢毛諳世故，筆頭詩句答樵歌。", "風穿樹秃寒林淺，月展江空夜浪多。", "脱病欲歸歸便得，花家魚港自烟蓑。"]'),
('2b6354fe-1b5f-4927-a91d-1f1dbbe66f14','留分司衙','董嗣杲','宋','宋诗','song-poetry','','[]','往來幾苦浪濤驚，塵役而今亦懶營。',64,'全唐诗/poet.song.237000.json','["往來幾苦浪濤驚，塵役而今亦懶營。", "雪積墻腰連屋瑩，日涵城影接江平。", "市樓有酒晴旗小，賓舘無人夜榻清。", "孤坐搜吟難造妙，霜風吹月紙窗明。"]'),
('159ee946-d0b1-4ceb-b9c8-6cd5538530de','富池江上蕩舟遊望二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','江風吹得烏帽偏，江水驚秋狂拍船。',64,'全唐诗/poet.song.237000.json','["江風吹得烏帽偏，江水驚秋狂拍船。", "此身客逺積鄉夢，何日丹靈朝洞仙。", "將軍廟無老鴉異，羅漢院有古柏堅。", "蕩槳津頭來往遍，北望淮雲成愴然。"]'),
('7cc06d55-1c7b-4f3c-bbe0-1e664a4ca872','富池江上蕩舟遊望二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','上江落水渺莽中，入軍遡水曲折通。',64,'全唐诗/poet.song.237000.json','["上江落水渺莽中，入軍遡水曲折通。", "此鎮巧當兩汊路，毎日飽看千帆風。", "客知鼓棹白日急，人傷對鏡玄髮空。", "荒寒殊甚只自笑，悲聲遶井餘枯桐。"]'),
('3cb3ca16-4110-499f-9369-d731caa0bec3','客居余明逺來訪','董嗣杲','宋','宋诗','song-poetry','','[]','風浪而今自忍聞，尚甘客隠大江濆。',64,'全唐诗/poet.song.237000.json','["風浪而今自忍聞，尚甘客隠大江濆。", "酒家債負將償足，詩境情懐任醉分。", "愛睡有魔銷椀茗，遣閑無事對爐熏。", "梧桐井畔敲門處，問字何人訪子雲。"]'),
('07372f5b-3749-48c0-80e7-ec2199db84d1','發黄池與朱一夔相别情思黯如','董嗣杲','宋','宋诗','song-poetry','','[]','同行誰際此心同，我去君留悵北風。',64,'全唐诗/poet.song.237000.json','["同行誰際此心同，我去君留悵北風。", "兩地相分雲袂逺，前峯自掩雪林空。", "幾多遣興懐樽爼，千萬將書托燕鴻。", "獨過顧城湖上晚，已拚絕飲蟄孤篷。"]'),
('7230aca5-bd54-4263-8a31-9dcf95eb93cf','别王監鎮','董嗣杲','宋','宋诗','song-poetry','','[]','僑寄荒津厭鼓鼙，逆行遣日守羈栖。',64,'全唐诗/poet.song.237000.json','["僑寄荒津厭鼓鼙，逆行遣日守羈栖。", "天兵未卜何時解，心事難侔此日齊。", "雨醉田家無屐借，春眠野寺有詩題。", "蒲帆行趁東流去，應目狂蹤類阮嵇。"]'),
('3d9ff213-eb70-4093-9d6c-ca7e9739d457','醉後登黄池港舟','董嗣杲','宋','宋诗','song-poetry','','[]','大江勝絕此無儔，不省荒寒醉酒樓。',64,'全唐诗/poet.song.237000.json','["大江勝絕此無儔，不省荒寒醉酒樓。", "秉燭尚嫌盃數窄，換舟便覺櫓聲柔。", "山連青意爲仙塜，池接黄名是逆流。", "僵卧莫知身紀墮，岸南燈火屬宣州。"]'),
('ee23dfcf-640a-498e-aae0-eb6700e807e3','舟次示朱友龍','董嗣杲','宋','宋诗','song-poetry','','[]','雪花侵鬢轉栖栖，身寄篷窗醉似泥。',64,'全唐诗/poet.song.237000.json','["雪花侵鬢轉栖栖，身寄篷窗醉似泥。", "荻港水寒鷗聚逺，蕪湖山近鴈飛低。", "客舟泊夜秋無奈，社鼓催春夢欲迷。", "津岸喜登無可語，不堪明日各東西。"]'),
('dc52dbdf-147b-4ecb-b275-6b9ce6eff95a','初欲登小孤惠濟廟水盛風駛回首已逺矣','董嗣杲','宋','宋诗','song-poetry','','[]','蘆荻蕭蕭掩敗汀，抛南抛北慣曾經。',64,'全唐诗/poet.song.237000.json','["蘆荻蕭蕭掩敗汀，抛南抛北慣曾經。", "淮山有雪侵雲白，江水無風接樹青。", "吟卷紀遊揮小草，醉篷埋恨載浮萍。", "廟門轉眼隨帆過，不得重登絕頂亭。"]'),
('d7e80e21-6da6-4c4c-8d29-d851393b970a','得京友信問曾觀三疊水否因寄','董嗣杲','宋','宋诗','song-poetry','','[]','破槖蕭然不自休，蘆黄葦白九江秋。',64,'全唐诗/poet.song.237000.json','["破槖蕭然不自休，蘆黄葦白九江秋。", "抗塵狂作兩年客，看水慳爲三疊遊。", "得酒問魚愁入市，有書無鴈却登樓。", "征裘幾揾思家淚，兩眼凝窮桑落洲。"]'),
('bbc5963d-7025-4fe7-b9ea-ed364fab7102','冬寒客懐','董嗣杲','宋','宋诗','song-poetry','','[]','争錐無意志摧藏，歲晚栖然滯客房。',64,'全唐诗/poet.song.237000.json','["争錐無意志摧藏，歲晚栖然滯客房。", "井臼自親猶火食，琴書誰力謾時裝。", "前峯雪洗心方快，破廨風穿骨欲僵。", "燒荻禦寒身尚曲，有人皸瘃守邊疆。"]'),
('11782b60-9c44-4ee3-b0c2-df815315f204','九日留彭澤','董嗣杲','宋','宋诗','song-poetry','','[]','牢繫扁舟在樹根，依然風物晉時村。',64,'全唐诗/poet.song.237000.json','["牢繫扁舟在樹根，依然風物晉時村。", "幾年思采東籬菊，此際狂傾北海樽。", "野鶴離羣翔碧落，江鴻排字入黄昏。", "有人若學淵明隠，五柳蕭疎静掩門。"]'),
('c2c53b4e-44fa-4b7b-b385-3e500d0d4268','江上晚眺  其一','董嗣杲','宋','宋诗','song-poetry','','[]','江北西風髙，江南新酒熟。',24,'全唐诗/poet.song.237000.json','["江北西風髙，江南新酒熟。", "長笛吹梅花，月色滿營屋。"]'),
('c74e2866-8094-4044-b40b-447c54444555','江上晚眺  其二','董嗣杲','宋','宋诗','song-poetry','','[]','得酒終日醉，都忘醒後愁。',24,'全唐诗/poet.song.237000.json','["得酒終日醉，都忘醒後愁。", "往來狂走馬，直過皖山頭。"]'),
('72b18e29-bc4a-4311-aed5-f9aae37cfe01','遊冷翠谷','董嗣杲','宋','宋诗','song-poetry','','[]','急流潄亂石，石色白齒齒。',24,'全唐诗/poet.song.237000.json','["急流潄亂石，石色白齒齒。", "瞥見水色渾，籬頭過山麂。"]'),
('7feb47f0-90c2-4840-8728-06bb030cac41','寄江城口占  其一','董嗣杲','宋','宋诗','song-poetry','','[]','夢魂蕩孤舟，波聲塞兩耳。',24,'全唐诗/poet.song.237000.json','["夢魂蕩孤舟，波聲塞兩耳。", "不眠聞管絃，方悟江城裏。"]'),
('c003ccf7-0d4f-4e3f-8e55-c2fb016321e0','寄江城口占  其二','董嗣杲','宋','宋诗','song-poetry','','[]','蹉跎歲事空，次第春風起。',24,'全唐诗/poet.song.237000.json','["蹉跎歲事空，次第春風起。", "雪消夕陽平，徹底清江水。"]'),
('fc198a0d-6424-425e-834c-d4db0aa0f6d4','乍歸信筆寫興二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','閒抛南峯雲，狂汎西江葦。',24,'全唐诗/poet.song.237000.json','["閒抛南峯雲，狂汎西江葦。", "眠食思故栖，吹燈任山鬼。"]'),
('ff49b62d-9e70-4236-9cd7-34a2e1fd2b23','乍歸信筆寫興二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','身絕一毫榮，膽落幾回醉。',24,'全唐诗/poet.song.237000.json','["身絕一毫榮，膽落幾回醉。", "難忘踏霜茅，忍凍吟冷翠。"]'),
('330312f6-d75c-41be-a03a-eb52886ccd10','聞笛  其一','董嗣杲','宋','宋诗','song-poetry','','[]','四海水尚淺，孤城愁更深。',24,'全唐诗/poet.song.237000.json','["四海水尚淺，孤城愁更深。", "船上何人笛，吹入蘆花林。"]'),
