('d8f8baed-c440-4ecc-bc25-fc4768f2021e','自廬山歸城賦四首  其四','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','重葺芒鞋約更堅，山家意味况相便。',32,'全唐诗/poet.song.237000.json','["重葺芒鞋約更堅，山家意味况相便。", "須先折簡同遊客，剥蘚題名就石鎸。"]'),
('6c09aa99-e021-4d80-bd3b-ed41113f2c9f','鈞天曲','董嗣杲','宋','宋诗','song-poetry','','[]','圓丘崇且髙，廣漢清且淺。',72,'全唐诗/poet.song.237000.json','["圓丘崇且髙，廣漢清且淺。", "元祀播鼓鐘，嚴禘列瑚璉。", "天酒瀉琪花，遵此奉常典。", "恩流昭感通，報稱示豐腆。", "鶴鳴集霞臺，鳳曳翔雲輦。", "已際天人和，八表清塵卷。"]'),
('bea1d9d0-fb6a-4d99-9640-972ff9f9bdca','擬古  其一','董嗣杲','宋','宋诗','song-poetry','','[]','海上采珠人，惟視夜光吐。',48,'全唐诗/poet.song.237000.json','["海上采珠人，惟視夜光吐。", "携持以爲珍，美價重合浦。", "異哉足照乘，殷勤獻明主。", "逺物奈不寶，棄之猶糞土。"]'),
('0b7ec4fb-ae4a-4bfb-85fb-3428aee9c99b','擬古  其二','董嗣杲','宋','宋诗','song-poetry','','[]','河漢金氣老，海月光陸離。',48,'全唐诗/poet.song.237000.json','["河漢金氣老，海月光陸離。", "蟋蟀鳴我床，聲聲有餘悲。", "美人天之涯，言旋杳無期。", "西風吹脫葉，撫時傷所思。"]'),
('35dd76ab-ce39-4df1-80a2-a7140353b37b','武康邑俗  其一','董嗣杲','宋','宋诗','song-poetry','','[]','邑俗尚巫誕，竭力營鼎爼。',48,'全唐诗/poet.song.237000.json','["邑俗尚巫誕，竭力營鼎爼。", "無方絕此幻，舉口輙齟齬。", "衰世無真儒，反欲構室處。", "顧我暫爾棲，信得子不語。"]'),
('33ade0b6-4240-494b-bfd0-706deed01329','武康邑俗  其二','董嗣杲','宋','宋诗','song-poetry','','[]','官廨俯官溪，溪流極清泚。',48,'全唐诗/poet.song.237000.json','["官廨俯官溪，溪流極清泚。", "魚遊值天陰，競指龍光起。", "古祠偶相鄰，愚徒望風靡。", "我欲照衰顔，且展闌干倚。"]'),
('2034d6fb-3ba2-43c0-9635-a2c7ffd8ce0d','由京買航還武康夜泊中途因醉曉還邑中摭實有賦','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','上船且偃卧，月出攬衣起。',180,'全唐诗/poet.song.237000.json','["上船且偃卧，月出攬衣起。", "周覽郊原曠，肆毒暑未已。", "河漢水色浄，身寄圖畫裏。", "幽情苦跋涉，未克安所止。", "憶蕩西湖舟，白蓮弄清泚。", "歌聲透夜響，鉅麗瀛蓬比。", "景絕四無人，風揺六橋水。", "今如夢中覺，乍離官河觜。", "板橋餘店燈，酒旗三尺紙。", "狂來發興深，野航暫時艤。", "崖凉勝埋篷，獨信橋闌倚。", "倐然想歸程，便遲二十里。", "醉眼忘離津，風順差可喜。", "入邑日已髙，不掩罍之恥。", "因感孤生浮，若此能幾耳。"]'),
('4a1abbbd-d406-4ba6-8c5c-270c8ebf565f','甲戌八月初九夜武康山中洪水驟發越十日漕司檄往檢澇','董嗣杲','宋','宋诗','song-poetry','','[]','甲戌纒國哀，時屬秋八月。',264,'全唐诗/poet.song.237000.json','["甲戌纒國哀，時屬秋八月。", "近輔餘英山，洪水中夜發。", "狼藉徹句雨，拔地殊飄忽。", "滔天肆奔迸，變幻起𡷾崒。", "徒步登縣樓，浩渺沉林樾。", "妖氛混澤氣，勢極火燄突。", "綿亘山下鄉，逃難想顛蹶。", "晨興雨更澍，邑屋已隉杌。", "髙跳空刺腸，何異覩溟渤。", "飄屍不可計，强者布竹筏。", "棲危或得命，其奈服食闕。", "號天天不聞，不若就滅没。", "瀑派裂青山，溪岸奔屍骨。", "杵臼埋虚沙，蛇虺出深窟。", "邊方乘孔殷，糜爛事征伐。", "民生不奠枕，復罹此酷罰。", "隠憂非一端，國脉存如髮。", "檢澇亦具文，民力各已竭。", "豈知坐困窮，終歲常矻矻。", "奉行亦漫爾，持論敢躐越。", "步步涉坑塹，路梗勞輿卒。", "歸愁强就床，魂夢隨恍惚。"]'),
('4e2e92d8-46bb-4af6-8eeb-81330fac7c72','甲戌武康大水净林寺山門殿屋悉皆倒敝','董嗣杲','宋','宋诗','song-poetry','','[]','仲秋秋陰合，壁落走鼯鼠。',180,'全唐诗/poet.song.237000.json','["仲秋秋陰合，壁落走鼯鼠。", "徹宵風雨驟，平地生洲渚。", "莫辨路與溪，廬舍失處所。", "净林古梵屋，木佛豈得禦。", "當門金剛惡，兹復化何許。", "方丈九旬僧，足廢不能舉。", "徘徊想舊歴，突突起沙嶼。", "遺闗茁芝菌，卧竹壓麻苧。", "山民窮無吿，謀食屢多阻。", "三鄉凡幾户，竟墮魚鼈侣。", "傷痛李生迂，捲盡牌頭墅。", "獨慨虚浮身，昏迷怯幽佇。", "上流未偃戈，戰血沍荆楚。", "近畿天示儆，歲月不我與。", "就食難下咽，酸恨徹心膂。"]'),
('c43b51ff-c231-4233-b853-729b97e583c1','古意','董嗣杲','宋','宋诗','song-poetry','','[]','山中有流泉，洗耳今無人。',120,'全唐诗/poet.song.237000.json','["山中有流泉，洗耳今無人。", "樹陰互蒙密，烏語交昏晨。", "誰能觀大運，達此秋與春。", "生意自爾蕃，葉葉分光新。", "藤蔓附女蘿，蘭茝披荒榛。", "興言混棲托，隨跡安可伸。", "悲哉倦遊子，感寓徒酸辛。", "榮枯了不計，老大將迫身。", "澘然眼中淚，墮此衣上塵。", "所耽軒裳故，殊失煙霞親。"]'),
('ea74215f-98d5-402c-871d-094faacfc8e2','趙南康可齋築屋武康孟保園池喬木極有思致東野故廬藉以表出感古傷今成重遊三十韻','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','東野英溪英，妙寄寒苦詩。',288,'全唐诗/poet.song.237000.json','["東野英溪英，妙寄寒苦詩。", "里社今有井，誰構亭覆之。", "想彼異代賢，孤標奪葳蕤。", "可齋出帝冑，結廬探幽奇。", "分符廬山陽，歸葺園與池。", "髙懐敦薄俗，萬象共眇窺。", "惟憐時不與，舟壑忽夜移。", "身世付永擯，逸駕淪西馳。", "我此偶竊稍，荏苒垂三朞。", "兩獲憩絕境，真與浮世遺。", "牽裾古木底，洗屐官溪湄。", "想像貞曜公，淪落長安時。", "壯心侔元造，瀝思抽肝脾。", "衰謝入硬語，難以好爵縻。", "此鄉所自出，指點餘芳茨。", "相去五百年，隨勝營詩詞。", "清揚藉發揮，昧者迷藩籬。", "孟公能歸歟，趙侯今已而。", "罷酒聞清彈，眼在空涕洟。", "孰能經始初，欲綿無窮期。", "再傳至斯荒，曠望逝水悲。", "丘壑漫獨存，豈不重爾思。", "拘情失寢處，觸事逢乖離。", "無端菊帽破，不管西風吹。"]'),
('bcb46723-fe16-4169-9cac-551d0885f069','酒邊憶去年苦病','董嗣杲','宋','宋诗','song-poetry','','[]','發誓遊四方，言歸多自責。',96,'全唐诗/poet.song.237000.json','["發誓遊四方，言歸多自責。", "秋髙風浪險，懐家萬山隔。", "江北與江西，夢寐困行役。", "去年病褵褷，客死亦何惜。", "心空病自退，藥裹漫山積。", "今日秋又深，誰念饑凍逼。", "祗幸徤於酒，酒盡從墮幘。", "醒來聽談空，鳥啼晚峯碧。"]'),
('8b088943-e685-4090-abca-99d7303c0815','聞趙芳洲已歸武康梅廨','董嗣杲','宋','宋诗','song-poetry','','[]','歸來慰我思，山疇稻田熟。',96,'全唐诗/poet.song.237000.json','["歸來慰我思，山疇稻田熟。", "雨驟不終朝，水退出平陸。", "梅廬暮色黯，欲入足尚縮。", "月地舉深杯，杯光泛纎菊。", "燈明不藉輝，來去絕慙恧。", "所恨懐寶迷，失計資薄禄。", "鄙人更曠縱，肯作阮途哭。", "有時得親書，多是不再讀。"]'),
('2ec6ccdd-6db7-4509-a2a8-c9b217d69547','坐暑病初招汪學老醫次招黄平齋兩公枘鑿之甚病者反取多事而黄終奏藥績因有中秋共醉之約漫述長句','董嗣杲','宋','宋诗','song-poetry','','[]','卧病不知暑，况在英溪隅。',288,'全唐诗/poet.song.237000.json','["卧病不知暑，况在英溪隅。", "入京涉夜航，藥物艱所需。", "汪公業於醫，其實真癯儒。", "醫故不違理，非但以理拘。", "覽鏡面百皺，半月怯步趨。", "積憂那得解，肌瘠徒長吁。", "兹晨近秋中，疲憊憑杖扶。", "忽枉黄公駕，慰此困櫪駒。", "指我傴僂形，旦暮耽書劬。", "病源肇於心，證與芝术殊。", "所嗟露電如，滿歲罹艱虞。", "寒暑復見宼，閻浮可久圖。", "行止任天造，其或誚以迂。", "凉軒聆欬唾，眷眷非世娛。", "浮榮信飄風，况復假合軀。", "墮落焦熬坑，難煉六一爐。", "感公致湯饋，瀹盞浮雪腴。", "仙傳起死劑，頓醒爪髮枯。", "西風捲茅屋，篝燈竹窗孤。", "蔬腸轉陽脉，趣向歸酒壺。", "誰傳病退舍，可奈流俗徒。", "汪黄信可人，彼此皆枌榆。", "往締中秋盟，未卜月有無。", "因拈二公姓，激我懐東都。"]'),
('c6d477be-adc5-4717-b56e-ecfc757eb046','裝伯弜周先生手澤','董嗣杲','宋','宋诗','song-poetry','','[]','桐溪恩上人，留遺盈束紙。',132,'全唐诗/poet.song.237000.json','["桐溪恩上人，留遺盈束紙。", "初疑龍蛇奮，不敢傲睨視。", "嗚呼汶陽翁，父子傳心旨。", "手澤落世間，枯盡幾硯水。", "言言闗世運，字字窮物理。", "悲風颯雙鬢，涕淚揮不止。", "思超漢魏髙，人可晉唐似。", "逸態出天然，凛若對英峙。", "此時吟嘯者，跌蕩何可比。", "卷舒手不停，光芒射桯几。", "下取防六丁，急寘空谷裏。"]'),
('b4e613ce-c1e3-4937-818f-4cbe861b89bc','宿嘉興新城市','董嗣杲','宋','宋诗','song-poetry','','[]','汎秋入禾鄉，鈍舟無期程。',120,'全唐诗/poet.song.237000.json','["汎秋入禾鄉，鈍舟無期程。", "西風吹官河，其壤惟新城。", "雲圍畎畆遍，星零聚落盈。", "前畈出頑獷，有可敵無勍。", "梵坊名能仁，所向乖幽情。", "房房市藥富，滌面塵不嬰。", "習俗困促迫，意度無専征。", "市沽更漓甚，不堪客子傾。", "偕行得佳士，共此秋榻清。", "未晚急掩扉，屢貽暴客驚。"]'),
('944c65c4-7826-491e-8206-ecbb46c5ea34','潔牲謝響應龍廟予不及往','董嗣杲','宋','宋诗','song-poetry','','[]','龍宫藴特異，精禱通萬靈。',144,'全唐诗/poet.song.237000.json','["龍宫藴特異，精禱通萬靈。", "昭著二百年，錫封専朝廷。", "去年偕宰公，投誠涕欲零。", "驅車入松扉，雨勢如建瓴。", "仰髙迓靈昐，雲斂不暫停。", "煙沉瀑聲凉，分坐瀑外亭。", "從兹感佑助，争謂胸百銘。", "治任亦已速，潔謝資芳馨。", "緘素展真忱，要終寄冥冥。", "願恢溥濟功，致此百里寧。", "夜披東堂集，孤燈炯深青。", "朗誦神之聰，壁落山鬼聽。"]'),
('34cf9b79-4094-43e9-b189-63bfd6f6e582','越城步月不知子城已閉因托宿趙義齋宅','董嗣杲','宋','宋诗','song-poetry','','[]','晚步初月髙，忘却子城閉。',240,'全唐诗/poet.song.237000.json','["晚步初月髙，忘却子城閉。", "客樓枕新荷，幾夜香襲袂。", "羸骸奔走倦，不擬尚凝滯。", "白面佳少年，塞途莫勝計。", "低顔謝許可，不甘暗拭涕。", "窮迫傍人籬，傍籬畏奴隸。", "風采就衰憊，心孔轉昏翳。", "見舟思江湖，懐隠睨松桂。", "故人立霄漢，敢詫平生契。", "兹時進退難，假宿義齋第。", "官橋醉尉多，大懼獲重戾。", "徘徊益羈愁，愈痛乏邊際。", "讒毀那能免，失擁文侯篲。", "身如被酒酣，心類垂旒綴。", "嗟嗟文不績，有學謾經濟。", "逆行且倒施，猶幸舌未敝。", "月西黯蓬萊，城烏聲更厲。", "借榻逢可人，度夜等匏繫。", "履險復自笑，汨没信此世。", "願逢陽明仙，餐霞度千歲。"]'),
('6cb570af-7c59-46dc-8c52-6287a1a9e238','病中步入蔡公橋村落間','董嗣杲','宋','宋诗','song-poetry','','[]','水淺篙師勞，况值夏日炎。',144,'全唐诗/poet.song.237000.json','["水淺篙師勞，况值夏日炎。", "舟維蔡橋晚，扶行禦頑痁。", "誰期村疃中，雙屐苔花粘。", "同行幸同志，出語無猜嫌。", "曉霞晚必雨，故老嘗所占。", "兩行桑麻香，農計得盡覘。", "偶聞讀書聲，白叟依茅簷。", "自奮力稼耕，其志方隠潛。", "延我坐俄頃，障日西垂簾。", "竹床半已弊，暫睡亦安恬。", "傳酒强我飲，飲絕徒掀髯。", "神思偶爾清，吟興爲此添。"]'),
('710fc7bf-7941-406c-9f16-1b3e6257eb71','自武康入京隨即渡越','董嗣杲','宋','宋诗','song-poetry','','[]','意杳軒中坐，坐見新竹長。',144,'全唐诗/poet.song.237000.json','["意杳軒中坐，坐見新竹長。", "病夫欲尋睡，不禁竹氣凉。", "昏昏度白日，神倦慵舉觴。", "偶然探吟處，誰謂醒爲狂。", "扶行壺中天，草樹含夕光。", "雨橋荷柄閙，亭亭雲錦張。", "中有窈窕質，忽透洛妃粧。", "引領不忍去，水風遞幽香。", "簷梢鵲啑啑，戒我租夜航。", "我生尚未了，何地安韜藏。", "宵程促登津，食息何皇皇。", "郭南待朝渡，西陵晚蒼茫。"]'),
('ab70f60a-279a-4652-9aaa-531ff057b2ac','烏棲曲','董嗣杲','宋','宋诗','song-poetry','','[]','緑陰凉透城頭樹，月明正照烏棲處。',64,'全唐诗/poet.song.237000.json','["緑陰凉透城頭樹，月明正照烏棲處。", "黄昏角起吹晴雲，烏欲啼愁愁夜分。", "夜分湖波幻絕境，境絕月漾玻瓈冷。", "棲烏忽過别枝棲，何人採蓮移舴艋。"]'),
('2cb9f5c6-3253-4c66-8c41-65198f8117b6','賦得河中之水曲','董嗣杲','宋','宋诗','song-poetry','','[]','清莫清兮河中水，白莫白兮頭上絲。',224,'全唐诗/poet.song.237000.json','["清莫清兮河中水，白莫白兮頭上絲。", "河清頭白自千古，有身清白知爲誰。", "提籃采桑西城婦，容髮蓬勃霜色欺。", "傳是長安估客女，二八嫁與東鄰兒。", "東鄰兒郎負梟獍，别家出戍征羌夷。", "沙場杳邈絕信息，譍門無子難撐支。", "花榮草枯知幾度，日升月落常雙馳。", "力勤織絍活旦暮，堂前姑老心驚疑。", "攢心萬苦失頭緒，年如逝水何能追。", "不恨兒郎祗恨妾，有生無分安齊眉。", "西鄰女兒年將笄，雙髻壓頸簪花枝。", "金鈿貼額腮凝脂，笑妾採葉愁蠶饑。", "妾身薄命何暇恤，所嗟母子各天涯。", "空閨誓此守清白，不願封侯願早歸。"]'),
('851cf730-3352-4779-90da-9dac6f1e492a','武康防風王廟前入西鄉山中曠遊歸看邑志偶成','董嗣杲','宋','宋诗','song-poetry','','[]','苕溪直西山嶙峋，莫干矗空參北辰。',128,'全唐诗/poet.song.237000.json','["苕溪直西山嶙峋，莫干矗空參北辰。", "荒村去縣未甚逺，日落將盡埋紅輪。", "羈人憩此醉徒御，僻壤曾際神禹巡。", "敝祠古木質擁腫，色泥癡塑防風身。", "遥遥石徑險如棧，芒屨掣足移換頻。", "狂貪遊歴不顧倦，肯因巇嶮嗟迷津。", "錦卷要演江海思，拍塞景物描天真。", "偶繙邑志寧訛舛，下筆希古今無人。"]'),
('e5afd7fe-1f75-4514-8edc-eab491861de7','武康附夜航入京','董嗣杲','宋','宋诗','song-poetry','','[]','今晚後溪風色順，暑威未肯回凉信。',64,'全唐诗/poet.song.237000.json','["今晚後溪風色順，暑威未肯回凉信。", "獨泛官河雨氣收，野林鴉落歸無陣。", "聽鐘揺出港汊重，新塘光現横空龍。", "松頭暝破月色吐，油雲散盡迴千峯。"]'),
('ca297ce9-3db9-4685-b2e1-e519afc0cf6c','秋夜宴客歌','董嗣杲','宋','宋诗','song-poetry','','[]','賓從齊聲歌提壺，有酒在樽殽在廚。',96,'全唐诗/poet.song.237000.json','["賓從齊聲歌提壺，有酒在樽殽在廚。", "秋髙廣寒桂子落，時零金粟成泥塗。", "秋空月露炯冰玉，情深莫出南山屋。", "自駐南山持酒巵，愁人驚糝陶家菊。", "花枝易空人易老，人生安得無醜好。", "只須傲兀醉乾坤，人老花空如電掃。"]'),
('1abddd75-1e48-4461-aed4-17d892cd54d7','羽觴飛上苑','董嗣杲','宋','宋诗','song-poetry','','[]','日色蕩曉香塵起，上苑春融錦屏裏。',128,'全唐诗/poet.song.237000.json','["日色蕩曉香塵起，上苑春融錦屏裏。", "蕙枝小葉攢石臺，桃英亂糝浮池水。", "鱗波皺雲展翠綃，羽幰逐風颯珠履。", "騮飛步褭蹀躞髙，杯行聲度提壺美。", "提壺朝暮啼芳陰，啼盡東君脉脉心。", "螭毬流影晚陽淺，獸匜噴香淑景深。", "靈鼉鼓曲肯停調，緑蟻漾艶争歡斟。", "醉情得向芳辰暢，香車回碾銀蟾沈。"]'),
('e1b3ede0-0c1d-4255-a0da-cd48ee057c7c','和樓恪齋自述','董嗣杲','宋','宋诗','song-poetry','','[]','碧樹前林合，黄雲百里迷。',48,'全唐诗/poet.song.237000.json','["碧樹前林合，黄雲百里迷。", "月髙溪水定，風逆漏籖低。", "列宿來花邑，凉秋入菊畦。", "比閭回善譽，招得頌聲齊。"]'),
('c7fbbebe-ba58-4501-96d8-84a4aaadacc5','題蔡主簿小園','董嗣杲','宋','宋诗','song-poetry','','[]','聒耳禽聲細，澄顔池影浮。',48,'全唐诗/poet.song.237000.json','["聒耳禽聲細，澄顔池影浮。", "襟懐猶徼塞，松竹自林丘。", "剪韭疏畦闊，分蘭貼石幽。", "吟箋滿芸架，閑樂野僧留。"]'),
('e829520f-b356-4f8e-9a79-3199ac202d02','官舍病中','董嗣杲','宋','宋诗','song-poetry','','[]','古劍秋埋匣，昏鐘冷壓樓。',48,'全唐诗/poet.song.237000.json','["古劍秋埋匣，昏鐘冷壓樓。", "吟情臨晚銳，歸計待春謀。", "雞遶村墟捕，魚空藪澤收。", "斂將筋骨悴，所恃有新篘。"]'),
('a900416f-5b80-4fa9-a774-3cbd531863d6','客滯','董嗣杲','宋','宋诗','song-poetry','','[]','粹容成槁木，浮跡類流萍。',48,'全唐诗/poet.song.237000.json','["粹容成槁木，浮跡類流萍。", "天地春明净，江山晚晦冥。", "花芒環野茜，柳桁接簷青。", "淹滯知何事，思歸夢短亭。"]'),
('f4a76286-34db-4e2d-8974-e864a67a7d50','題城山道人庵  其一','董嗣杲','宋','宋诗','song-poetry','','[]','官俸胥方給，山殽市可需。',48,'全唐诗/poet.song.237000.json','["官俸胥方給，山殽市可需。", "雨多沙磧失，橋斷路程迂。", "古樹聲何壯，秋萍跡已枯。", "病身慙到此，有愧竹笻扶。"]'),
('c20e3b03-8e79-4e87-be1b-c2419f5c749d','題城山道人庵  其二','董嗣杲','宋','宋诗','song-poetry','','[]','山暉丹氣紫，路隠翠林香。',48,'全唐诗/poet.song.237000.json','["山暉丹氣紫，路隠翠林香。", "野道依城社，山童執紀綱。", "田髙秋斂薄，溪曲夜湍長。", "誶語令人倦，蚍蜉肯自量。"]'),
('e8fa89f9-d670-4353-9a93-7118563302ce','過證道寺','董嗣杲','宋','宋诗','song-poetry','','[]','證道山門曠，延僧草座禪。',48,'全唐诗/poet.song.237000.json','["證道山門曠，延僧草座禪。", "不知爲額始，曾記有歌傳。", "驛路橋梁壊，沙溪石蘚填。", "往來荒廨近，時可托清眠。"]'),
('fe4e65f3-6bb0-4a01-838c-fc37c46f9a7f','武康姓丁人號生魂神合邑騷動','董嗣杲','宋','宋诗','song-poetry','','[]','世降多淫祀，時荒扇盗區。',48,'全唐诗/poet.song.237000.json','["世降多淫祀，時荒扇盗區。", "妖丁肆荒誕，結甲走昏愚。", "揭幟營祠廟，椎鑼誷市衢。", "大夫清似水，勦絕莫踟蹰。"]'),
('d1f9f08a-ec98-42e3-812e-6494464097eb','雨窗夜感','董嗣杲','宋','宋诗','song-poetry','','[]','風窗停暑雨，竹簟展寒波。',48,'全唐诗/poet.song.237000.json','["風窗停暑雨，竹簟展寒波。", "酒醒乾坤小，林昏鳥雀多。", "凉堂喧管鑰，秋戍淬弓戈。", "殊感征行苦，悲蛩咽楚莎。"]'),
('373abeb8-4e70-405c-909e-4c633b97bd87','清穆鄉農户','董嗣杲','宋','宋诗','song-poetry','','[]','山峭回峯緊，場空得雨忙。',48,'全唐诗/poet.song.237000.json','["山峭回峯緊，場空得雨忙。", "赤楓溪觜立，白草渡頭荒。", "寒市虚聲隘，秋疇喜氣揚。", "野舂連屋響，瑞入雪匙香。"]'),
('85d7dbb5-54ac-439d-957e-271a32deec23','題園堂壁','董嗣杲','宋','宋诗','song-poetry','','[]','廨扉臨水掩，世路入山窮。',48,'全唐诗/poet.song.237000.json','["廨扉臨水掩，世路入山窮。", "暑謝晚尤熾，秋髙凉未通。", "蓮香霞沼廢，竹色月樓空。", "天地機難測，山林志少同。"]'),
('adf3f17d-50d3-48fc-bea7-1320d21fb676','題意香壁','董嗣杲','宋','宋诗','song-poetry','','[]','朱户編簾掩，花顛覽鏡羞。',48,'全唐诗/poet.song.237000.json','["朱户編簾掩，花顛覽鏡羞。", "酒多無客過，茶盡有僧留。", "世慮經心久，花時撚指休。", "悅生憐濁骨，愧死混清流。"]'),
('9df4369c-7213-4cdc-ac5d-5d6e8cd892d9','題方用卿書屋壁','董嗣杲','宋','宋诗','song-poetry','','[]','野雲埋墅晚，城樹掩江春。',48,'全唐诗/poet.song.237000.json','["野雲埋墅晚，城樹掩江春。", "門巷人烟古，雲山屋宅新。", "悲歌陶此世，塵土汚吾身。", "無地堪挑薺，殊乖晚膳真。"]'),
('810a025b-c628-4721-b4fe-52e93b1e3bba','泊鴈汊寄主簿','董嗣杲','宋','宋诗','song-poetry','','[]','窮通歸造化，蹤跡易參商。',48,'全唐诗/poet.song.237000.json','["窮通歸造化，蹤跡易參商。", "自畫新居様，誰傳舊稾香。", "寒沙埋虎坂，晚燒起龍岡。", "相望風塵濶，愁懐不可量。"]'),
('800a9baf-8318-46b8-a24c-d4ed74bd54b0','夜坐','董嗣杲','宋','宋诗','song-poetry','','[]','西原陰接樹，東浦暝沉籬。',48,'全唐诗/poet.song.237000.json','["西原陰接樹，東浦暝沉籬。", "月落溪沙走，星飛岸柳移。", "鮮螢縈淺草，幽鳥擇深枝。", "背水中宵坐，愁多病莫支。"]'),
('1454da58-9d4c-4f74-83f1-48d692563ea6','坐病不赴姚總統席夜聞樂聲因寄','董嗣杲','宋','宋诗','song-poetry','','[]','精神疲夜漏，絃管沸秋筵。',48,'全唐诗/poet.song.237000.json','["精神疲夜漏，絃管沸秋筵。", "想醉黄花下，誰歌翠幙前。", "病身空羡酒，愁耳愛聽泉。", "月轉羈窗破，蕭蕭照客眠。"]'),
('a8f82ebe-9d32-4992-83e9-2161ef06665d','甲戌九日和樓宰烏回寺登髙','董嗣杲','宋','宋诗','song-poetry','','[]','烏回何代寺，鳩喚此山晴。',48,'全唐诗/poet.song.237000.json','["烏回何代寺，鳩喚此山晴。", "心契將軍約，肩摩小隊行。", "明年人更健，今夜月初明。", "更過譙樓飲，偏垂野客情。"]'),
('0fb068e0-89a0-42b7-bccc-c3d2748a65c5','滿替在眼即景賦二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','野分霜信薄，溪落雨痕乾。',48,'全唐诗/poet.song.237000.json','["野分霜信薄，溪落雨痕乾。", "僻邑催冬早，遥林積暝寒。", "雞棲隠壊壁，鶴老戀空闗。", "燭下哀筝發，樓頭送漏殘。"]'),
('9f9c78aa-48c0-4199-b02c-6591c029930d','滿替在眼即景賦二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','菊向籬陰老，松連石影交。',48,'全唐诗/poet.song.237000.json','["菊向籬陰老，松連石影交。", "山棃寒脫樹，溪鳥晚投巢。", "欲把肩輿卸，先將手版抛。", "是時柴户月，任客带吟敲。"]'),
('704d6049-5055-4c98-aece-85ab851d97e2','乾會聖節賜宴','董嗣杲','宋','宋诗','song-poetry','','[]','瑞靄薰風遍赤墀，共歌隨佛下生時。',64,'全唐诗/poet.song.237000.json','["瑞靄薰風遍赤墀，共歌隨佛下生時。", "報班立筍嵩呼逺，接宴簪花拜舞遲。", "聫坐不矜朝士貴，綴員深愧醴曹卑。", "山中雨露恩榮溥，賦得三宮萬壽詩。"]'),
('eaa6c616-3112-4ab9-9460-d60763609fe6','暑中宴張穆父第','董嗣杲','宋','宋诗','song-poetry','','[]','席地莫禁流汗體，陰陰竹樹埋虚堂。',64,'全唐诗/poet.song.237000.json','["席地莫禁流汗體，陰陰竹樹埋虚堂。", "夜分幾傳逡巡酒，暑甚一沃沆瀣漿。", "不聽哀絃知興逸，纔舒清簟覺心凉。", "青瓜碧李凝冰齒，萬蕚南花吹濕香。"]'),
('39bd5ca9-fcf6-42c8-9cb0-511fc4bb7efe','劉閤舍遷居山中','董嗣杲','宋','宋诗','song-poetry','','[]','玉粒榮途稅駕難，遯棲山屋樂顔簞。',64,'全唐诗/poet.song.237000.json','["玉粒榮途稅駕難，遯棲山屋樂顔簞。", "寫梅當畫同誰賞，採菊成糧獨自餐。", "五字詩成消興晚，半缻酒熟抵秋寒。", "太空月色清如洗，多向疎林缺處看。"]'),
('8eef030e-c9d3-412c-bd6e-9982e786123b','壺中日月與葛秋巖納凉','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','身離匡廬紫翠重，壺中且寄水雲蹤。',64,'全唐诗/poet.song.237000.json','["身離匡廬紫翠重，壺中且寄水雲蹤。", "故人逺夢迷千里，濁酒髙懐渺萬鍾。", "臺上苦吟無别事，枕前間籟有孤松。", "不知憂樂隨時意，但慮荒蕪鈍筆鋒。"]'),
('c07d720a-c32a-4a2a-a2cf-49e77d37048f','陳石泉送詩走筆次韻','董嗣杲','宋','宋诗','song-poetry','','[]','依劉殊乏仲宣才，方重相逢笑口開。',64,'全唐诗/poet.song.237000.json','["依劉殊乏仲宣才，方重相逢笑口開。", "惡况敗人佳思盡，寓公貽我好詩來。", "夜寒歸夢迷松菊，灰冷塵蹤混草萊。", "别後莫裁馳戀意，寄梅須带雪枝苔。"]'),
('ffee3d07-8d78-408b-ae83-ae08c1e2dab5','題大賽山中人家','董嗣杲','宋','宋诗','song-poetry','','[]','課孫課子業桑麻，最喜無人識故家。',64,'全唐诗/poet.song.237000.json','["課孫課子業桑麻，最喜無人識故家。", "八口日支資地力，一頭雪色感年華。", "甜瓜苦過王戎李，古木枯如博望槎。", "豈得不諳培植性，又思尋客學餐霞。"]'),
('f59aeca0-efbb-4084-8ce7-9d23552fdcf5','玉繡毬花  其一','董嗣杲','宋','宋诗','song-poetry','','[]','芳妍獨殿緑陰闌，幾簇流瓊擁髻鬟。',64,'全唐诗/poet.song.237000.json','["芳妍獨殿緑陰闌，幾簇流瓊擁髻鬟。", "攢粉倚風揺舞地，妬晴抛日透飛闗。", "蝶魂春聚蒼枝頂，雪片寒團翠幄間。", "花壓露梢如許重，有瓶難插懶能攀。"]'),
('ae0e0f35-f0a9-4aae-88a6-1a1a666c8797','玉繡毬花  其二','董嗣杲','宋','宋诗','song-poetry','','[]','潔身自擁翠枝寒，遺得春魂寄素顔。',64,'全唐诗/poet.song.237000.json','["潔身自擁翠枝寒，遺得春魂寄素顔。", "夜月曳光凝絕徑，晚風抛影入空闗。", "幾團白雪能嬌膩，五色流蘇只等閑。", "宛似戀香蝴蝶亂，緑陰深處不飛還。"]'),
('5383a4b4-3231-4535-a5d2-2d65ef6276b3','送陸明府歸嘉禾','董嗣杲','宋','宋诗','song-poetry','','[]','塵雜莫湔游宦非，端憂何暇寓琴徽。',64,'全唐诗/poet.song.237000.json','["塵雜莫湔游宦非，端憂何暇寓琴徽。", "孝先便腹尚嘲懶，元亮折腰須問歸。", "所懼棄官鄉曲笑，不思獻策廟堂稀。", "義和市尾漁舟聚，獨樂披裘坐釣磯。"]'),
('2403cd22-3898-4441-a6aa-c5161d83e9e6','水退小園散步時垂替感賦','董嗣杲','宋','宋诗','song-poetry','','[]','移來菊本已成叢，潦退園籬失笑空。',64,'全唐诗/poet.song.237000.json','["移來菊本已成叢，潦退園籬失笑空。", "夢蝶自應知境幻，問牛誰謂可年豐。", "渺茫天地浮秋水，寂歴溪山截暮虹。", "蛩咽莫禁莎砌濕，萬愁愁付酒杯中。"]'),
('ff8da81c-bc43-49c0-91b8-5583884a3445','近苦多故坐病乏藥','董嗣杲','宋','宋诗','song-poetry','','[]','江郊雪沍莫知津，客淚雙垂悵此身。',64,'全唐诗/poet.song.237000.json','["江郊雪沍莫知津，客淚雙垂悵此身。", "魔障在前無妄想，饑寒隨處肯言貧。", "畏途日有風波恐，病骨時需藥石頻。", "屏息支吾心已擾，眼前謀絕故鄉親。"]'),
('5b1926b2-b149-49d3-a130-2731537ed537','甲戌重午留越寄武康同官','董嗣杲','宋','宋诗','song-poetry','','[]','湘纍莫弔楚雲迷，力疾喑喑客會稽。',64,'全唐诗/poet.song.237000.json','["湘纍莫弔楚雲迷，力疾喑喑客會稽。", "心想同寅分席醉，身逢重午借樓棲。", "今朝氣象悲歡異，幾種葵橊色澤齊。", "水際晚凉應有賦，藕花多處想供題。"]'),
('8a4f04f0-995c-4f91-b151-553711f5ccfd','縣齋東堂盆荷著花樓恪齋約客賞之時葛秋巖作草聖和席間韻二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','酸辛莫甚此時心，忍過琴廳散客襟。',64,'全唐诗/poet.song.237000.json','["酸辛莫甚此時心，忍過琴廳散客襟。", "萬竹静涵空翠杳，孤蓮愁吐妬紅深。", "岫雲有信投林晚，溪霧無根漲郭陰。", "誰草數行鴉蚓墨，東堂古壁遇知音。"]'),
('6ff07d99-68b5-4796-91d8-b673e1746f37','縣齋東堂盆荷著花樓恪齋約客賞之時葛秋巖作草聖和席間韻二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','簾底陪清傍兩年，愁城築得許能堅。',64,'全唐诗/poet.song.237000.json','["簾底陪清傍兩年，愁城築得許能堅。", "詩章罷詠猶評畫，管樂沈聲却得蟬。", "花縣無心聽夜漏，英溪有日罷歸船。", "敲窗更苦西風急，又攬閒情伴葛仙。"]'),
('c3a9fd52-7e26-42a2-9135-40e3b5760d17','越城客中','董嗣杲','宋','宋诗','song-poetry','','[]','暑滋衣袖苦逢迎，濡滯連旬夢亦驚。',64,'全唐诗/poet.song.237000.json','["暑滋衣袖苦逢迎，濡滯連旬夢亦驚。", "奔走泥塗誰送死，浮沉光景自憐生。", "鴉穿晚照棲公館，龍挾晴雲入子城。", "亂試法歌攢碧落，無端新月客窗明。"]'),
('efba63e1-e7cf-4d36-b96e-6f131be97d04','武康邑中劉王廟','董嗣杲','宋','宋诗','song-poetry','','[]','水圍聚落藹藤纒，靈紀金刀祀典専。',64,'全唐诗/poet.song.237000.json','["水圍聚落藹藤纒，靈紀金刀祀典専。", "碑語誰非年月誤，神功自托道途傳。", "三鄉捐廩祈多福，百里齎香卜有年。", "争怪野雲頭上起，村村先欲雨公田。"]'),
('5960c91d-04b5-446f-8bb8-75616fca97e8','抵北新橋','董嗣杲','宋','宋诗','song-poetry','','[]','指出飛梁是北新，羈懐冰釋返吾真。',64,'全唐诗/poet.song.237000.json','["指出飛梁是北新，羈懐冰釋返吾真。", "歸逢鄉井心纔穏，羞對湖山迹已陳。", "徹鑰要芟三徑草，懐人空睨一汀蘋。", "滿頭殘髮凝霜膩，達旦梳雲却愛頻。"]'),
('cb9e0553-1cd7-40d2-baaf-1c8521982a73','題意香壁','董嗣杲','宋','宋诗','song-poetry','','[]','養生肯羡葛洪砂，醒困還評陸羽茶。',64,'全唐诗/poet.song.237000.json','["養生肯羡葛洪砂，醒困還評陸羽茶。", "溪上攬雲歸酒屋，雨中看瀑憶樵家。", "時時禽鳥嗚心曲，歲歲風霜趲鬢華。", "窗户生香還有意，夕陽紅皺石榴花。"]'),
('cf47cc3b-bfea-4c47-80d3-9c495408ac38','思隠二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','岌嶪愁城不可攻，三年心事入秋空。',64,'全唐诗/poet.song.237000.json','["岌嶪愁城不可攻，三年心事入秋空。", "虚名已出諸公右，往事都歸一笑中。", "植杖耘田思北墅，補爐煮藥老西風。", "臨歸自照凉池影，不與初來面目同。"]'),
('1e5459da-4171-481b-a61c-c8e1b1d44b56','思隠二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','夢落家村野屋磯，欲治生事與心違。',64,'全唐诗/poet.song.237000.json','["夢落家村野屋磯，欲治生事與心違。", "偃禾雨久溪聲改，采菊人歸鬢色非。", "灌圃肯差陳仲子，登山莫遜謝元暉。", "從今舉步防輕蹈，更演潛書急掩扉。"]'),
('563acc65-1035-4911-9380-060166d2e0a9','夜坐','董嗣杲','宋','宋诗','song-poetry','','[]','秋清道院空，更籌受風掩。',24,'全唐诗/poet.song.237000.json','["秋清道院空，更籌受風掩。", "二更看斜河，濕却萬星點。"]'),
('daed3b1f-352a-4800-bad4-5677a5b87d0f','陌上二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','水花粘稚蛙，野菜戀殘蝶。',24,'全唐诗/poet.song.237000.json','["水花粘稚蛙，野菜戀殘蝶。", "麥岐苦薄收，青黄兩不接。"]'),
('c2dd768e-1aa1-4871-b8d8-6edc03ff22c6','陌上二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','恨鵑啼桑顛，醜婦淚如洗。',24,'全唐诗/poet.song.237000.json','["恨鵑啼桑顛，醜婦淚如洗。", "手中捻銀絲，階頭博紅米。"]'),
('b09e2e08-e162-42be-a94c-ece6b4f0c925','估客謡二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','浪兒重規利，半世家如寄。',24,'全唐诗/poet.song.237000.json','["浪兒重規利，半世家如寄。", "千金得美人，長向船窗醉。"]'),
('b9f813bb-fc2e-4f5c-98c6-cc7db053777e','估客謡二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','溺利誰知輕，性流甚於水。',24,'全唐诗/poet.song.237000.json','["溺利誰知輕，性流甚於水。", "東去復西回，難將逝水比。"]'),
('32acd0d1-eb36-462d-9e72-846ad9dd6273','逢曹子敬知錄三首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','相逢愁醉霅溪西，老却陳思七步詩。',32,'全唐诗/poet.song.237000.json','["相逢愁醉霅溪西，老却陳思七步詩。", "二十年前親擢第，孤忠曾際穆陵知。"]'),
('977524d4-f271-4d30-85ca-a38f306dc3b7','逢曹子敬知錄三首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','州縣間闗老調官，青衫敝盡只儒酸。',32,'全唐诗/poet.song.237000.json','["州縣間闗老調官，青衫敝盡只儒酸。", "玉堂學士思求代，珍重春風在筆端。"]'),
('2404ec9c-8135-46d8-88da-b549f918c64d','逢曹子敬知錄三首  其三','董嗣杲','宋','宋诗','song-poetry','','[]','屏氣安時彼此同，此時虹燄已銷空。',32,'全唐诗/poet.song.237000.json','["屏氣安時彼此同，此時虹燄已銷空。", "東君造化攙春早，看取花開自在紅。"]'),
('44f3d02a-42d6-4585-b50a-cf6b3f04c2fd','陳石泉送芍藥花','董嗣杲','宋','宋诗','song-poetry','','[]','花分近侍了春殘，分付荼䕷糝雪寒。',32,'全唐诗/poet.song.237000.json','["花分近侍了春殘，分付荼䕷糝雪寒。", "天色轉陰陰轉雨，愁人可憑柳邊闌。"]'),
('50111b10-508e-41b5-b875-aad5c0e7488e','寄廬山道士二首  其一','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','纔懐故里餘清夢，方說廬山得好詩。',32,'全唐诗/poet.song.237000.json','["纔懐故里餘清夢，方說廬山得好詩。", "何日與師傳菊酒，劇談浩劫未分時。"]'),
('fa30662d-376e-4b26-8b86-adb7fa9b20ac','寄廬山道士二首  其二','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','常常有約尋幽趣，汨汨無從避俗喧。',32,'全唐诗/poet.song.237000.json','["常常有約尋幽趣，汨汨無從避俗喧。", "欲斷世間千萬事，須窮紙上五千言。"]'),
('48135230-0af7-4934-9882-561313e3d749','秋夜','董嗣杲','宋','宋诗','song-poetry','','[]','秋堂初霽短檠凉，堂外風簾減舊香。',32,'全唐诗/poet.song.237000.json','["秋堂初霽短檠凉，堂外風簾減舊香。", "螢火正流孤溆燄，閒來坐覺二更長。"]'),
('2963d4fc-b3e9-4a30-a175-fa6e876a6550','豐樂樓','董嗣杲','宋','宋诗','song-poetry','','[]','鶯花簫鼓綺羅叢，人在熈和境界中。',64,'全唐诗/poet.song.237000.json','["鶯花簫鼓綺羅叢，人在熈和境界中。", "海？三登歌化日，湖山一覽醉春風。", "水揺層棟青紅濕，雲鎖危梯粉黛空。", "十里掌平都掩盡，有誰曾紀建樓功。"]'),
('b480b66c-1a42-44b5-9ede-ebf1e4c134d6','湧金池','董嗣杲','宋','宋诗','song-poetry','','[]','一道香溝壓郭西，粉墻低䕶石階危。',64,'全唐诗/poet.song.237000.json','["一道香溝壓郭西，粉墻低䕶石階危。", "短碑數尺鎸何字，清泰三年鑿此池。", "橋市浣衣無空處，廟門賣卜有靈時。", "碧桃自趁東流水，暗老春光水不知。"]'),
('6e3307dc-324c-4266-8e95-1db9f749a3f5','環碧園','董嗣杲','宋','宋诗','song-poetry','','[]','繞舍晴波聚釣仙，五龍祠畔柳洲前。',64,'全唐诗/poet.song.237000.json','["繞舍晴波聚釣仙，五龍祠畔柳洲前。", "清虚不類侯家屋，輪奐曾資母后錢。", "三面軒窗秋水觀，四時簫鼓夕陽船。", "攬將山北山南翠，獨有黄昏得景全。"]'),
('4707ab69-93d7-4a63-a0cd-f591f8876aff','玉蓮堂','董嗣杲','宋','宋诗','song-poetry','','[]','仙根曾就華峰移，净引湘波出浴妃。',64,'全唐诗/poet.song.237000.json','["仙根曾就華峰移，净引湘波出浴妃。", "龍？先皇三字在，燕居舊尹一清非。", "風簷揺影涼姿媚，月檻迷香冷艷肥。", "平展水天菱唱逺，竹山蒼翠自成圍。"]'),
('9771bc99-945f-4aac-a14e-39a49338e410','玉壺園','董嗣杲','宋','宋诗','song-poetry','','[]','莫問南漪與玉壺，杜鵑還更試花無。',64,'全唐诗/poet.song.237000.json','["莫問南漪與玉壺，杜鵑還更試花無。", "坡仙一顧吟空老，地主頻更景不殊。", "船出斷橋春溆逺，鐘傳蕭寺晚樓孤。", "山明水秀軒扉敞，落日漁歌過裏湖。"]'),
('c63033fe-1a26-4a04-99e8-c2129c516b6f','先得樓','董嗣杲','宋','宋诗','song-poetry','','[]','瀲灧澄波漾彩椽，柳絲晴絆俊遊鞭。',64,'全唐诗/poet.song.237000.json','["瀲灧澄波漾彩椽，柳絲晴絆俊遊鞭。", "傍湖莫厭官樓水，得月無如此地先。", "迎榜書生空絳帳，抱琴才子沃金船。", "壺天蕭爽人人醉，雪色屏風畫謫仙。"]'),
('69e8fa5c-7362-4c3d-ae55-5285d510e888','古柳林','董嗣杲','宋','宋诗','song-poetry','','[]','幾眠幾醒幾清明，萬態風流學老成。',64,'全唐诗/poet.song.237000.json','["幾眠幾醒幾清明，萬態風流學老成。", "古翠碧連雲洞杳，夕陽西捲射場平。", "絮團破徑應迷蝶，枝壓荒墻不露鶯。", "如此多栽堪卜隐，苦無十畆秫田耕。"]'),
('99f1cc49-a8a0-46fe-9e3b-003786311c7a','雲洞園','董嗣杲','宋','宋诗','song-poetry','','[]','擁湖營圃藉元勲，景色天然曲折分。',64,'全唐诗/poet.song.237000.json','["擁湖營圃藉元勲，景色天然曲折分。", "水脉窨花通活港，洞基壘石走空雲。", "千間大厦歸春夢，一撮危亭納夕曛。", "扁畫自懸碑自壓，當年何事立孤墳。"]'),
('eb9382c0-0cad-492a-9796-3bc8a0457aae','霍山祠','董嗣杲','宋','宋诗','song-poetry','','[]','霍家山下敞行宫，溜水橋西透鼓鐘。',64,'全唐诗/poet.song.237000.json','["霍家山下敞行宫，溜水橋西透鼓鐘。", "古迹建平遺烈在，春風廣惠歷朝封。", "露臺獻社呈蒼馬，陰壁飛旌繪赤龍。", "蟻聚乞靈人散後，雲街雨陌撼濤松。"]'),
('add947c6-b462-417d-b559-e934f6396437','湧泉','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山腰溜脉出遥峰，隔斷西湖翠幾重。',64,'全唐诗/poet.song.237000.json','["山腰溜脉出遥峰，隔斷西湖翠幾重。", "疊甃漫依僧刹久，煎茶曾入翰林供。", "亭心覆雨塗丹鳯，石口嘘雲噴玉龍。", "何日星馳天使絕，不知誰利湼槃宗。"]'),
('80654564-925d-47ef-97a1-416ae75d5ee3','東西馬塍','董嗣杲','宋','宋诗','song-poetry','','[]','土城聚落界西東，業在澆畦奪化工。',64,'全唐诗/poet.song.237000.json','["土城聚落界西東，業在澆畦奪化工。", "接死作生滋夜雨，變紅爲白借春風。", "幾家衣食花姿異，兩岸園池地勢同。", "病叟扶鋤耡晚照，前身莫是槖駞翁。"]'),
('bef22a7f-6e55-47eb-8ef4-f3d40f1119a2','石函橋','董嗣杲','宋','宋诗','song-poetry','','[]','函開函閉管年豐，白傅能方夏禹功。',64,'全唐诗/poet.song.237000.json','["函開函閉管年豐，白傅能方夏禹功。", "湖石記埋泥蘚裏，斗門字蝕水花中。", "犁平阡陌猶春雨，船載笙歌自晚風。", "遍倚暮闌懐古往，月明無奈瀑聲空。"]'),
('bb86840f-8d45-4cc4-8c92-97f7e46fe0ea','孤山路','董嗣杲','宋','宋诗','song-poetry','','[]','翠微四絕載蓬瀛，柳引遊人入畫屏。',64,'全唐诗/poet.song.237000.json','["翠微四絕載蓬瀛，柳引遊人入畫屏。", "詩借樂天傳得久，山因和靖隠來靈。", "半空梁駕橋闌赤，一道腰分草界青。", "粧點風光如此盛，藕花香裏又三亭。"]'),
('c35bae99-3e8d-4031-8ab5-54e2678dcb7e','德生堂','董嗣杲','宋','宋诗','song-poetry','','[]','瑶臺瑞滿玉皇家，澤溥山巔與水涯。',64,'全唐诗/poet.song.237000.json','["瑶臺瑞滿玉皇家，澤溥山巔與水涯。", "魚躍鳶飛函德意，天長地久演年華。", "金揺巨扁雙龍護，翠掩髙碑一字差。", "須信石頑能萬古，老龜無語問鶯花。"]'),
('f634fc3a-72f6-4c91-a30a-3c32bb247030','總宜園','董嗣杲','宋','宋诗','song-poetry','','[]','望極湖山變幻奇，萬千光景自紛披。',64,'全唐诗/poet.song.237000.json','["望極湖山變幻奇，萬千光景自紛披。", "妙分西子争妍態，絕想東坡得句時。", "桞徑曲埋兜率寺，花陰直接放生池。", "內官愛展亭臺去，盡付年華與酒巵。"]'),
('3d885d27-5cc5-46f2-bcd5-20335ab8d97c','斷橋','董嗣杲','宋','宋诗','song-poetry','','[]','繡轂青驄驟晚風，柳絲翠裊石闌紅。',64,'全唐诗/poet.song.237000.json','["繡轂青驄驟晚風，柳絲翠裊石闌紅。", "彩篙刺水停飛鷁，華表侵雲截卧虹。", "杖屨誰歸瀛嶼去，笙歌自補玉壺空。", "重招張祜商新詠，不與當時蘚合同。"]'),
('e86b23fa-e728-45ca-9d41-2cc25b6047a4','大佛頭','董嗣杲','宋','宋诗','song-poetry','','[]','不是金塗丈六仙，莊嚴法界想西天。',64,'全唐诗/poet.song.237000.json','["不是金塗丈六仙，莊嚴法界想西天。", "自因僧浄鎸空像，誰說秦皇纜海船。", "全體未知何日現，半生且坐此山禪。", "石頭照水無塵土，飽聽鐘聲雜管絃。"]'),
('18ae5758-7d86-4290-ab1f-0126fe1cff36','葛嶺','董嗣杲','宋','宋诗','song-poetry','','[]','白雲幾疊翠嵐重，往往踈鐘出梵宫。',64,'全唐诗/poet.song.237000.json','["白雲幾疊翠嵐重，往往踈鐘出梵宫。", "石骨誰人鎸佛像，嶺頭何處覔仙翁。", "樓臺水月丹青地，簾幙鶯花錦繡叢。", "遊子莫支蒼竹去，風雷容易起虚空。"]'),
('218bf4f7-b7d3-43a4-89e7-6e93b840aca2','保叔塔','董嗣杲','宋','宋诗','song-poetry','','[]','咸平曾有募緣僧，遍走街坊負叔稱。',64,'全唐诗/poet.song.237000.json','["咸平曾有募緣僧，遍走街坊負叔稱。", "定力一堅無外想，窣波七級可中興。", "愚夫春日燒冥𥯃，道者昏時炙梵燈。", "祗怪青龍行雨過，煙雲遍護最髙層。"]'),
('8c2195c6-83eb-4dbb-974a-a2abf263ed9a','巾子山','董嗣杲','宋','宋诗','song-poetry','','[]','岌嶪山形醜莫收，傍湖獨整傲春秋。',64,'全唐诗/poet.song.237000.json','["岌嶪山形醜莫收，傍湖獨整傲春秋。", "幾株烏桕無根在，一幅華陽有様留。", "寒日霜乾還掠額，曉天嵐重且遮頭。", "東籬漉酒人知得，醒立風前不可求。"]'),
('79bce50f-bec6-435e-9ab3-7e8c4c56fc31','水月園','董嗣杲','宋','宋诗','song-poetry','','[]','園門當路掩清華，喬木靈根裹翠霞。',64,'全唐诗/poet.song.237000.json','["園門當路掩清華，喬木靈根裹翠霞。", "地擁樓臺齊葛嶺，天分香影傍林家。", "中興勲將曾營業，外邸王孫且看花。", "月色水光三十里，何人來此泛仙槎。"]'),
('b8cffecf-83a2-434e-b24b-bc08f56e303d','水仙廟','董嗣杲','宋','宋诗','song-poetry','','[]','雲翹雨佩有遺仙，香火寜隨世道遷。',64,'全唐诗/poet.song.237000.json','["雲翹雨佩有遺仙，香火寜隨世道遷。", "廟始大同年紀著，額頒乾化敕碑鎸。", "鳳閒露輦荒瑶草，龍濕秋衣翦玉蓮。", "隄上創新誰述記，却無門外一泓泉。"]'),
('b3670379-2ee1-4a79-89ec-0aac16157904','寒泉','董嗣杲','宋','宋诗','song-poetry','','[]','照膽寒泓覆有亭，此泉曾入老坡評。',64,'全唐诗/poet.song.237000.json','["照膽寒泓覆有亭，此泉曾入老坡評。", "八詩最得吟梅苦，一盞能消薦菊清。", "不拜韜光徴士詔，却傳配食水仙名。", "銀床響絕無人汲，墓在孤山木自榮。"]'),
('1d7081bf-477d-48c3-82f1-c1fe11a16330','參寥泉','董嗣杲','宋','宋诗','song-poetry','','[]','湖曲春風正禁煙，試茶味此石間泉。',64,'全唐诗/poet.song.237000.json','["湖曲春風正禁煙，試茶味此石間泉。", "坡仙忽憶黄州夢，濳老初拈智果禪。", "幾客醉遊三月裏，一聨詩兆七年前。", "題梁妙墨如新染，合與雲崖淺井傳。"]'),
('1fdda9be-b9aa-41bc-bc7f-16cf52816989','葛公雙井','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','仙翁洗藥傍西湖，脉與靈山碧溜俱。',64,'全唐诗/poet.song.237000.json','["仙翁洗藥傍西湖，脉與靈山碧溜俱。", "泉迸一枝源更異，甃分雙眼味何殊。", "石函霞湧沉鉛汞，井屋風清轉轆轤。", "日日汲花朝復暮，當方曾說病人無。"]'),
('587af504-73dd-45e3-96b2-da642e40ba51','江湖偉觀','董嗣杲','宋','宋诗','song-poetry','','[]','倚空窗户不曾扄，兩眼風煙障翠屏。',64,'全唐诗/poet.song.237000.json','["倚空窗户不曾扄，兩眼風煙障翠屏。", "西子艷分晴雨倦，伍胥魂激浪濤腥。", "鼓簫咽晚難無酒，花柳争春别有亭。", "恨掩四時歌舞去，古祠寒玉幾竿青。"]'),
('4f2670dd-5df5-4547-b853-b8561a0a6fdd','此君軒','董嗣杲','宋','宋诗','song-poetry','','[]','瀟灑幽扉掩碧叢，塵昏題扁想坡翁。',64,'全唐诗/poet.song.237000.json','["瀟灑幽扉掩碧叢，塵昏題扁想坡翁。", "六千君子寒光落，十二䦨干晚色空。", "僧指舊基埋積雨，鳥翻新籜起枯風。", "蒼凉不障層坡峻，一擊亭閒夕照中。"]'),
('af406928-2d88-41fc-8118-78f8b2e2bd94','杯泉','董嗣杲','宋','宋诗','song-poetry','','[]','古甃澄泓照膽清，畫龍壁暗挂瓢輕。',64,'全唐诗/poet.song.237000.json','["古甃澄泓照膽清，畫龍壁暗挂瓢輕。", "汲來不療相如渇，掬處難供太白傾。", "傍屋四圍埋石色，侵山一溜走溪聲。", "鉢盂可攬江湖濶，參取詩禪放眼明。"]'),
('b87c73bf-448a-454f-8424-f5f9f227be4d','初陽臺','董嗣杲','宋','宋诗','song-poetry','','[]','寶山山頂結芙蓉，方士凌虚幾御風。',64,'全唐诗/poet.song.237000.json','["寶山山頂結芙蓉，方士凌虚幾御風。", "日月光華含吐異，雲萍踪跡往來空。", "石盤草子粘深碧，土級苔花剥碎紅。", "舍側又將精舍展，蓬瀛有路直能通。"]'),
('9143e8ab-9ba3-4647-a65a-9819a889e477','孤山','董嗣杲','宋','宋诗','song-poetry','','[]','縹緲蓬萊擁翠寒，百年營取屋千間。',64,'全唐诗/poet.song.237000.json','["縹緲蓬萊擁翠寒，百年營取屋千間。", "黄庭殿矗煙霞老，瀛嶼堂幽日月閒。", "水泛花陰藏輦路，墻分柳色護仙闗。", "林家梅塜陳家柏，萬古流芳鎮此山。"]'),
('f7e6b392-32cc-4572-b1d3-098dcd2e6aae','和靖先生墓','董嗣杲','宋','宋诗','song-poetry','','[]','詔旨天頒起卧龍，首丘甘老水雲東。',64,'全唐诗/poet.song.237000.json','["詔旨天頒起卧龍，首丘甘老水雲東。", "一聨香影孤山月，兩架茅茨萬古風。", "有鶴有童家事足，無妻無子世緣空。", "清標卓絕何人繼，表表仙宫壠樹中。"]'),
('a0055b91-df11-4e6f-8a6f-4615ee14a3cd','陳朝柏','董嗣杲','宋','宋诗','song-poetry','','[]','枯株獨壽憶雙棲，誰想天嘉蓊鬰時。',64,'全唐诗/poet.song.237000.json','["枯株獨壽憶雙棲，誰想天嘉蓊鬰時。", "坡老詩成無繼筆，阜陵書此有遺碑。", "日揺槎影龍蛇斷，雪綴花痕鳥雀疑。", "化日可期人莫訝，柏堂不復辨荒基。"]'),
('a8bdb224-c1f8-47c8-af74-7cd79f015d58','瑪瑙坡','董嗣杲','宋','宋诗','song-poetry','','[]','支徑逶迤混碧苔，樹根積水沒蒿萊。',64,'全唐诗/poet.song.237000.json','["支徑逶迤混碧苔，樹根積水沒蒿萊。", "兩坡截路棊分處，何日經人斧鑿來。", "誰說異光迷草野，要知遺蹟等塵埃。", "孤山瓦礫曾聞道，寄語貪夫莫狼猜。"]'),
('fdc93de9-94fa-41b8-bc87-acb0dc8b5dff','金沙井','董嗣杲','宋','宋诗','song-poetry','','[]','沙漾金星湧活泉，虚堂龍染德馨懸。',64,'全唐诗/poet.song.237000.json','["沙漾金星湧活泉，虚堂龍染德馨懸。", "朱繩汲冷梅林外，翠甃圍凉桂洞前。", "石鼎煮茶非異事，井闌鎸字是何年。", "西南雲擁仙人屋，品酌今誰想樂天。"]'),
('b0b88dcd-38e8-46a4-ab5d-77bb43d11b44','六一泉','董嗣杲','宋','宋诗','song-poetry','','[]','一别孤山十八年，重來忍見講堂泉。',64,'全唐诗/poet.song.237000.json','["一别孤山十八年，重來忍見講堂泉。", "當時同出師門下，今日多傷井屋前。", "取重歐公名有自，肯教勤老跡空傳。", "此銘此意流千古，鑿石爲庵不可眠。"]'),
('0f4daa64-bb41-4817-9d62-504ac8953021','西林橋','董嗣杲','宋','宋诗','song-poetry','','[]','水竹雲山拱畫圖，因懐喚渡想東都。',64,'全唐诗/poet.song.237000.json','["水竹雲山拱畫圖，因懐喚渡想東都。", "雨餘晴蝀銜西照，風遏春船入裏湖。", "闌曲祗供遊子憑，林間今有野人無。", "隔墻莫是神仙宅，紅白梅花五百株。"]'),
('60dea730-7042-4854-b1cc-17b725f293ca','鳥窠','董嗣杲','宋','宋诗','song-poetry','','[]','松頂巢成亦甚危，元和禪此太和歸。',64,'全唐诗/poet.song.237000.json','["松頂巢成亦甚危，元和禪此太和歸。", "比丘隨處心傳異，刺史遊山禮謁稀。", "銘誌土侵無幾字，塔亭雨壊有孤扉。", "一空四十年間夢，定業門前鵲自飛。"]'),
('60bac01c-6a38-4b82-852b-a57d667ec0e9','樂天竹閣','董嗣杲','宋','宋诗','song-poetry','','[]','此君玉立此樓空，不復幽眠想白公。',64,'全唐诗/poet.song.237000.json','["此君玉立此樓空，不復幽眠想白公。", "百尺有簷侵碧落，千竿無語足清風。", "闌尖亭影流漁屋，龕面祠香托佛宫。", "石琢端平丞相記，都歸寶慶守臣功。"]'),
('b7edf2bc-3dcb-4819-bd01-c45a81154b37','岳鄂王墓','董嗣杲','宋','宋诗','song-poetry','','[]','將軍魂夢遶旌旃，偃月謀成尚忍言。',64,'全唐诗/poet.song.237000.json','["將軍魂夢遶旌旃，偃月謀成尚忍言。", "一旦風波誰左袒，八陵荆棘自中原。", "更無鴈带邉頭信，惟有天知地下寃。", "鬰鬱棲霞霞外樹，墓門不掩雀巢喧。"]'),
('9126c9b6-4ba3-4279-a4ee-bc82a8ba22eb','妙智菴洞','董嗣杲','宋','宋诗','song-poetry','','[]','梵庵雲隔洞髙虛，傍路陰森樹幾株。',64,'全唐诗/poet.song.237000.json','["梵庵雲隔洞髙虛，傍路陰森樹幾株。", "石室跨空山骨碎，林風掠地土痕枯。", "兩亭瀹俗秋偏暢，六月披襟暑欲無。", "如此巖墻難此立，有人編入職方圖。"]'),
('868668fd-deaf-424f-9f77-09c63a74f9a4','九里松','董嗣杲','宋','宋诗','song-poetry','','[]','開元刺史擅清風，九里親栽夾道松。',64,'全唐诗/poet.song.237000.json','["開元刺史擅清風，九里親栽夾道松。", "屋頂自生濤浪勢，根頭誰覔茯苓蹤。", "行春橋掩雲千態，一字門封翠幾重。", "人訝金填吳說筆，不知此筆遇髙宗。"]'),
('9a04052a-acf9-449b-8ade-f7e5277da2a9','玉泉','董嗣杲','宋','宋诗','song-poetry','','[]','南齊事蹟已銷沉，曾立苔碑記古今。',64,'全唐诗/poet.song.237000.json','["南齊事蹟已銷沉，曾立苔碑記古今。", "一老出泉猶撫掌，此僧演法欲傳心。", "樹頭龍過家家雨，池面魚游尾尾金。", "行客不須閒照影，要知澤物溥春霖。"]'),
('c5a47720-21e1-45cd-93d3-db12b33ed4c1','鮑家田','董嗣杲','宋','宋诗','song-poetry','','[]','衕轉東山憶故錢，錢家曾賜鮑家田。',64,'全唐诗/poet.song.237000.json','["衕轉東山憶故錢，錢家曾賜鮑家田。", "地名有自誰能考，相業無聞姓却傳。", "種藕户繁招宿鷺，尋花人倦信啼鵑。", "玉泉流蔭分西去，併入官塘漾野船。"]'),
('bf5393db-6318-43dc-b635-78d5932fa54e','忠勇廟','董嗣杲','宋','宋诗','song-poetry','','[]','纔接軍符便起程，此行要並鐵山名。',64,'全唐诗/poet.song.237000.json','["纔接軍符便起程，此行要並鐵山名。", "孤忠解得孤城急，一勇判來一死輕。", "堂屋依湖空柳色，廟門當路枕松聲。", "丈夫對著褒榮典，誓挽天河洗甲兵。"]'),
('fc6677c7-1cf7-486d-b23e-4bf85ca9f228','將軍教場墓','董嗣杲','宋','宋诗','song-poetry','','[]','閱武場開傍古松，忽驚塵起廢墻東。',64,'全唐诗/poet.song.237000.json','["閱武場開傍古松，忽驚塵起廢墻東。", "黑蜂飛毒歸鉏下，白骨通靈入夢中。", "花草地寛千騎勇，鼓鼙聲撼一壞空。", "若錢若馬訛傳久，難覔埋銘證異同。"]'),
('e99682b6-6962-47b4-9493-03320f541373','靈隠天竺寺門','董嗣杲','宋','宋诗','song-poetry','','[]','畫棟朱簷暴虎蹲，亂鐘穿翠掩朝昏。',64,'全唐诗/poet.song.237000.json','["畫棟朱簷暴虎蹲，亂鐘穿翠掩朝昏。", "去來所得無多衲，覺悟何曾有二門。", "山鳥山花應自若，佛心佛法與誰論。", "風埃幾換行人鬢，博士元公扁却存。"]'),
('7a8d9a2b-83a9-4ee5-8b7d-46a817e9aba9','合澗橋','董嗣杲','宋','宋诗','song-poetry','','[]','危闌壓定活流重，誰識錢源遶梵宫。',64,'全唐诗/poet.song.237000.json','["危闌壓定活流重，誰識錢源遶梵宫。", "兩澗共歸橋底合，萬雷莫敵水聲雄。", "遊人移步心還恐，野衲棲禪耳欲聾。", "石倚卧梁山月落，白猿一嘯五峯空。"]'),
('19a42d1f-1d5a-4103-b64a-ef136628a810','北髙峰','董嗣杲','宋','宋诗','song-poetry','','[]','幡竿裊影入青冥，暮鼓朝鐘鎮不停。',64,'全唐诗/poet.song.237000.json','["幡竿裊影入青冥，暮鼓朝鐘鎮不停。", "劫火幾灰龕底像，西風兩減塔層鈴。", "市人祈福心苖異，廟祝求金口角靈。", "三十六彎登絕頂，日中長現七元星。"]'),
('14ae981b-20d1-4a7c-bd5f-1118caa7123c','韜光菴','董嗣杲','宋','宋诗','song-poetry','','[]','悟得師禪隠此林，謾傳難下碧天吟。',64,'全唐诗/poet.song.237000.json','["悟得師禪隠此林，謾傳難下碧天吟。", "巢溝塢上人無迹，雲月堂前梅有陰。", "家棄蜀鄉年歲逺，身濳洛寺屋廬深。", "死生印得香山去，可遂西來一片心。"]'),
('789c361f-2f76-490c-bc47-8e517f887304','石筍峰','董嗣杲','宋','宋诗','song-poetry','','[]','異種休參玉版禪，嶄然一角立層巔。',64,'全唐诗/poet.song.237000.json','["異種休參玉版禪，嶄然一角立層巔。", "逺尖自抱雲根壯，疊蘚誰疑雨籜纒。", "夢裏三生空過眼，胸中千畆謾流涎。", "此龍難入寜僧譜，出土摩霄是幾年。"]'),
('c2db09c3-91df-4d95-b28a-24ecc257b46d','西溪','董嗣杲','宋','宋诗','song-poetry','','[]','漁樵耕牧自成村，就屋編籬古意存。',64,'全唐诗/poet.song.237000.json','["漁樵耕牧自成村，就屋編籬古意存。", "出塢野雲多曲折，過橋溪水半清渾。", "一逢白壁書香社，幾見朱闌障墓門。", "地利最饒人事簡，山家還有别乾坤。"]'),
('4d07fa6a-9cd3-4b84-8813-5836fafebc23','飛來峰','董嗣杲','宋','宋诗','song-poetry','','[]','理公著脚五峰前，樹石蒼浮滴翠涎。',64,'全唐诗/poet.song.237000.json','["理公著脚五峰前，樹石蒼浮滴翠涎。", "因指何年飛到此，曾棲中竺悟來禪。", "一猿可驗爲靈鷲，萬古無言有冷泉。", "今日共知遺跡勝，隠名却有許由傳。"]'),
('43d66d4b-a024-4f56-ad27-eba25660972b','冷泉亭','董嗣杲','宋','宋诗','song-poetry','','[]','小朵峰前玉鏡寒，幾回倚杖聽潺湲。',64,'全唐诗/poet.song.237000.json','["小朵峰前玉鏡寒，幾回倚杖聽潺湲。", "箕公飲澗非凡水，慧理呼猿是此山。", "亭角静依金刹古，樹身凉卧石闌閒。", "無因可洗人間熱，時御清風照影還。"]'),
('0760b3a1-714f-47f6-9382-19d8716d0e2d','呼猿洞','董嗣杲','宋','宋诗','song-poetry','','[]','小隱靈山莫計年，此猿清嘯洞門前。',64,'全唐诗/poet.song.237000.json','["小隱靈山莫計年，此猿清嘯洞門前。", "當時不有胡僧唤，今日應無野迹傳。", "寒挂枯條申右臂，晚藏碧樹憶西天。", "雲巖烟谷多遺種，月下三聲醒客眠。"]'),
('a2aeee9f-380c-40b7-b8f3-aae38fda5e5c','龍泓洞','董嗣杲','宋','宋诗','song-poetry','','[]','葛翁行滿赤烏年，丹竈離披已絕煙。',64,'全唐诗/poet.song.237000.json','["葛翁行滿赤烏年，丹竈離披已絕煙。", "龍在此泓誰得見，路通别邑自相傳。", "樹頭雷兩遺神火，岩腹莓苔带海涎。", "有耳不須聞浪湧，只消采乳亦通仙。"]'),
('2c6ca969-6b39-47c4-ad0d-a7982b2261e4','理公巖','董嗣杲','宋','宋诗','song-poetry','','[]','西來識得此雲根，終此雲根護法門。',64,'全唐诗/poet.song.237000.json','["西來識得此雲根，終此雲根護法門。", "由晉尚傳斯語在，到今休想舊巖存。", "天開教觀香燈盛，人仰胡僧相貌尊。", "行果芟教荆棘盡，分明隻手破沉昏。"]'),
('847c0e34-0610-44a3-805f-78065bfa9af9','香林','董嗣杲','宋','宋诗','song-poetry','','[]','日月岩頭古翠埋，錦雲深隔洞門開。',64,'全唐诗/poet.song.237000.json','["日月岩頭古翠埋，錦雲深隔洞門開。", "蒼藤隨石無根活，靈杞何年有種栽。", "氣裊野烟疑麝過，暖熏山雨悞蜂來。", "空亭誰領幽芬坐，雲鶴同行損緑苔。"]'),
('d41ab86c-a15f-4a22-8e38-46cd9485ae17','翻經臺','董嗣杲','宋','宋诗','song-poetry','','[]','過門跬步入香林，七葉遺陰地尚靈。',64,'全唐诗/poet.song.237000.json','["過門跬步入香林，七葉遺陰地尚靈。", "曾借東山康樂手，共翻北本湼槃經。", "闌腰葉擁空臺赤，石罅泉通逺筧青。", "雲掩蓮花峰下座，若人演義若人聽。"]'),
('8c46402d-0ad6-476f-bdaf-6a7bba7e66d3','重榮檜','董嗣杲','宋','宋诗','song-poetry','','[]','一株蒼檜卧龍身，受得隋朝雨露深。',64,'全唐诗/poet.song.237000.json','["一株蒼檜卧龍身，受得隋朝雨露深。", "地下仙根將換骨，人間劫火不燒心。", "死條節節蕃春信，生意枝枝蓊翠陰。", "此木豈知魂可返，争傳咒水出叢林。"]'),
('e619cc4b-8e20-4b4a-bef9-0816055127ee','鍊丹井','董嗣杲','宋','宋诗','song-poetry','','[]','稚川曾此倒靈瓢，闌上銀牀壓甃腰。',64,'全唐诗/poet.song.237000.json','["稚川曾此倒靈瓢，闌上銀牀壓甃腰。", "丹氣騰空知幾轉，神光射屋起中宵。", "有茶可品春煎細，何疾能治曉汲遥。", "萬古仙踪應不泯，轆轤聲落病僧寮。"]'),
('1480f3c4-0815-4e96-91fb-79f2d6410a4f','跳珠軒','董嗣杲','宋','宋诗','song-poetry','','[]','溪流穏信竹龍驅，聲激清虚入耳孤。',64,'全唐诗/poet.song.237000.json','["溪流穏信竹龍驅，聲激清虚入耳孤。", "此竅可消諸念妄，一丸長躍半空珠。", "挂瓢舀水應知味，就壁龕碑不用砆。", "誰謂佛靈占有驗，殆於兒戯果何殊。"]'),
('cc0cc829-b6ed-476a-962f-b1cc8c452b06','曲水亭','董嗣杲','宋','宋诗','song-poetry','','[]','竹色松陰翠浪浮，春風吹落澗聲幽。',64,'全唐诗/poet.song.237000.json','["竹色松陰翠浪浮，春風吹落澗聲幽。", "古亭當路空凉影，溪水循盤散漫流。", "蠒紙叙詩年幾換，羽觴傳酒禊重修。", "晴嵐四掩鳴琴杳，如在稽山道上遊。"]'),
('101953c3-1810-4770-be16-f9a0a34b3c78','天竺觀音','董嗣杲','宋','宋诗','song-poetry','','[]','木異難儕衆木淹，刻成慈相孔仁謙。',64,'全唐诗/poet.song.237000.json','["木異難儕衆木淹，刻成慈相孔仁謙。", "真珠瓔珞鴛鴦殿，白玉屏風翡翠簾。", "晴雨禱祈隨感召，香燈熾盛極莊嚴。", "鎮山寶聚田廬廣，靈貺彌彰一百籖。"]'),
('22b69cbe-cf43-46c5-8989-4fe78d124288','風篁嶺','董嗣杲','宋','宋诗','song-poetry','','[]','横陳翠葆列烟屏，聨步蒼林想典刑。',64,'全唐诗/poet.song.237000.json','["横陳翠葆列烟屏，聨步蒼林想典刑。", "二老相分龍井嶺，一時如過虎溪亭。", "風吹貼石叢篁碧，雨剥題名暈蘚青。", "更有澗流朝暮落，此聲不厭客來聽。"]'),
('a33eb95d-21ba-43a6-9de2-27903e0a57bb','龍井','董嗣杲','宋','宋诗','song-poetry','','[]','腥攅石縫瀑花多，還有龍神蟄此窠。',64,'全唐诗/poet.song.237000.json','["腥攅石縫瀑花多，還有龍神蟄此窠。", "通海淺深山不語，隨潮長落水無波。", "謾傳方士遺丹在，不奈潜鱗吐霧何。", "時雨愆期無驗處，幾番雷火爇松柯。"]'),
('e2ceeaf9-2cdc-4a30-b569-c14ad9f8edfc','辨才塔','董嗣杲','宋','宋诗','song-poetry','','[]','瀾翻八十一年空，争訝前身是井龍。',64,'全唐诗/poet.song.237000.json','["瀾翻八十一年空，争訝前身是井龍。", "心静已成無上智，學知今復有誰宗。", "雲生遺塔封慈相，雨濺冲泉雜定鐘。", "幾字碑陰坡老筆，聲聲想得舊遊從。"]'),
('e9baec94-fb01-4b16-93a8-55c3ccff1c8c','梅坡園','董嗣杲','宋','宋诗','song-poetry','','[]','墻擁雙扉鎖錦窩，溪聲不敵樹聲多。',64,'全唐诗/poet.song.237000.json','["墻擁雙扉鎖錦窩，溪聲不敵樹聲多。", "誰家種麥曾名嶺，今日尋梅且陟坡。", "萬厦棟梁巢燕雀，四山風日養松蘿。", "園丁自飽栽花利，月給楊家得幾何。"]'),
('370ef5ad-ba6b-4c5c-8656-55982848941f','長耳相','董嗣杲','宋','宋诗','song-poetry','','[]','眉目如生骨骼寒，後來曾紀短碑頑。',64,'全唐诗/poet.song.237000.json','["眉目如生骨骼寒，後來曾紀短碑頑。", "雙垂長耳過肩角，千古遺軀落世間。", "覆履有方隨迹滅，守龕無語向僧閒。", "想知自醜難遮斷，兩扇禪扉及早闗。"]'),
('cc8739f5-4a70-49eb-be21-d829fab96519','玉岑','董嗣杲','宋','宋诗','song-poetry','','[]','雲掩風林萬竅號，慧因橋畔息方袍。',64,'全唐诗/poet.song.237000.json','["雲掩風林萬竅號，慧因橋畔息方袍。", "秦郎閒濯溪頭足，許老清揮石上毫。", "玉出何年迷草莽，教傳異域想波濤。", "山門翠擁山嵐潤，一道光芒月正髙。"]'),
('889fd7ff-0228-4715-a7b1-c6aa0f969efe','南髙峯塔','董嗣杲','宋','宋诗','song-poetry','','[]','誰舍塵身石骨巔，浮屠突兀拂霄躔。',64,'全唐诗/poet.song.237000.json','["誰舍塵身石骨巔，浮屠突兀拂霄躔。", "方隅端拱明離位，梯級髙營石晉年。", "土穴有龍嘘重霧，草庵無衲坐空禪。", "虚危直視烟霞路，鏜鞳風鈴到處傳。"]'),
('9e4c6456-2e07-41ad-ba1c-077468032dd5','烟霞洞','董嗣杲','宋','宋诗','song-poetry','','[]','萬色無如疊翠何，何僧鎸像屹嵳峩。',64,'全唐诗/poet.song.237000.json','["萬色無如疊翠何，何僧鎸像屹嵳峩。", "山屏晴掩牌門杳，風鑰陰封梵屋多。", "象落鼻形懸洞右，佛垂手跡寄岩阿。", "燈輝金碧琉璃椀，暗掩僧房絡薜蘿。"]'),
('67f01614-3f97-4ded-a022-18d4fee188bb','石佛庵','董嗣杲','宋','宋诗','song-poetry','','[]','南峯雲堕屋梁危，異蹟曾遺廣順時。',64,'全唐诗/poet.song.237000.json','["南峯雲堕屋梁危，異蹟曾遺廣順時。", "行脚影留巖石澗，頭陀老守草庵欹。", "幾年香火傳朝晚，萬谷烟霞擁路岐。", "半掩風扉鐘又響，風霜皴盡砌街碑。"]'),
('e3f82c70-f645-46d4-bbab-f268ca382c95','水樂洞','董嗣杲','宋','宋诗','song-poetry','','[]','築園裹寺接山椒，如此經營豈一朝。',64,'全唐诗/poet.song.237000.json','["築園裹寺接山椒，如此經營豈一朝。", "兩洞倚雲空鎻鑰，亂泉激雨想簫韶。", "樹埋院落闗門邃，石罨亭臺棧路遥。", "白髪聾僧扶舊額，金蓮又長玉淵苗。"]'),
('420548eb-a5b9-4e67-be10-131dd55b3b9d','楊梅塢','董嗣杲','宋','宋诗','song-poetry','','[]','仙子遺丹滿瑞峯，纍纍疑與荔枝同。',64,'全唐诗/poet.song.237000.json','["仙子遺丹滿瑞峯，纍纍疑與荔枝同。", "金婆傳種移根異，火齊燒空滿塢紅。", "鶴頂分丸凝曉露，猩唇結顆綴薰風。", "曩時若解包茆貢，一騎星馳入漢宫。"]'),
('582b1530-04f5-41aa-bc69-acc183783a7a','石屋','董嗣杲','宋','宋诗','song-poetry','','[]','雲梁烟棟翠嶔崟，五百癡人謾飾金。',64,'全唐诗/poet.song.237000.json','["雲梁烟棟翠嶔崟，五百癡人謾飾金。", "屋頂誰增華閣迥，石頭自擁白雲深。", "鐘聲透谷泉分響，鬼力支空雨聚陰。", "無廢無興無唘閉，老僧不動一生心。"]'),
('a8624a37-a78f-4b96-9724-da811ec6a11b','真珠泉','董嗣杲','宋','宋诗','song-poetry','','[]','泉光四散駭猿猱，迸起平池點滴髙。',64,'全唐诗/poet.song.237000.json','["泉光四散駭猿猱，迸起平池點滴髙。", "誰欲斗量徒積夢，人将瓶汲肯辭勞。", "聲随夜雨穿疎箔，名逐春風入小槽。", "别有雷峯峯下圃，一泓埋沒在蓬蒿。"]'),
('b63e05b5-4d22-4651-b3bb-fc61c7eb6634','虎跑泉','董嗣杲','宋','宋诗','song-poetry','','[]','廣福山靈托獸傳，甃邊依約爪痕堅。',64,'全唐诗/poet.song.237000.json','["廣福山靈托獸傳，甃邊依約爪痕堅。", "噬人雖負平時口，跑地能開一掬泉。", "不遇下車馮婦勇，都因脫屣性空禪。", "大慈塢內腥風起，善結叢林渇飲緣。"]'),
('5079b358-d9db-4144-a14a-f9b140c957b2','南屏山','董嗣杲','宋','宋诗','song-poetry','','[]','南有屏山掩翠霏，齊雲亭子漫尋基。',64,'全唐诗/poet.song.237000.json','["南有屏山掩翠霏，齊雲亭子漫尋基。", "雨淋米老琴臺字，火烈温公易卦碑。", "回首金魚誰撫檻，銷魂白骨自汚池。", "春風不管遊人老，愁落朝昏法鼓悲。"]'),
('2bb2bbdd-d85c-4ba1-a799-ea01425d0711','蘇公隄','董嗣杲','宋','宋诗','song-poetry','','[]','青紅一線界沙隄，日日香風逐馬蹄。',64,'全唐诗/poet.song.237000.json','["青紅一線界沙隄，日日香風逐馬蹄。", "三月桃花無浪起，六橋柳色有鶯啼。", "官亭飛盖春相接，酒舍收旗晚自迷。", "游子豈知坡老意，兩山長擁夕陽西。"]'),
('3635a612-c1f8-4de6-af98-a151f0efdca3','先賢祠','董嗣杲','宋','宋诗','song-poetry','','[]','列仙始自許箕公，上國尊賢典禮隆。',64,'全唐诗/poet.song.237000.json','["列仙始自許箕公，上國尊賢典禮隆。", "三十九人裁信史，百千萬禩紀清風。", "衣冠文物流傳盛，花柳亭臺曲折通。", "鏡水在先祠越隠，如今彼此可稱雄。"]'),
('15285165-6777-48ca-8212-3977f93a2646','西湖道院','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','名祠相接啓珠庭，巧對南屏萬疊青。',64,'全唐诗/poet.song.237000.json','["名祠相接啓珠庭，巧對南屏萬疊青。", "深院冷侵雲砌竹，虚舟閒載錦池萍。", "廊頭道士書符簡，門外遊人挈酒瓶。", "分坐夕陽斜背水，鼓簫於此最宜聽。"]'),
('d7a9320c-acd8-409e-974b-ebfce9687169','湖山堂','董嗣杲','宋','宋诗','song-poetry','','[]','彩檻雕闌倚地仙，南堂深架北堂先。',64,'全唐诗/poet.song.237000.json','["彩檻雕闌倚地仙，南堂深架北堂先。", "湖光十里饒春日，山色三隄合霽烟。", "簾幙香傳歌扇底，鶯花影落酒旗邊。", "紅塵不受斜陽壓，暗逐東風入畫船。"]'),
('70ca1173-ba32-4e4a-8475-9385782b1dab','三賢祠','董嗣杲','宋','宋诗','song-poetry','','[]','東坡政績踵香山，梅下韜光獨養閒。',64,'全唐诗/poet.song.237000.json','["東坡政績踵香山，梅下韜光獨養閒。", "一様清風無異代，三公遺像有生顔。", "竹亭畫鶴銜芝老，石鼎蟠蛛炷柏慳。", "摘取吟聨分扁隸，英遊時駕碧雲還。"]'),
('75b96c02-faa0-42ab-befe-9a68d037fb34','雪江講堂','董嗣杲','宋','宋诗','song-poetry','','[]','索居占得藕花風，幾字頭銜迥不同。',64,'全唐诗/poet.song.237000.json','["索居占得藕花風，幾字頭銜迥不同。", "烏帽染紗裁一幅，錦囊分卷集羣公。", "湖光長日侵比座，竹籜多時積鶴籠。", "繫柳吟驢何處去，想應乘雪釣江空。"]'),
('df718dfd-6815-4752-9e86-d072d105f103','崇真道院','董嗣杲','宋','宋诗','song-poetry','','[]','蹁躚鶴聚水雲中，雲水相逢色色空。',63,'全唐诗/poet.song.237000.json','["蹁躚鶴聚水雲中，雲水相逢色色空。", "講道無人知畏壘，集仙有閣想崆峒。", "柳隄風日齋鐘散，蒲座塵埃食鉢充。", "一老雙丫離蜀久，西窗掩定讀同。"]'),
('1909efff-fc79-4497-8455-20258af38fe8','小新隄','董嗣杲','宋','宋诗','song-poetry','','[]','誰築湖隄種柳條，行春路截九松腰。',64,'全唐诗/poet.song.237000.json','["誰築湖隄種柳條，行春路截九松腰。", "直看西日當三竺，平接南山第五橋。", "麯院岸通沙澗淺，桃溪寺接玉泉遥。", "遊人從此言旋便，不受回舟著相招。"]'),
('917488a7-6a9b-4229-a45c-b00a9cd00018','翠芳園','董嗣杲','宋','宋诗','song-poetry','','[]','翠挹南山樹石蒼，五花亭外萬花芳。',64,'全唐诗/poet.song.237000.json','["翠挹南山樹石蒼，五花亭外萬花芳。", "雲芝栱斗晴簷濕，金字屏風水榭涼。", "柳接蘇堤無空地，萍侵蘭枻有深坊。", "未幾移築仙宫邃，一本紅查委路傍。"]'),
('7636d196-e37e-48b0-8396-ee8a22a82049','甘園','董嗣杲','宋','宋诗','song-poetry','','[]','內官園邃傍齋宫，楊柳堤南翠幾重。',64,'全唐诗/poet.song.237000.json','["內官園邃傍齋宫，楊柳堤南翠幾重。", "四面堂虚凌上界，五層塔近壓中峯。", "徑連湖水行幽草，廊接風亭卧偃松。", "隣岸御舟空望幸，深坊長日鎖飛龍。"]'),
('4068d4f6-833e-4765-bae5-9c5153dc9ce4','雷峯','董嗣杲','宋','宋诗','song-poetry','','[]','五級浮屠透泬寥，黄皮園上梵坊遥。',64,'全唐诗/poet.song.237000.json','["五級浮屠透泬寥，黄皮園上梵坊遥。", "當時雷就家曾棄，前代皇妃迹已銷。", "鈴带水風傳古衕，燈分山月照長橋。", "根基自廣雲層減，擁腫難供畫筆描。"]'),
('1992e933-e1f1-4be9-99a7-b2cde4b5f7a7','勝景園','董嗣杲','宋','宋诗','song-poetry','','[]','名花嫋嫋草纎纎，臺榭隨幽逐勝添。',64,'全唐诗/poet.song.237000.json','["名花嫋嫋草纎纎，臺榭隨幽逐勝添。", "十様結亭環水樹，一碑述記卧風簷。", "梅闗橋落停𣡬鑰，射圃樓空失垜簾。", "向日相傳誰學吠，村莊畢竟出沽帘。"]'),
('9c1ef51e-3814-40a6-80a7-b2d837b2d5f6','長橋','董嗣杲','宋','宋诗','song-poetry','','[]','南港虚明架石梁，寺樓鐘鼓幾斜陽。',64,'全唐诗/poet.song.237000.json','["南港虚明架石梁，寺樓鐘鼓幾斜陽。", "相傳亭跨危基壯，誰見橋横古道長。", "澄水閘荒沙草碧，清波門近市塵黄。", "鳳凰山在闌干外，玉抺烟屏鷺一行。"]'),
('17f5a9d4-088d-4515-a049-07fceb70bd3c','劉妃墓','董嗣杲','宋','宋诗','song-poetry','','[]','佛廬增耀石人眠，莫謂思陵雨露偏。',64,'全唐诗/poet.song.237000.json','["佛廬增耀石人眠，莫謂思陵雨露偏。", "寵斷自空蝴蝶夢，魂歸猶咽鳳凰泉。", "碑砆蝕翠埋荒土，樓拱塗丹落廢磚。", "主祭有誰今若此，此時出色想無氊。"]'),
('c70d5fd0-7477-437b-bf4a-589e4b27cbbc','慈雲嶺','董嗣杲','宋','宋诗','song-poetry','','[]','疊疊流雲步步苔，九霄紫氣限蓬萊。',64,'全唐诗/poet.song.237000.json','["疊疊流雲步步苔，九霄紫氣限蓬萊。", "後唐刻石初開路，南宋郊天别築臺。", "慰眼江湖空歲月，傷心陵寢堕塵埃。", "桃花争趁春風老，又引遊人一度來。"]'),
('130a16f0-1b20-4fe9-8f02-7e10246b7e54','包家山','董嗣杲','宋','宋诗','song-poetry','','[]','綺霞蒸日透林梢，一簇南山尚姓包。',64,'全唐诗/poet.song.237000.json','["綺霞蒸日透林梢，一簇南山尚姓包。", "冷水峪邊苔色老，沖雲樓下樹陰髙。", "園隣古道傳耕耤，臺倚青城想拜郊。", "欲趁桃花尋隠去，闗門無鑰不須敲。"]'),
('b835c6f2-8b86-4392-bfd7-515ce54a3a23','登雲臺','董嗣杲','宋','宋诗','song-poetry','','[]','吴越山川幾落暉，登臨轉步入雲扉。',64,'全唐诗/poet.song.237000.json','["吴越山川幾落暉，登臨轉步入雲扉。", "寺名曾侈天真錫，碑字空傳武肅揮。", "靈洞土埋攅棘掩，古臺石落借松圍。", "龍旗鸞輅曾遮擁，有祀圎丘慶六飛。"]'),
('b5537dcb-6dfc-4975-aea0-27570a1de97c','五丈觀音','董嗣杲','宋','宋诗','song-poetry','','[]','海國風濤擁萬尋，此軀何翅直千金。',64,'全唐诗/poet.song.237000.json','["海國風濤擁萬尋，此軀何翅直千金。", "涉波直現昻藏相，結屋還堅報施心。", "圗得諸方傳轉智，幸存一半有觀音。", "陰廊誰立苔碑在，只載三朝法駕臨。"]'),
('32ab3f1a-cb10-40b2-b860-2171a040d183','表忠觀','董嗣杲','宋','宋诗','song-poetry','','[]','錢子欣然著羽衣，何須學賦鑑湖詩。',64,'全唐诗/poet.song.237000.json','["錢子欣然著羽衣，何須學賦鑑湖詩。", "帝俞清獻垂情疏，人讀文忠叙事碑。", "五廟衮圭榮祖節，千年香火托孫枝。", "雲林閣上西風起，吹落龍山宰樹悲。"]'),
('be6fd6e1-3313-4f65-b688-ed3ecf18d2a8','聚景園','董嗣杲','宋','宋诗','song-poetry','','[]','鑾鈴遺響輦遺踪，萬景曾經聚此中。',64,'全唐诗/poet.song.237000.json','["鑾鈴遺響輦遺踪，萬景曾經聚此中。", "寺宇有名基址散，君王無逸讌遊空。", "橋昏柳浪龍舟雨，亭冷花光雉扇風。", "臺沼已無春又老，萬年枝上夕陽紅。"]'),
('bdfa65af-1680-443e-b505-2f5f461e453f','崔府君廟','董嗣杲','宋','宋诗','song-poetry','','[]','靈休逺被衛行都，宿有元勛夢又符。',64,'全唐诗/poet.song.237000.json','["靈休逺被衛行都，宿有元勛夢又符。", "引馬擁羊昭景貺，立碑建廟述嘉謨。", "九陵荆棘年空往，十里笙歌景不殊。", "莫倚西齋闌檻去，斜陽無語滿錢湖。"]'),
('89a5b5dd-28e8-4a2c-925b-b1a99919f644','依光堂','董嗣杲','宋','宋诗','song-poetry','','[]','塵凝黼座憶垂衣，今古湖波錦四圍。',64,'全唐诗/poet.song.237000.json','["塵凝黼座憶垂衣，今古湖波錦四圍。", "靈毓紫芝三秀逺，光開緑玉片金輝。", "松窗自掩空蓮社，石榻相期卧柳枝。", "半捲珠簾看落景，笙歌長送畫船歸。"]'),
('4c707471-c9a4-4c3a-9a77-59e291921f77','松花','董嗣杲','宋','宋诗','song-poetry','','[]','肪花簌簌綴茸茸，誰覿長生欲此逢。',64,'全唐诗/poet.song.237000.json','["肪花簌簌綴茸茸，誰覿長生欲此逢。", "黄雪凝釵資霧滃，翠虬吐汞借雪封。", "釀漿可問通仙醉，捻餅須知漬蜜供。", "飄砌忍看僧掃去，異香躡取茯苓蹤。"]'),
('fbfa817e-2135-4571-a24e-92875aa67ea6','桂花','董嗣杲','宋','宋诗','song-poetry','','[]','月地雲叢花意妍，清芬曾向竇家傳。',64,'全唐诗/poet.song.237000.json','["月地雲叢花意妍，清芬曾向竇家傳。", "登山不愧自招隱，斫樹莫名誰學仙。", "香換西風埋麝腹，種分南海藴龍涎。", "玉盃甘露何從得，欲折蟾枝是幾年。"]'),
('9e60fbe4-323e-4b00-bf71-196a1c5674ea','桐花','董嗣杲','宋','宋诗','song-poetry','','[]','清明疎雨洗芳天，爛積霞英漲曉暄。',64,'全唐诗/poet.song.237000.json','["清明疎雨洗芳天，爛積霞英漲曉暄。", "香藹路陰埋古井，枝纏瓦影接頹垣。", "琴村鼓舜無遺調，圭葉封唐豈戲言。", "此本自云花自委，叢生樹子墮秋原。"]'),
('cf962811-3f93-4ac6-980e-923e8090a275','槐花','董嗣杲','宋','宋诗','song-poetry','','[]','此樹開花簌簌黄，秋蟬鳴破雨餘涼。',64,'全唐诗/poet.song.237000.json','["此樹開花簌簌黄，秋蟬鳴破雨餘涼。", "髪回七袠仙人黑，心落三年舉子忙。", "肯信植庭能根葉，誰知列樹自成行。", "雲屯暗掩宮陰老，蜜糝龍池鳳沼香。"]'),
('358e125c-04da-49bd-a876-b0feb0b9a01b','柳花','董嗣杲','宋','宋诗','song-poetry','','[]','翠絲窣地裹晴綿，三月春空灞巖煙。',64,'全唐诗/poet.song.237000.json','["翠絲窣地裹晴綿，三月春空灞巖煙。", "四下葉蕃如吐言，一隨風起欲漫天。", "池心直作浮萍化，墄胔多將缺蘚填。", "恨落夕陽亭樹晚，趁蜂趁蝶撲鞦韆。"]'),
('b6e88f00-4bab-4f4b-bd05-548bce7a9aa4','椶櫚花','董嗣杲','宋','宋诗','song-poetry','','[]','碧玉輪張萬葉陰，一皮一節筍抽金。',64,'全唐诗/poet.song.237000.json','["碧玉輪張萬葉陰，一皮一節筍抽金。", "胚成黄穗如魚子，朵作珠花出樹心。", "蜜漬可馳千里遠，種收不待早春深。", "蜀人事佛營精饌，遺得坡仙食木吟。"]'),
('ad63dad5-edf8-4844-bc73-1f46f4f82d3f','萬年枝花','董嗣杲','宋','宋诗','song-poetry','','[]','此種何奇等壽椿，吹香時借好風頻。',64,'全唐诗/poet.song.237000.json','["此種何奇等壽椿，吹香時借好風頻。", "細花當暑飛黄玉，密葉屯陰侍紫宸。", "深樾暗埋巢鵲乳，纖蕤亂綴網蛛塵。", "歲賽重結青青子，培擁皇基不老春。"]'),
('39d81d43-e0e7-48ed-b47f-89b6c8840e25','棣棠花','董嗣杲','宋','宋诗','song-poetry','','[]','綠羅搖曳鬰梅英，裊裊柔條韡韡金。',64,'全唐诗/poet.song.237000.json','["綠羅搖曳鬰梅英，裊裊柔條韡韡金。", "榮萼有光傾日近，仙姿無語繫春深。", "盛傳覆第承華喻，別紀遺恩芾木陰。", "晚圃甚花堪並駕，周詩明寫友于心。"]'),
('4564befc-ee18-4695-a6bf-d8068c363bc8','大笑花','董嗣杲','宋','宋诗','song-poetry','','[]','種出海南誰爲誇，嫣然無語送韶華。',64,'全唐诗/poet.song.237000.json','["種出海南誰爲誇，嫣然無語送韶華。", "何人何事入彼粲，傾國傾城非比花。", "羞靨倚風遺素臉，爛香浥露逼青瓜。", "開時氣味起憎妬，牢掩籬門蠶婦家。"]'),
('080b0724-1dda-4dff-ac98-eb7b17bad72c','薔薇花','董嗣杲','宋','宋诗','song-poetry','','[]','接夏連春秀可誇，東山雲月滿誰家。',64,'全唐诗/poet.song.237000.json','["接夏連春秀可誇，東山雲月滿誰家。", "浪埋纖刺翻晴錦，綃綴柔條熨暮霞。", "海外有瓶還貯水，亭前無洞可藏花。", "多年不拆黄封酒，莫向樽前說夢華。"]'),
('81614c3d-2816-4213-a653-a1068f78377a','木筆花','董嗣杲','宋','宋诗','song-poetry','','[]','始開已落謾芳菲，暗寫東皇幾夕暉。',64,'全唐诗/poet.song.237000.json','["始開已落謾芳菲，暗寫東皇幾夕暉。", "傍樹誰矜火燄異，對花自感壯年非。", "紅脂含蒂長枝勁，紫粉粘蕤老葉肥。", "名占辛夷播方冊，詩豪惟許少陵揮。"]'),
('bbe22382-cae1-48b7-9f3a-8bbf91a98a50','芭蕉花','董嗣杲','宋','宋诗','song-poetry','','[]','綠扇搖秋吐秀黄，宿根清傲雪和霜。',64,'全唐诗/poet.song.237000.json','["綠扇搖秋吐秀黄，宿根清傲雪和霜。", "花能成實連莖脆，子可爲房取蜜藏。", "爭愛廣陰能障暑，誰知甘味亦充糧。", "何人吟羨青青葉，如此山殽不得嘗。"]'),
('37fea63f-8e6b-49ff-be06-62c6179bb832','葵花','董嗣杲','宋','宋诗','song-poetry','','[]','纏粉花心吐膩英，根柔葉縐簇娉娗。',65,'全唐诗/poet.song.237000.json','["纏粉花心吐膩英，根柔葉縐簇娉娗。", "錦窼繡窟攢風日，絳節華旌列運氣庭。", "五色種遺吳地秀，獨醒人耀楚江靈。", "年年重午家家有，桃柳菖蒲共一瓶。"]'),
('3368dab0-2b45-490c-85b5-94eab256c143','酴醾花','董嗣杲','宋','宋诗','song-poetry','','[]','韻友相送春已遒，翦瓊肌骨更嬌柔。',65,'全唐诗/poet.song.237000.json','["韻友相送春已遒，翦瓊肌骨更嬌柔。", "畫屏繚繞無風展，酒甕豐腴有味留。", "雲洞懸枝畢疑雪蛹，雨牆引蔓走煙虬。", "年年壓倒看承架，又費山翁斫竹修。"]'),
('49613606-4f9c-4c58-bfb7-d7737465eae2','芍藥花','董嗣杲','宋','宋诗','song-poetry','','[]','花中近侍盛江都，艷朵低攢意態殊。',64,'全唐诗/poet.song.237000.json','["花中近侍盛江都，艷朵低攢意態殊。", "白傅詞工誰續得，劉郎譜在可修無。", "翻階媚雨嬌紅軟，壓砌迎風醉粉腴。", "二十四橋春事老，而今難覓玉盤盂。"]'),
('b6f44a09-ac6b-4f53-bee7-fe18702cb2c9','蘭花','董嗣杲','宋','宋诗','song-poetry','','[]','芳友幽棲九畹陰，花柔葉勁怯深尋。',64,'全唐诗/poet.song.237000.json','["芳友幽棲九畹陰，花柔葉勁怯深尋。", "謝家毓取階庭秀，屈子紉歸澤國吟。", "百卉混林尊異種，一清傳世絕同心。", "身悝風露甘修潔，誰託斯馨欲援琴。"]'),
('3a2ee311-1d5b-4f62-b27e-72112cb9d954','木蘭花','董嗣杲','宋','宋诗','song-poetry','','[]','弄粉調紅抹野姿，寂寥誰抱遠書思。',64,'全唐诗/poet.song.237000.json','["弄粉調紅抹野姿，寂寥誰抱遠書思。", "粧凝彩日含朱粉，艷染光霞拆紫絲。", "守戍自知身是女，發祥誰見樹生芝。", "晚橈歌斷何人望，遺得天隨醉後詩。"]'),
('94e66be2-413b-43f0-bdb1-f94229c1e719','牡丹花','董嗣杲','宋','宋诗','song-poetry','','[]','大花香透已春過，莫妙春工點染多。',64,'全唐诗/poet.song.237000.json','["大花香透已春過，莫妙春工點染多。", "蜀地錦機裁色樣，洛陽土脈藴中和。", "牙牌有字分奇品，金屋無人續艷歌。", "明月天澤橋上晚，一聲不奈杜鵑何。"]'),
('560160de-e037-4e23-bb0f-32d0ae778d89','楝花','董嗣杲','宋','宋诗','song-poetry','','[]','吹將二十四番愁，錦樣羣芳逐急流。',64,'全唐诗/poet.song.237000.json','["吹將二十四番愁，錦樣羣芳逐急流。", "風信到花春自往，霜華著子晚誰收。", "樹攢密萼屯陰重，瓣落高枝綴蘚稠。", "霞外曾傳香醉詠，鶯鶯未囀舌應柔。"]'),
('5b405c9f-040d-4273-a238-9ef76a209263','瓊花','董嗣杲','宋','宋诗','song-poetry','','[]','后土花呈絕世祥，瑤姿琪艷著惟揚。',64,'全唐诗/poet.song.237000.json','["后土花呈絕世祥，瑤姿琪艷著惟揚。", "一株獨擅無雙譽，六月重開有異香。", "描作畫圖尊地產，釀成花露敵天漿。", "朱闌幾曲圍叢樹，珠絡懸虛翠鳳翔。"]'),
('633cf135-5145-4822-98db-4ef6077003f1','芙蓉花','董嗣杲','宋','宋诗','song-poetry','','[]','如館如城幾艷叢，拒霜不覺老西風。',64,'全唐诗/poet.song.237000.json','["如館如城幾艷叢，拒霜不覺老西風。", "曼卿人見騎驢去，丁度仙遊按轡空。", "惆悵二公皆死讖，淺深十里尚秋紅。", "且圖席地看花醉，肯羨豪家繡褥工。"]'),
('b567eaf2-2563-4536-8124-36e3914e6218','蓼花','董嗣杲','宋','宋诗','song-poetry','','[]','瘦葉浮根傍柳磯，水天秋色夕陽時。',64,'全唐诗/poet.song.237000.json','["瘦葉浮根傍柳磯，水天秋色夕陽時。", "晶晶紅染纍垂糝，嫋嫋涼搖軟弱枝。", "挼汁自能爲酒母，托名誰製作風宜。", "花開只熨溜翁眼，可奈漁翁醉不知。"]'),
('ba7bd56b-f66f-4abe-a784-af58eb1e6f4b','瑞香花','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','春沁幽花透骨清，矮窼殊邁百芳馨。',64,'全唐诗/poet.song.237000.json','["春沁幽花透骨清，矮窼殊邁百芳馨。", "紫英四出醉嬌粉，綠萼千攢簇巧丁。", "自覆熏籠須閉戶，誰栽錦傘都當庭。", "晝眠不用熏沈水，夢落廬山九疊屏。"]'),
('4c64ab3a-aa84-4278-bfc2-96b5b83256eb','茉莉花','董嗣杲','宋','宋诗','song-poetry','','[]','雪綴柔枝冷未融，暗銷塵境暑威隆。',64,'全唐诗/poet.song.237000.json','["雪綴柔枝冷未融，暗銷塵境暑威隆。", "根從海國分靈種，花逐仙娥下蘂宮。", "珠絡香懸風緊處，玉壺人在月明中。", "直須第四番開過，都灑秋愁落翠叢。"]'),
('709ff54b-6e87-43c1-b7ad-daba881bde0e','罌粟花','董嗣杲','宋','宋诗','song-poetry','','[]','紅白花開委暮塵，野糧能療野居貧。',64,'全唐诗/poet.song.237000.json','["紅白花開委暮塵，野糧能療野居貧。", "長腰可抵豐年米，蒼玉難資食肉人。", "石鉢柳槌研乳細，春苗秋實薦香新。", "馬前見此羈懷惡，強飯應鍾萬里身。"]'),
('2d993cd5-2884-4814-81cc-aaa052f3626c','梔子花','董嗣杲','宋','宋诗','song-poetry','','[]','玉瓣涼叢擁翠煙，南薰池閣燦雲仙。',64,'全唐诗/poet.song.237000.json','["玉瓣涼叢擁翠煙，南薰池閣燦雲仙。", "芳林園裏誰曾賞，薝蔔坊中自可禪。", "明艷倚嬌攢六出，浄香乘烈裊孤妍。", "風霜成實秋原晚，付與華燈作樣傳。"]'),
('2b0cdf55-b433-4f39-b5a3-99be2ef43870','槿花','董嗣杲','宋','宋诗','song-poetry','','[]','髣髴戎葵勁且柔，托名日及嘆生浮。',64,'全唐诗/poet.song.237000.json','["髣髴戎葵勁且柔，托名日及嘆生浮。", "苦憐相態無多艷，空綴郊原度一秋。", "紅澡暮零籬？上，翠深涼過屋山頭。", "風英掩映枯茅把，勾引行人覓酒流。"]'),
('d1fc059a-a068-4e0a-bf18-eedaf9e10e21','菊花','董嗣杲','宋','宋诗','song-poetry','','[]','籬東佳友手曾刪，莫把南山提眼看。',64,'全唐诗/poet.song.237000.json','["籬東佳友手曾刪，莫把南山提眼看。", "荒徑可供元亮采，落英惟許屈平餐。", "艷鍾金氣中分晚，香裊清霜獨傲寒。", "誰插滿頭開笑口，翠微亭北倚闌干。"]'),
('9e6f1ab6-e575-42b2-ab48-925280cf6a09','蕙花','董嗣杲','宋','宋诗','song-poetry','','[]','翠葉層敷楚茝苗，誰將綺石養清標。',64,'全唐诗/poet.song.237000.json','["翠葉層敷楚茝苗，誰將綺石養清標。", "幽姿晴待光風轉，熏草寒禁艷雪消。", "一榦數蕤香不足，重栽百畝魄難招。", "零陵雖是名堪托，無事因花憶晉朝。"]'),
('840e3874-49c4-432f-ae29-29571f2a25b6','徘徊花','董嗣杲','宋','宋诗','song-poetry','','[]','疊萼黄心紫瓣柔，穠薰粉膩入香篝。',64,'全唐诗/poet.song.237000.json','["疊萼黄心紫瓣柔，穠薰粉膩入香篝。", "應知上苑清和轉，聊爲東皇款曲□。", "拂拂靚香遺片異，鱗鱗刺葉矮叢抽。", "夜長還有人空度，花裏相延月一鈎。"]'),
('79e42c2c-39a0-4720-a803-65fd9c1d90b6','密友花','董嗣杲','宋','宋诗','song-poetry','','[]','此花誰謂結朋慳，點染繁枝怯手刪。',64,'全唐诗/poet.song.237000.json','["此花誰謂結朋慳，點染繁枝怯手刪。", "叢矮暗埋晴徑秀，刺多橫接露籬間。", "野香雨浥遺春態，茜艷風梢取醉顔。", "情似酒濃甘倚附，不教疎遠晚芳閒。"]'),
('b379281c-af7e-4214-900d-5dc82f2ab648','桃花','董嗣杲','宋','宋诗','song-poetry','','[]','占取韶光二月時，妬紅深淺漫成蹊。',64,'全唐诗/poet.song.237000.json','["占取韶光二月時，妬紅深淺漫成蹊。", "暗銷春恨含煙薄，靚落晨粧受雨低。", "憶樹自傷前度種，見花誰想去年題。", "武陵源上風光異，引得漁翁過此溪。"]'),
('e279fd1f-a673-4c26-bcfb-a8b4528aa404','杏花','董嗣杲','宋','宋诗','song-poetry','','[]','太極林中碎錦堆，花仙曾識探花回。',64,'全唐诗/poet.song.237000.json','["太極林中碎錦堆，花仙曾識探花回。", "自知壇上弦歌樂，誰想軒前羯鼓催。", "煙撚濕鬚攢綺繡，露零醉臉削瓊瑰。", "野行覓酒無童指，擬拾遺仁作藥媒。"]'),
('96907682-47c8-4a0a-b129-25ca3dd4f417','李花二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','宜繁宜遠九標新，花露能仙雨點頻。',64,'全唐诗/poet.song.237000.json','["宜繁宜遠九標新，花露能仙雨點頻。", "傳姓老聃因指樹，過門方朔驗呼人。", "葦綃縞月明偷夜，練帨當風靜撚春。", "實薦冰盆傳種去，莫教鑽破核中仁。"]'),
('fb0fb7ca-1097-472e-b0b6-9372edc662e2','李花二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','嘉李繁相倚，園林淡泊春。',48,'全唐诗/poet.song.237000.json','["嘉李繁相倚，園林淡泊春。", "齊紈翦衣薄，吳紵下機新。", "色與晴光亂，香和露氣勻。", "望中皆玉樹，環堵不爲貧。"]'),
('322d6192-3209-4b25-b19c-484798afae42','郁李子花','董嗣杲','宋','宋诗','song-poetry','','[]','勁條馥卉冒仙荄，殿取東皇艷杏開。',64,'全唐诗/poet.song.237000.json','["勁條馥卉冒仙荄，殿取東皇艷杏開。", "茜瓣吐鬚凝露態，白英粘萼暈春腮。", "自知此樹無人指，誰問他蹊有種栽。", "插取瓦瓶聊補空，不期粗俗誤蜂來。"]'),
('01a3f5ce-406e-4672-b010-bd552dce9949','梅花','董嗣杲','宋','宋诗','song-poetry','','[]','水光月色最相宜，獨結空林歲晚期。',64,'全唐诗/poet.song.237000.json','["水光月色最相宜，獨結空林歲晚期。", "萬國春回先有信，孤山人往絕無詩。", "吟風海鶴眠清影，敲雪村童認老枝。", "舉世祇知調鼎貴，玄機誰向靜中規。"]'),
('11be3e59-4c42-45ae-8454-15441caa5468','梨花','董嗣杲','宋','宋诗','song-poetry','','[]','辦取看花沽酒銭，素肌嬌怯冷籠煙。',64,'全唐诗/poet.song.237000.json','["辦取看花沽酒銭，素肌嬌怯冷籠煙。", "愁遺弟子離園日，淚盡宮妃過驛年。", "縞夜露零啼恨濕，扶春雪壓洗粧妍。", "鞦韆院落清明近，絕艷能期月黑天。"]'),
('ddaa0785-dd61-479b-9764-1e64b16b2ba6','荷花','董嗣杲','宋','宋诗','song-poetry','','[]','天機雪錦織鮫綃，艷朵亭亭倚畫橋。',64,'全唐诗/poet.song.237000.json','["天機雪錦織鮫綃，艷朵亭亭倚畫橋。", "無垢自全君子潔，有姿誰想六郎嬌。", "翠房分菂蓮鬚褪，玉藕抽絲暑葉搖。", "花裏不妨呼凈友，采香須棹月明橈。"]'),
('16e6850d-2ebc-46e1-b0ef-b927bcdd9aac','菱花','董嗣杲','宋','宋诗','song-poetry','','[]','珠團綠錦趁晴攤，涼蔭龜魚六月寒。',64,'全唐诗/poet.song.237000.json','["珠團綠錦趁晴攤，涼蔭龜魚六月寒。", "背日開花非芡比，荒年收實當蔬餐。", "一方錦裏消清暑，五瓣闌干俯碧瀾。", "漠漠水天誰唱晚，苕溪翠展夕陽殘。"]'),
('96bc6000-a7f3-45b9-9379-b9f5fda850c1','林檎花','董嗣杲','宋','宋诗','song-poetry','','[]','樹枝高墜展霞綃，粧點清明景物饒。',64,'全唐诗/poet.song.237000.json','["樹枝高墜展霞綃，粧點清明景物饒。", "帖上幸聯青李字，花頭不似海棠嬌。", "英英褪雨新紅淡，瓣瓣零風蝶粉綃。", "光景無多成實易，冰奩催薦泛涼橈。"]'),
('bea4ff5d-99df-4ae2-b666-8930faed2c45','棗花','董嗣杲','宋','宋诗','song-poetry','','[]','香落衣巾靡靡中，花垂碧澗不流冬。',64,'全唐诗/poet.song.237000.json','["香落衣巾靡靡中，花垂碧澗不流冬。", "易開易落催成子，誰采誰收怕見紅。", "種有萬林綿北地，詩傳八月剝西風。", "千株可等侯千戶，安邑曾收結實功。"]'),
('640241d0-e334-430f-9e65-b3b65a99ad68','棖花','董嗣杲','宋','宋诗','song-poetry','','[]','穠芳比似橘花肥，當日曾從細雨移。',64,'全唐诗/poet.song.237000.json','["穠芳比似橘花肥，當日曾從細雨移。", "老有縐顔羞晚出，清無柔性結春知。", "雪香四月蜂攢處，風味重陽蟹健時。", "院落彩粧人最巧，攙先茉莉簇涼枝。"]'),
('64ef622d-fd4b-4528-aece-7bc90a90533e','橘花','董嗣杲','宋','宋诗','song-poetry','','[]','對花懷母望雲心，不見圍棋隱者尋。',64,'全唐诗/poet.song.237000.json','["對花懷母望雲心，不見圍棋隱者尋。", "晚徑風清香更醉，小亭月滿艷能侵。", "千林翠幄千英雪，一點瓊苞一顆金。", "莫問封侯惟問酒，泛盃摘蘂寄情深。"]'),
('0336bc0b-198a-4e2e-bc66-5762af96b613','枇杷花','董嗣杲','宋','宋诗','song-poetry','','[]','種接他枝宿土乾，花開抵得北風寒。',64,'全唐诗/poet.song.237000.json','["種接他枝宿土乾，花開抵得北風寒。", "蛹鬚負雪疑蜂蟄，毛葉粘霜若蝟攢。", "蕤破極冬懸蠟蒂，果收初夏摘金丸。", "凍香便覺飴如蜜，樹掩盧村月色寬。"]'),
('2a976333-063c-4d23-98f7-d428ca190599','薺花','董嗣杲','宋','宋诗','song-poetry','','[]','挑根掃葉古牆陰，雨後青腴有客尋。',64,'全唐诗/poet.song.237000.json','["挑根掃葉古牆陰，雨後青腴有客尋。", "又見開花如雪處，不知遍野已春深。", "山殽難入膏粱味，冰室偏鍾采擷心。", "荼苦回甘誰識取，周詩歷歷播微吟。"]'),
('30861008-d630-4fc9-b0e4-d67c7c281508','木香花','董嗣杲','宋','宋诗','song-poetry','','[]','鬬雪輕微吐粉蕤，同開結約是酴醾。',64,'全唐诗/poet.song.237000.json','["鬬雪輕微吐粉蕤，同開結約是酴醾。", "玉英遞韻埋深葉，檀蘂分姿裊別枝。", "無力可延春色住，有方曾著藥名遺。", "花空風轉薰絃院，紅柱棚欹𧀥亂垂。"]'),
('8e3c624d-f711-4d28-8fdb-438fd879b73a','百合花','董嗣杲','宋','宋诗','song-poetry','','[]','有聚無分比蒜強，春苗數尺紫莖長。',63,'全唐诗/poet.song.237000.json','["有聚無分比蒜強，春苗數尺紫莖長。", "青蒼暗接多重葉，紅白爭開五月涼。", "罔使蒸？食氣，祇堪當肉潤吟腸。", "山廚櫻筍同時薦，不似花心瓣瓣香。"]'),
('4c53b83f-6218-4632-82db-0ee309f7f982','懸空草花','董嗣杲','宋','宋诗','song-poetry','','[]','小繩掛起小壺擎，欲透青冥夢未成。',64,'全唐诗/poet.song.237000.json','["小繩掛起小壺擎，欲透青冥夢未成。", "百卉弸中涼色進，丹絲垂下暑塵清。", "纖蕤承雨無多艷，拳石圍泉不滿漒。", "生意可撩書眼凈，分明偷命寄簷楹。"]'),
('0b621e36-10e1-4c11-9050-ff0ef4e3524f','茶花','董嗣杲','宋','宋诗','song-poetry','','[]','花埋葉底寓春先，便想烹雲煮活泉。',64,'全唐诗/poet.song.237000.json','["花埋葉底寓春先，便想烹雲煮活泉。", "玉臉含羞勻晚艷，翠裾高曳掩秋妍。", "靈隨雷雨爭抽瑞，尖吐槍旗趲摘鮮。", "带雪莫知開又落，採鬚誰厭老蜂顛。"]'),
('3f7e18cd-0236-4043-a6a8-40d00ad0782a','菖蒲花','董嗣杲','宋','宋诗','song-poetry','','[]','開時可食勝餐松，應在神人守護中。',64,'全唐诗/poet.song.237000.json','["開時可食勝餐松，應在神人守護中。", "九節自知遺種異，一花誰可鬬香同。", "碧叢露養仙苗細，靈卉泉抽玉髄空。", "還有癡愚求見面，欲期顔貌亟還童。"]'),
('c0ad71e1-de3b-4c06-a3fa-6c0c4cbcaad4','萱草花','董嗣杲','宋','宋诗','song-poetry','','[]','嬌含丹粉映池臺，憂豈能忘俗謾猜。',64,'全唐诗/poet.song.237000.json','["嬌含丹粉映池臺，憂豈能忘俗謾猜。", "曹植頌傳天上去，嵇康種滿舍前來。", "鹿葱誰驗宜男讖，鳳首猶尋別種栽。", "浩有苦懷偏憶母，從今不把北堂開。"]'),
('378f53b2-8454-4c04-acbf-111cee2190a7','藤花','董嗣杲','宋','宋诗','song-poetry','','[]','蒙茸紫結秀蕤明，遠訝霞鋪彩鳳輕。',65,'全唐诗/poet.song.237000.json','["蒙茸紫結秀蕤明，遠訝霞鋪彩鳳輕。", "有碎影照溪羞晚悴，爛香蔓壑藉春榮。", "蔓如諛佞依權勢，色比空華易死生。", "花落水流儴沈約，至今故宅號餘英。"]'),
('c3945d8b-5a87-49dc-8acc-733ea410de8d','蘆花','董嗣杲','宋','宋诗','song-poetry','','[]','冗花焦葉裊風漪，亂展江鄉白渺瀰。',64,'全唐诗/poet.song.237000.json','["冗花焦葉裊風漪，亂展江鄉白渺瀰。", "兩岸水枯鷗宿處，一天雪衮鴈銜時。", "羌兒削管吹邊遠，淮俗編簾障屋危。", "豈特絮氈堪禦凍，津頭拾取作薪炊。"]'),
('3436c28f-f86d-41fa-b68e-cc12e095aae3','蘋花','董嗣杲','宋','宋诗','song-poetry','','[]','花明五出繡汀州，自在沉沉自在浮。',64,'全唐诗/poet.song.237000.json','["花明五出繡汀州，自在沉沉自在浮。", "古有楚童謠可信，今無越女采爲羞。", "江清得實誰能剖，風起虛根不復留。", "晚向水鄉回野棹，一規西日落湖州。"]'),
('42468766-5433-41df-ae9f-f729a5c31a0f','茨菰花','董嗣杲','宋','宋诗','song-poetry','','[]','剪刀葉兩枝芳，柔弱難勝带露粧。',63,'全唐诗/poet.song.237000.json','["剪刀葉兩枝芳，柔弱難勝带露粧。", "翠管嫩粘瓊糝重，野泉情心玉蕤涼。", "舂成臼粉資秋實，種入盆池想水鄉。", "小小滄洲歸眼底，幽研自覺成炎光。"]'),
('0d60005c-2ad4-4f61-84e2-d98d34e38472','越上','董嗣杲','宋','宋诗','song-poetry','','[]','海色連雲氣，登臨晚不同。',48,'全唐诗/poet.song.237000.json','["海色連雲氣，登臨晚不同。", "越山齊北斗，秦樹起西風。", "燈火官橋暗，笙歌店橋空。", "小樓無夢裏，誰此種梧桐。"]'),
('a8d17c0c-6840-4dc8-800f-a9dcd9180212','稻花','董嗣杲','宋','宋诗','song-poetry','','[]','四海張頤望歲豐，此花不與萬花同。',64,'全唐诗/poet.song.237000.json','["四海張頤望歲豐，此花不與萬花同。", "香分天地生成裏，氣應陰陽子午中。", "頃頃紫芒搖七月，穰穰玉糝杵西風。", "雨晹時若關開落，歌壤誰攄畎畝忠。"]'),
('3f6ad390-b1dc-42e6-a150-ff4980054597','豆花','董嗣杲','宋','宋诗','song-poetry','','[]','西風籬落草蟲鳴，喚起書生啜菽心。',64,'全唐诗/poet.song.237000.json','["西風籬落草蟲鳴，喚起書生啜菽心。", "雨瓣霏霏成晚莢，霞英藹藹爍秋陰。", "三年得謫非無樂，七步燃茸謾有吟。", "請看種分紅白色，南山山下此苗深。"]'),
('3b755a5c-3132-4e9d-ab1f-9f3e47106383','麥花','董嗣杲','宋','宋诗','song-poetry','','[]','輕花細細復猗猗，何止青熒秀兩枝。',64,'全唐诗/poet.song.237000.json','["輕花細細復猗猗，何止青熒秀兩枝。", "萬頃雪光抽夏日，一天翠浪弄秋時。", "暖風覆野看搖燕，晨氣籠晴想韻鸝。", "有實可祈催食麨，晝長村疃不攢眉。"]'),
('9516b5a5-e91a-4847-b11a-444c02327318','凌霄花','董嗣杲','宋','宋诗','song-poetry','','[]','根苗着土幹柔纖，依附青松度歲年。',64,'全唐诗/poet.song.237000.json','["根苗着土幹柔纖，依附青松度歲年。", "彤蘂有時承雨露，蒼藤無賴拂雲煙。", "艷欹偷醉斜陽裏，體弱愁纏立石顛。", "翠颭紅英高百尺，藏春塢上憶坡仙。"]'),
('32333030-d9aa-440e-bb9e-d3c55bb2a77d','月丹花','董嗣杲','宋','宋诗','song-poetry','','[]','朱砂煉椀質輕盈，知是蟾宮幾杵成。',64,'全唐诗/poet.song.237000.json','["朱砂煉椀質輕盈，知是蟾宮幾杵成。", "槁蒂秀鍾天種艷，碾光輝映御袍榮。", "葉沿綠刺星星勁，心結黄芽粟粟明。", "皓魄正圓花正麗，相看無語說長生。"]'),
('dd2a3430-c2e1-469b-ac32-be3ffc03ae5d','月季花','董嗣杲','宋','宋诗','song-poetry','','[]','謝了還開肯悟空，一年三十六旬中。',64,'全唐诗/poet.song.237000.json','["謝了還開肯悟空，一年三十六旬中。", "相看誰有長春艷，莫道花無百日紅。", "酡風倚嬌承舞雪，瘦枝扶力借柔風。", "四時常吐芳姿媚，人老那能與此同。"]'),
('010eaa71-c0fb-476d-b35c-fa1623295445','南天竺花','董嗣杲','宋','宋诗','song-poetry','','[]','粉紅朵子不勝簪，何日移根鷲嶺深。',64,'全唐诗/poet.song.237000.json','["粉紅朵子不勝簪，何日移根鷲嶺深。", "碎顆綠攢知暑過，欒枝紅透得霜侵。", "涼分細葉猶張蓋，秀結枯條可架禽。", "憶着花開花謝處，假山亭畔石池陰。"]'),
('07cb3005-b820-4e04-96e3-996d1e681ae5','石竹花','董嗣杲','宋','宋诗','song-poetry','','[]','矮叢平翦海霞鮮，亂撒東風紫錦錢。',64,'全唐诗/poet.song.237000.json','["矮叢平翦海霞鮮，亂撒東風紫錦錢。", "露瀋翠抽春節嫩，煙枰繡蹙絳綃圓。", "土階曄曄搖芳澤，山舍英英吐秀妍。", "秋色易花誰得見，何時容得麝香眠。"]'),
('68c758b9-c699-4260-8ce5-3f187c9f2aa7','山丹花','董嗣杲','宋','宋诗','song-poetry','','[]','知是何峯秀所鍾，曾因手種得仙翁。',64,'全唐诗/poet.song.237000.json','["知是何峯秀所鍾，曾因手種得仙翁。", "暑鬚怯裊粘金穗，涼瓣嗔封迸柿紅。", "撲賣有聲傳寂晝，幽妍無力借薰風。", "窰瓶插滿清香烈，欹枕探吟鄙鹿葱。"]'),
('c3363cf3-f6d8-4853-9fd9-dfc6adb16f26','水葒花','董嗣杲','宋','宋诗','song-poetry','','[]','問花憶別向秋江，清占花叢白鳥雙。',64,'全唐诗/poet.song.237000.json','["問花憶別向秋江，清占花叢白鳥雙。", "落日裊愁歸釣岸，薰風吹艷入船窗。", "情迷洲渚根無蒂，名寄閭閻曲有腔。", "寒露拉摧浮脆盡，斷磯絕岸出枯樁。"]'),
('f0ead0d8-0774-4084-a8ea-75275f52e580','散水花','董嗣杲','宋','宋诗','song-poetry','','[]','的皪繁英貼翠鞭，流波拂影自牽連。',64,'全唐诗/poet.song.237000.json','["的皪繁英貼翠鞭，流波拂影自牽連。", "柔條裊畫粘瓊靨，小葉抽春壘玉鈿。", "冷艷遠疑冰剪處，穠華低燦月明天。", "莫欺露卉雲叢亂，暗引迷香采蝶眠。"]'),
('a47280f9-f3a7-4d9c-b721-ed4b78016472','山礬花','董嗣杲','宋','宋诗','song-poetry','','[]','萬花開遍鄭花明，風墮纖纖萼頻□。',64,'全唐诗/poet.song.237000.json','["萬花開遍鄭花明，風墮纖纖萼頻□。", "小白挼香傳七里，繁英篩雪餞三春。", "無言甘作凌波弟，有意端凝老子身。", "葉染嫩黄成色易，苔階積糝總歸塵。"]'),
('1f99ac23-c6b1-4bac-b64d-c98e03902147','山茶花','董嗣杲','宋','宋诗','song-poetry','','[]','老樹蒼枝翠子乾，爛紅攙向雪晴看。',64,'全唐诗/poet.song.237000.json','["老樹蒼枝翠子乾，爛紅攙向雪晴看。", "綠攢勁葉身邊刺，金凝纖鬚腹內丹。", "鶴頂剪開霞瓣暖，驪珠遺下日亡寒。", "幾多名品中州有，染透春風十二闌。"]'),
('4a358bc4-1917-4649-baba-bf64179e54a4','海棠花','董嗣杲','宋','宋诗','song-poetry','','[]','鸚柔猩艷勝西川，有色無香意態妍。',64,'全唐诗/poet.song.237000.json','["鸚柔猩艷勝西川，有色無香意態妍。", "吟令美招名友聚，眠春羞並醉妃傳。", "錦城紅濯垂絲雨，繡幄青籠秉燭煙。", "莫待臙脂成粉去，月明便好泛金船。"]'),
('8245fcae-8035-457d-8d8f-9954dc759d7a','石榴花','董嗣杲','宋','宋诗','song-poetry','','[]','猩巾縐摺亞枝紅，獨現精神萬綠中。',64,'全唐诗/poet.song.237000.json','["猩巾縐摺亞枝紅，獨現精神萬綠中。", "带種歸來傳博望，動人詠處想荆會。", "觸風絳彩逃春艷，縈火朱房爍暑空。", "別有盆窠培埴異，深黄線碧不相同。"]'),
('b3b9b69d-a0ed-4d69-83cf-256dac4c5692','迎春花','董嗣杲','宋','宋诗','song-poetry','','[]','破寒乘暖迓東皇，簇定剛條爛熳黄。',64,'全唐诗/poet.song.237000.json','["破寒乘暖迓東皇，簇定剛條爛熳黄。", "野艷飄搖金雀嫩，露叢勾引蜜蜂狂。", "萬千花事從頭起，九十韶光有底忙。", "歲歲陽和先占取，等閒排日趲群芳。"]'),
('842e8d39-6d54-44a8-97b5-f39fb617d5ae','長春花','董嗣杲','宋','宋诗','song-poetry','','[]','一枝纔謝一枝殷，自是春工不與閑。',32,'全唐诗/poet.song.237000.json','["一枝纔謝一枝殷，自是春工不與閑。", "縱使牡丹稱絕艷，到頭榮瘁片時間。"]'),
('a1db49c0-f2d9-4afa-8459-06d3acc8cbc9','杜鵑花','董嗣杲','宋','宋诗','song-poetry','','[]','樹底催歸咽一聲，夕陽噴恨入繁英。',64,'全唐诗/poet.song.237000.json','["樹底催歸咽一聲，夕陽噴恨入繁英。", "枝枝血染花風晚，萼萼愁開穀雨晴。", "尚有春魂遺萬古，豈無月色照三更。", "冤紅遮莫隨流水，最撓天涯蜀客情。"]'),
('a1e0199e-04eb-460d-955d-875c0aaf0f16','雞冠花','董嗣杲','宋','宋诗','song-poetry','','[]','晴芳掩映宋窗曛，醜瓣攢鱗鬬野雲。',64,'全唐诗/poet.song.237000.json','["晴芳掩映宋窗曛，醜瓣攢鱗鬬野雲。", "艷挺雙頭誰立異，名儕五德自爲群。", "丹裳浥露承秋重，赤幘臨風唱曉分。", "函谷關前如有此，不鳴惟恐誤田文。"]'),
('59b80cd8-df7d-4987-b8c6-b054cc384907','金鳳花','董嗣杲','宋','宋诗','song-poetry','','[]','花仙五色自迎逢，翅翼翔霞濕翠籠。',64,'全唐诗/poet.song.237000.json','["花仙五色自迎逢，翅翼翔霞濕翠籠。", "嬌萃九苞攢露萼，秀離丹穴舞秋風。", "埋叢還繞蕭臺勝，絢彩應懷舜殿空。", "曾見毗陵遺便面，善描開謝不相同。"]'),
('270d9c59-2d0b-4c47-a47c-c1ae92791fb7','碧蟬兒花','董嗣杲','宋','宋诗','song-poetry','','[]','翠蛾遺種吐纖蕤，不逐西風曳別枝。',64,'全唐诗/poet.song.237000.json','["翠蛾遺種吐纖蕤，不逐西風曳別枝。", "翅翅展青無體勢，心心埋白有鬚眉。", "偎籬冷吐根苗處，傍路涼資雨露時。", "分外一般天水色，此方獨許染家知。"]'),
('6efcb9e2-ac8e-4912-9114-e57b687f008d','牽牛花','董嗣杲','宋','宋诗','song-poetry','','[]','籬笆雨過晚陽紅，碧襯秋空點染工。',64,'全唐诗/poet.song.237000.json','["籬笆雨過晚陽紅，碧襯秋空點染工。", "河鼓星高鍾異卉，銖衣煙靚裊西風。", "香挼茜彩塗薑色，蔓引涼姿入豆叢。", "爲藥尚猶分黑白，此花豈與易羊同。"]'),
('1ff7f155-d4a5-49f3-987f-7317c42b0f86','後庭花','董嗣杲','宋','宋诗','song-poetry','','[]','有葉無花孰與同，繄誰指作鴈來紅。',64,'全唐诗/poet.song.237000.json','["有葉無花孰與同，繄誰指作鴈來紅。", "翠梢潤色攢秋瓣，玉樹遺歌入野叢。", "混跡塵泥欺落日，強顔籬落媚西風。", "麗華曾灑當時淚，不把臙脂染井桐。"]'),
('819dbc68-5bc0-4413-8908-89b21ce03acb','瓶蕉花','董嗣杲','宋','宋诗','song-poetry','','[]','鵝項窰壺插翠幹，就中瓊卉裊清寒。',64,'全唐诗/poet.song.237000.json','["鵝項窰壺插翠幹，就中瓊卉裊清寒。", "暑天流影澄方沼，塵眼迷叢倚曲欄。", "幾葉但知靜尾掉，數蕤易覺粉香殘。", "西風枝上無多雨，留傍花臺當畫看。"]'),
('1dae1677-0151-47ec-8c7b-92fd87e5b7c6','聚八仙花','董嗣杲','宋','宋诗','song-poetry','','[]','密團粉膩翠枝擎，亂碾銖衣降紫冥。',64,'全唐诗/poet.song.237000.json','["密團粉膩翠枝擎，亂碾銖衣降紫冥。", "揉雪謾爲春晚殿，御風應負飲中靈。", "蒂占瓊瓣輕如蝶，心裊金叢燦若星。", "誰指凌波姑射醉，有人眠月可曾醒。"]'),
('5d30b8f8-6531-4323-af79-c28857927ac6','佛手花','董嗣杲','宋','宋诗','song-poetry','','[]','不能摩頂過祇園，幻作清芳與世傳。',64,'全唐诗/poet.song.237000.json','["不能摩頂過祇園，幻作清芳與世傳。", "排葉瓜痕分翠浄，吐葩心骨耀丹妍。", "但迷色界空華相，肯悟宗門直指禪。", "誰汲野泉臨曉浸，瓦瓶插供白衣仙。"]'),
('a626f113-feb7-426a-a4f7-fd86a240675d','紫荆花','董嗣杲','宋','宋诗','song-poetry','','[]','繁蘂粘條簇茜塵，挨牆傍壁爍荒榛。',64,'全唐诗/poet.song.237000.json','["繁蘂粘條簇茜塵，挨牆傍壁爍荒榛。", "風傳兄弟知何樂，雨噴精神老此春。", "眼底葉空枝有艷，根頭花盛樹無身。", "野芳若省榮枯易，肯厭遊蜂來蜜頻。"]'),
('ff78d749-e52d-4120-8f52-4af57b69ebc9','黄葵花','董嗣杲','宋','宋诗','song-poetry','','[]','天然嫩相爍秋明，淡染鵝裳結束輕。',64,'全唐诗/poet.song.237000.json','["天然嫩相爍秋明，淡染鵝裳結束輕。", "醉蘂強傳金盞側，赤心長向火輪傾。", "四娘蹊上能無種，一點眉間自有情。", "不照花根元藉葉，羨他衛足了孤生。"]'),
('d0463acb-2ee3-4ca8-a485-14ba543bd19b','素馨花','董嗣杲','宋','宋诗','song-poetry','','[]','負得劉王侍女稱，何年鍾作塚魂英。',64,'全唐诗/poet.song.237000.json','["負得劉王侍女稱，何年鍾作塚魂英。", "月娥暗吐溫柔態，海國元標悉茗名。", "翠髻雲鬟爭點綴，風香露屑鬬輕盈。", "分明削就梅花雪，誰在瑤臺醉月明。"]'),
('86d73463-0609-4d15-bbad-cd1da724744d','朱槿花','董嗣杲','宋','宋诗','song-poetry','','[]','朝開暮落自籬頭，此種南來翠葉稠。',64,'全唐诗/poet.song.237000.json','["朝開暮落自籬頭，此種南來翠葉稠。", "輦致一壺舒數艷，時當三伏眩雙眸。", "麝香藤畔遺丹椀，葉莉窠邊吐綿毬。", "涼月在天天似水，深紅獨照滿堂秋。"]'),
('89ddddd6-c23c-4973-94f7-c0f93b923bcf','臙脂菊花','董嗣杲','宋','宋诗','song-poetry','','[]','綠蒂黄心簇絳英，何時負取旱蓮名。',64,'全唐诗/poet.song.237000.json','["綠蒂黄心簇絳英，何時負取旱蓮名。", "預知荒徑非全盛，先吐芳葩破獨清。", "籬落赬填空有艷，風霜黄槁却無情。", "紅嫣香絕誰傷旱，難結蟂桑處士盟。"]'),
('8512906f-0dfb-47d4-b1f4-874cc6b6f7ca','碧桃花','董嗣杲','宋','宋诗','song-poetry','','[]','何時和露種瓊英，素質輕盈骨骼清。',64,'全唐诗/poet.song.237000.json','["何時和露種瓊英，素質輕盈骨骼清。", "古觀自栽千樹艷，重門誰鎖一春情。", "綃裳月曳瑤臺晚，綠蒂煙凝粉瓣晴。", "幾片雪香流出遠，涌金池傍涌金城。"]'),
('c6eb860f-b3b3-43c4-aa96-a561e1f5132f','紅梅花','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','瘦倚西岡石圃陰，玉容忽抹艷粧深。',64,'全唐诗/poet.song.237000.json','["瘦倚西岡石圃陰，玉容忽抹艷粧深。", "染春應借東君手，眩眼曾疑北客心。", "霞吐丰姿情脈脈，雪遺香影夢沈沈。", "粥餳風景清明近，錯認廬山種一林。"]'),
('b602ac0e-7d8b-40f0-b728-4fc7e14318a3','蠟梅花','董嗣杲','宋','宋诗','song-poetry','','[]','剛條簇簇陳蠅封，勁葉將零傲此冬。',64,'全唐诗/poet.song.237000.json','["剛條簇簇陳蠅封，勁葉將零傲此冬。", "磬口種奇英可嚼，檀心香烈蒂初鎔。", "根依陽地春風透，瓶倚晴窗日氣濃。", "一樣黄昏疎影處，懸知水月不相容。"]'),
('9e6ce22c-b4c7-43ea-9ff6-eeadf6fb9998','白蓮花','董嗣杲','宋','宋诗','song-poetry','','[]','素質盈盈綠蓋張，肯同媚眼醉斜陽。',64,'全唐诗/poet.song.237000.json','["素質盈盈綠蓋張，肯同媚眼醉斜陽。", "儼然玉井風姿異，無此冰壺月色香。", "天地一空誰染着，水雲十里自清涼。", "東林結社流芳處，還有池亭傍上方。"]'),
('be4eeb3c-d6e7-4172-92ae-f7c0d7a0527c','錦带花','董嗣杲','宋','宋诗','song-poetry','','[]','忍見柔枝綴彩英，愁圍未解又清明。',64,'全唐诗/poet.song.237000.json','["忍見柔枝綴彩英，愁圍未解又清明。", "茸茸疊萼縈春夢，嫋嫋長條繫別情。", "有樣謾傳居士製，無香徒滓海仙名。", "文臣服色開時驗，次第妖嬈織不成。"]'),
('64b5bd1e-e8bc-4af3-8617-58a6bef05629','玉繡毬花','董嗣杲','宋','宋诗','song-poetry','','[]','凈碾寒瓊色瓣妍，冷陰團雪壓枝圓。',64,'全唐诗/poet.song.237000.json','["凈碾寒瓊色瓣妍，冷陰團雪壓枝圓。", "錦梭風颺鴛鴦結，翠幄雲攢蛺蝶眠。", "眩夜似懸綃帳底，拋春如在綵竿前。", "眼明萬綠清和處，未數花中聚八仙。"]'),
('b8363df3-1da1-4783-9a1e-bb6d0a08c488','金燈花','董嗣杲','宋','宋诗','song-poetry','','[]','弱瓣堅鬚燦野光，成叢灼灼鬬丹粧。',64,'全唐诗/poet.song.237000.json','["弱瓣堅鬚燦野光，成叢灼灼鬬丹粧。", "風葩凈藴商天艷，霞朵輕搖月夜涼。", "瀋透柔柯難受雨，冷零嫩葉不禁霜。", "通明可使書窗透，肯拾秋螢聚作嚢。"]'),
('07a7a970-2a65-491e-ba53-9f9b207ab8d3','金沙花','董嗣杲','宋','宋诗','song-poetry','','[]','暖倚青牆揉紫綿，絳葩淡染露花鮮。',64,'全唐诗/poet.song.237000.json','["暖倚青牆揉紫綿，絳葩淡染露花鮮。", "花遺顔色祇如此，名借酴醾得並傳。", "伴直自應留故事，謾栽聊可殿春妍。", "年年滿架東風艷，夢斷詞林視草仙。"]'),
('6b5a6e00-97cb-44d3-bbfd-d38738a25da8','寶相花','董嗣杲','宋','宋诗','song-poetry','','[]','誰趲珍芳態度呈，風香露色謾敷榮。',64,'全唐诗/poet.song.237000.json','["誰趲珍芳態度呈，風香露色謾敷榮。", "縱矜百媚留春色，難壓群花殿晚名。", "暗綠園林黄鳥靜，嫣紅籬落粉機明。", "禁持光景無多日，冶艷隨飄逐雨晴。"]'),
('209d785e-e931-4c01-a776-01548c27e294','玉簪花','董嗣杲','宋','宋诗','song-poetry','','[]','石砌秋新展綠衣，綠衣涼矗嫩瓊飛。',64,'全唐诗/poet.song.237000.json','["石砌秋新展綠衣，綠衣涼矗嫩瓊飛。", "低抽葉面幾叢矮，高叢花頭二寸肥。", "月下自矜明艷盛，壇邊誰認墮翹非。", "午風掃凈青蠅止，還有清香眩落暉。"]'),
('6574aa1e-7e77-4f3e-807a-67de94f20320','錢清觀禾','董嗣杲','宋','宋诗','song-poetry','','[]','落葉清江路，秋行適古心。',48,'全唐诗/poet.song.237000.json','["落葉清江路，秋行適古心。", "井由秦法變，河海禹功深。", "鷗浴蒹葭影，牛眠桑柘陰。", "誰憐浪遊客，獨倚斷蓬吟。"]'),
('5b7bc52a-2348-4b59-848e-3e34b13a441b','登六和塔','董嗣杲','宋','宋诗','song-poetry','','[]','闌檻倚雲漢，身疑出上方。',48,'全唐诗/poet.song.237000.json','["闌檻倚雲漢，身疑出上方。", "乾坤一指顧，吳越兩消亡。", "海接空江白，山分落日黄。", "伍胥遺恨在，秋草隔沙長。"]'),
('56eabbba-e018-4f3e-b1db-7ef43acc86e7','雨中宿洞霄','董嗣杲','宋','宋诗','song-poetry','','[]','青青九鎖山，步步聽潺湲。',48,'全唐诗/poet.song.237000.json','["青青九鎖山，步步聽潺湲。", "雨重精神倦，雲深意緒閒。", "禽聲依石樹，泉溜出巖關。", "落落仙蹤在，何能見大還。"]'),
('3738260a-fdb2-446d-ba76-0df9d26d4ba8','客中懷西湖二首  其一','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一日無詩氣還濁，百年有限身更孱。',32,'全唐诗/poet.song.237000.json','["一日無詩氣還濁，百年有限身更孱。", "西湖多少好風月，何時買屋安蕭閒。"]'),
('87fdab96-2ea9-4526-9618-01b8688c3a65','客中懷西湖二首  其二','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閒多便可賦詩健，客少應能減酒豪。',32,'全唐诗/poet.song.237000.json','["閒多便可賦詩健，客少應能減酒豪。", "風雨六橋入圖畫，此身可並南山高。"]'),
('bf45955f-11b8-4e9f-a4ff-0b3ba2461478','杜陵至節後詩有遠在劍南思洛陽句予客九江遠過興國至後忽動西湖之感口占實情得四韻何當神交杜陵於夢寐中必亦一笑也','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','杜陵曾吟至後詩，我今客遠愁歸遲。',64,'全唐诗/poet.song.237000.json','["杜陵曾吟至後詩，我今客遠愁歸遲。", "蜀中想重洛陽憶，江上亦起錢塘思。", "地異心同一今古，風饕雪虐共路岐。", "西湖何殊灞橋趣，亟歸乘興無復疑。"]'),
('c28ea69e-f994-418f-abf9-9a50ec848128','蕪湖','董嗣杲','宋','宋诗','song-poetry','','[]','規規安利欲，擾擾競光陰。',48,'全唐诗/poet.song.237000.json','["規規安利欲，擾擾競光陰。", "男邑瀕江尾，商家截市心。", "炎涼難洗蕩，風月易招尋。", "見說圩田熟，欣逢節序臨。"]'),
('27b11304-610c-4210-95af-f03759483269','送劉漢老過蕪湖','董嗣杲','宋','宋诗','song-poetry','','[]','歌傳製錦久，樂得袖琴過。',48,'全唐诗/poet.song.237000.json','["歌傳製錦久，樂得袖琴過。", "浙客量鹽少，淮商販藥多。", "隨燈遊晚市，沽酒隔昏河。", "纔見江豚起，東風又碧波。"]'),
('0e1784c6-310b-476b-8e76-424fc8818bdb','落梧','董嗣杲','宋','宋诗','song-poetry','','[]','梧葉幾片飛，三日西風急。',24,'全唐诗/poet.song.237000.json','["梧葉幾片飛，三日西風急。", "新月冷銀牀，牀下孤螿泣。"]'),
('dd7feabd-c009-4231-bda8-60af52938d36','過新斗門感懷','董嗣杲','宋','宋诗','song-poetry','','[]','絕壁憑居險，中林憶故深。',48,'全唐诗/poet.song.237000.json','["絕壁憑居險，中林憶故深。", "臨溪掃地醉，就樹摘柑吟。", "打稻農初歇，餐芝客莫尋。", "重來嗟未卜，過此却酸心。"]'),
('6173f0ae-1cfd-4341-a5c3-955f6b3f17f2','出德化門外','董嗣杲','宋','宋诗','song-poetry','','[]','湖光分柳岸，野趣入桑畦。',48,'全唐诗/poet.song.237000.json','["湖光分柳岸，野趣入桑畦。", "錦片花隨水，犀尖筍迸泥。", "淮雲收雨去，蜀鳥失春啼。", "隔浦軍船過，斜陽送鼓鼙。"]'),
('c781bdd8-69e3-4500-8fba-67cb5883058a','江村二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','荒村雨過炊煙收，誰繫月下籬根舟。',32,'全唐诗/poet.song.237000.json','["荒村雨過炊煙收，誰繫月下籬根舟。", "風葉半夜摐摐響，老犬獨吠空江秋。"]'),
('eff2b57c-9f3b-42a1-b979-c5e20d6104d8','江村二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','秋聲月色饒江雲，携壺相呼有近鄰。',32,'全唐诗/poet.song.237000.json','["秋聲月色饒江雲，携壺相呼有近鄰。", "今宵拚得借榻睡，此時共作無懷民。"]'),
('13996bd1-ad06-4454-9189-11307ca8ff36','溪村晚步即事二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','溪嵐欑翳入窗空，最惱悲秋病瘧翁。',32,'全唐诗/poet.song.237000.json','["溪嵐欑翳入窗空，最惱悲秋病瘧翁。", "三日不行亭北路，誰將丹纈染喬楓。"]'),
('7cd33f91-29a7-492d-84d1-daab954c1999','溪村晚步即事二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','小策盤旋草舍東，東西拾穗走兒童。',32,'全唐诗/poet.song.237000.json','["小策盤旋草舍東，東西拾穗走兒童。", "村家間有秋收處，愁語酣歌自不同。"]'),
('cd449333-2201-420b-961e-3ee00938eea8','泊曹家沙  其一','董嗣杲','宋','宋诗','song-poetry','','[]','雪覆蘆花障遠郊，小舟不待起風拋。',32,'全唐诗/poet.song.237000.json','["雪覆蘆花障遠郊，小舟不待起風拋。", "沙頭只有三家住，爛草簷頭兩把茅。"]'),
('1e3888eb-2f5c-4b07-bf2b-ba6babedb1aa','泊曹家沙  其二','董嗣杲','宋','宋诗','song-poetry','','[]','行沙回望岸南頭，疊疊層層雪積稠。',32,'全唐诗/poet.song.237000.json','["行沙回望岸南頭，疊疊層層雪積稠。", "民社一同猶是寄，故應羈跡此生浮。"]'),
('4470c2d3-7ae5-49d5-8060-610f828ed17a','泊曹家沙  其三','董嗣杲','宋','宋诗','song-poetry','','[]','險危屢涉尚未慣，沙上盡認家爲曹。',32,'全唐诗/poet.song.237000.json','["險危屢涉尚未慣，沙上盡認家爲曹。", "江空不見雨點大，船隘莫禁人語高。"]'),
('44849806-5f01-477e-b171-f5925a93cdd0','泊曹家沙  其四','董嗣杲','宋','宋诗','song-poetry','','[]','遠歸誰道日辰誤，小醉自覺精神豪。',32,'全唐诗/poet.song.237000.json','["遠歸誰道日辰誤，小醉自覺精神豪。", "已誓孤褰脫世故，南山斗底誅蓬蒿。"]'),
('729b0f54-61cc-4619-bdfa-88fe0ca0a7c6','生意堂三首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','畫堂清傍水南橋，煙氣如炊掩紫霄。',32,'全唐诗/poet.song.237000.json','["畫堂清傍水南橋，煙氣如炊掩紫霄。", "十二闌幹成獨倚，櫓聲風隔大江遙。"]'),
('408dc9e5-9523-4e52-877b-685fb4485e5f','生意堂三首  其二','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江天饒霧未能開，閒拉孤笻睨九垓。',32,'全唐诗/poet.song.237000.json','["江天饒霧未能開，閒拉孤笻睨九垓。", "紅日破陰晴色轉，廬山如洗入堂來。"]'),
('5e86ab9a-862e-4d28-9f0a-4458ba064171','生意堂三首  其三','董嗣杲','宋','宋诗','song-poetry','','[]','絮花挼雪小橋寒，渾是蘇隄柳下看。',32,'全唐诗/poet.song.237000.json','["絮花挼雪小橋寒，渾是蘇隄柳下看。", "愁去不知春袖濕，晚風吹雨入闌干。"]'),
('29b9bf36-0282-4cc0-9507-86f2af23d050','素馨','董嗣杲','宋','宋诗','song-poetry','','[]','負得劉王侍女稱，何年鍾作塚魂英。',64,'全唐诗/poet.song.237000.json','["負得劉王侍女稱，何年鍾作塚魂英。", "月娥暗吐溫柔態，海國元標悉茗名。", "翠髻雲鬟爭點綴，風香露屑鬬輕盈。", "分明削就梅花雪，誰在瑤臺醉月明。"]'),
('68b6a58e-fbe4-475e-ac90-6a613f843ff6','西興道中二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','無馬可租衝曉去，有笻堪策趁晴行。',32,'全唐诗/poet.song.237000.json','["無馬可租衝曉去，有笻堪策趁晴行。", "初程便是蕭山縣，噴火榴花兩岸明。"]'),
('46405aba-7fb6-4ad8-afad-fb9c153e7696','西興道中二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','狂走斷貽猿鶴笑，醉吟忽感歲時遷。',32,'全唐诗/poet.song.237000.json','["狂走斷貽猿鶴笑，醉吟忽感歲時遷。", "野橋流水湘湖路，欲擷蓴絲飯午前。"]'),
('4b1ffeab-c808-45b5-8e58-abd25cfc9207','送徐性初歸隆興','董嗣杲','宋','宋诗','song-poetry','','[]','歲華鬚鬢裏，行色水雲中。',48,'全唐诗/poet.song.237000.json','["歲華鬚鬢裏，行色水雲中。", "南徑寒花在，西山落葉空。", "別憐今夜酒，歌續古人風。", "歸隱東湖上，忘機狎釣翁。"]'),
('b3031a21-2e2b-4df4-b118-4ea2553dc407','江感覺口號二首  其一','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','定江軍門擁雲氣，廬山面目長相朝。',32,'全唐诗/poet.song.237000.json','["定江軍門擁雲氣，廬山面目長相朝。", "閫臣所持止一恕，牆壁何恨粘歌謠。"]'),
('6e411d31-3742-4dab-af66-e32332b3a7fd','江感覺口號二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','此郡境有彭澤縣，淵明曾遺晉時蹤。',32,'全唐诗/poet.song.237000.json','["此郡境有彭澤縣，淵明曾遺晉時蹤。", "三徑莫知在何處，且撫官圃千尺松。"]'),
('bd26a164-5922-4ede-8b25-1250f2029e15','寄彭澤陳明府','董嗣杲','宋','宋诗','song-poetry','','[]','田頭遇白叟，爭說長官清。',120,'全唐诗/poet.song.237000.json','["田頭遇白叟，爭說長官清。", "決訟如轉燭，往往得其情。", "高風古靈派，惠澤流花城。", "荷鍤遍阡陌，咸樂及時耕。", "桑埂翠陰老，稻坂黄雲平。", "積愛發謠誦，連屋歌壤聲。", "春山映酒艷，秋籬挹金英。", "我滯亦已久，欲往搖心旌。", "有時遞信音，展轉思盍幷。", "重當買孤航，展拜陶淵明。"]'),
('2e970af4-5900-47a5-9023-b3079853ea7b','寄璹秋巖','董嗣杲','宋','宋诗','song-poetry','','[]','吟窮荒此地，靜極省吾生。',48,'全唐诗/poet.song.237000.json','["吟窮荒此地，靜極省吾生。", "秋老腸絲斷，江空月魄明。", "松簷嗔鳥聚，竹榻夢僧清。", "別後蒼顔改，初逢慨暑程。"]'),
('e73439ae-dfde-4fe5-b5ad-765e5cd7488d','寄樓恪齋館人兩黄丈','董嗣杲','宋','宋诗','song-poetry','','[]','四明山水秀，二老器能殊。',48,'全唐诗/poet.song.237000.json','["四明山水秀，二老器能殊。", "語劇欲流涕，吟清謾撚鬚。", "林香傳竹醉，溪影寫藤枯。", "愧我卑微者，無階助遠圖。"]'),
('20f9ad2d-3d51-4e50-950a-520cd1896cfc','寄韓玉璵二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','郭北下湖枕蒼綠，書屋奈此五月溽。',64,'全唐诗/poet.song.237000.json','["郭北下湖枕蒼綠，書屋奈此五月溽。", "涼臺水榭自柳陰，獨斂修程困羈束。", "心心巖峯不得住，瀑聲縈回夢不足。", "世故屈摺歌刺促，誰識其人美如玉。"]'),
('77185f1f-ac6d-409b-9ef4-00203fadc910','寄韓玉璵二首  其二','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','涼夢幾回繞=孤璵，想見絕得人間暑。',65,'全唐诗/poet.song.237000.json','["涼夢幾回繞=孤璵，想見絕得人間暑。", "西湖瀛嶼綠更熾，君胡爲兮不安處。", "信美非土固所慮，樓臺近水何多阻。", "自顧形驘況棲濕，未蓍共此清夜語。"]'),
('3a6e465e-99e2-4c29-bd6d-88fd7dae6842','寄湖口茶局臧尚幹','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','酡顔探得洞玄真，老氣摩霄岸角巾。',64,'全唐诗/poet.song.237000.json','["酡顔探得洞玄真，老氣摩霄岸角巾。", "案上押批呼局吏，津頭釀酒謝江神。", "天寒茶課收征倍，雪霽梅吟寄驛頻。", "何日此來聯榻語，廬山几案却無塵。"]'),
('c0126e0d-e624-4488-a5bb-3983d48cd7a4','記仙女三絕  其一','董嗣杲','宋','宋诗','song-poetry','','[]','柳條金嫩不勝鴉，青粉牆邊道藴家。',32,'全唐诗/poet.song.237000.json','["柳條金嫩不勝鴉，青粉牆邊道藴家。", "燕子不來春寂寞，小窗和雨夢梨花。"]'),
('374cf585-fb0e-4490-8e60-8ca98a2ada0e','記仙女三絕  其二','董嗣杲','宋','宋诗','song-poetry','','[]','松影侵壇琳觀靜，桃花流水石橋寒。',32,'全唐诗/poet.song.237000.json','["松影侵壇琳觀靜，桃花流水石橋寒。", "東風吹過雙蝴蝶，人倚危樓第幾闌。"]'),
('7cb621a4-3bc9-4c25-b205-a9399ecde3a5','記仙女三絕  其三','董嗣杲','宋','宋诗','song-poetry','','[]','屈曲闌干月半規，藕花香淡水漪漪。',32,'全唐诗/poet.song.237000.json','["屈曲闌干月半規，藕花香淡水漪漪。", "分明一夜文姬夢，只有青團扇子知。"]'),
('84e508e1-279b-4cf3-9c8a-3e015f04ad51','七愛詩贈程鄉令趙君 魏鄴令西門豹','蒲壽宬','宋','宋诗','song-poetry','','[]','吾愛西門豹，其事深可傚。',48,'全唐诗/poet.song.237000.json','["吾愛西門豹，其事深可傚。", "波神豈荒滛，巫言亦機巧。", "大嫗去不來，小嫗足踸踔。", "豪長涕叩頭，從此識政教。"]'),
('651a0acb-12f6-4bd1-b450-b08da219c1b0','七愛詩贈程鄉令趙君 漢中牟令魯恭','蒲壽宬','宋','宋诗','song-poetry','','[]','吾愛魯仲康，治效多致祥。',48,'全唐诗/poet.song.237000.json','["吾愛魯仲康，治效多致祥。", "害稼螟犬牙，中牟了無傷。", "掾驚雉馴擾，兒念雛方將。", "河南有府尹，其美乃播揚。"]'),
('fbf5e3b1-24d6-4e31-af8f-29c3243eb6f8','七愛詩贈程鄉令趙君 漢密令卓茂','蒲壽宬','宋','宋诗','song-poetry','','[]','吾愛卓子康，作邑非尋常。',48,'全唐诗/poet.song.237000.json','["吾愛卓子康，作邑非尋常。", "口不及人惡，撫字若弗遑。", "禮律乃並用，化嚚以爲良。", "解馬以與人，不較人自償。"]'),
('ddd050fe-e6ab-4f74-ad05-1b0225268148','七愛詩贈程鄉令趙君 漢堂邑令鍾離意','蒲壽宬','宋','宋诗','song-poetry','','[]','吾愛鍾離意，錦製與人異。',48,'全唐诗/poet.song.237000.json','["吾愛鍾離意，錦製與人異。", "荒縣民無廬，茅竹畢繕事。", "亦有多怖人，憯憯惑禍祟。", "祝土矢乃盡，神譴不敢避。"]'),
('746042a4-4bf0-4113-8113-d3c2943600c9','七愛詩贈程鄉令趙君 漢雍丘令劉矩','蒲壽宬','宋','宋诗','song-poetry','','[]','吾愛劉淑方，禮遜以化彊。',48,'全唐诗/poet.song.237000.json','["吾愛劉淑方，禮遜以化彊。", "諄諄耳提訓，語味深且長。", "忿恚爲可忍，莫入鳴絃堂。", "訟者各感去，從今無他腸。"]'),
('39e8933e-8236-4aca-8e8f-0218c711760b','七愛詩贈程鄉令趙君 齊山陰令傅琰','蒲壽宬','宋','宋诗','song-poetry','','[]','吾愛傳季珪，爲事求端倪。',48,'全唐诗/poet.song.237000.json','["吾愛傳季珪，爲事求端倪。", "羣愚亦智詐，不辨袪厥迷。", "感深賣針媪，靦以食豆鷄。", "一縣稱神明，鼠輩榛其蹊。"]'),
('694b3215-fc0b-4054-94fd-d00341178481','七愛詩贈程鄉令趙君 唐魯山令元德秀','蒲壽宬','宋','宋诗','song-poetry','','[]','吾愛元紫芝，卓爾不可移。',48,'全唐诗/poet.song.237000.json','["吾愛元紫芝，卓爾不可移。", "盗虎孰小大，許囚虎歸尸。", "音樂第勝負，蔿于遭殊知。", "歲滿何所爲，柴車一縑隨。"]'),
('22088ca2-98ca-4460-a34c-ecc30eed5803','詠史八首 陶侃母','蒲壽宬','宋','宋诗','song-poetry','','[]','坩鮓有幾許，直欲致一甘。',36,'全唐诗/poet.song.237000.json','["坩鮓有幾許，直欲致一甘。", "豈知聖善意，見此轉不堪。", "此毋天下毋，清風使人慙。"]'),
('956a0bc9-a413-4f4b-ac60-6079b121ebf6','詠史八首 黔婁妻','蒲壽宬','宋','宋诗','song-poetry','','[]','明知正不足，不若斜有餘。',36,'全唐诗/poet.song.237000.json','["明知正不足，不若斜有餘。", "破衾有何好，錦繡乃不如。", "卓哉婦人言，賢於五車書。"]'),
('353ea901-28c3-42b1-8848-e8c9c88ad765','詠史八首 謝道韞','蒲壽宬','宋','宋诗','song-poetry','','[]','當時詠雪句，誰能出其右。',36,'全唐诗/poet.song.237000.json','["當時詠雪句，誰能出其右。", "雅人有深致，錦心而繡口。", "此事難效顰，畫虎恐類狗。"]'),
('8e9b95ff-a70a-4d11-bab5-9f9b51455466','詠史八首 蔡文姬','蒲壽宬','宋','宋诗','song-poetry','','[]','琴彈十八拍，聽此雙淚流。',36,'全唐诗/poet.song.237000.json','["琴彈十八拍，聽此雙淚流。", "一死固已難，萬言復誰尤。", "九原見衛子，何語可以酬。"]'),
('b3f71df9-db79-499b-9d27-3078811d07c3','詠史八首 鮑宣妻','蒲壽宬','宋','宋诗','song-poetry','','[]','幡然棄舊習，布裙牽鹿車。',36,'全唐诗/poet.song.237000.json','["幡然棄舊習，布裙牽鹿車。", "拜姑禮云畢，提甕汲自如。", "富貴此一時，何可忘厥初。"]'),
('4dac5354-0c1e-4ffb-8405-2e38551b0536','詠史八首 樂羊子妻','蒲壽宬','宋','宋诗','song-poetry','','[]','拾遺戒不受，見金等沙泥。',36,'全唐诗/poet.song.237000.json','["拾遺戒不受，見金等沙泥。", "對姑不能食，又愧他舍鷄。", "其視取棗人，冰炭恐不齊。"]'),
('f803c293-ad7e-4d2a-81df-7342d18533be','詠史八首 朝鮮婦','蒲壽宬','宋','宋诗','song-poetry','','[]','白首携一壺，亂流去何之。',36,'全唐诗/poet.song.237000.json','["白首携一壺，亂流去何之。", "婦呼吻欲裂，彼乃昏不知。", "箜篌彈復彈，河水風瀰瀰。"]'),
('4a62a5c7-71c4-48a4-89ad-79561d856d2e','詠史八首 孟光','蒲壽宬','宋','宋诗','song-poetry','','[]','色不諧朱鈆，力可舉杵臼。',36,'全唐诗/poet.song.237000.json','["色不諧朱鈆，力可舉杵臼。", "貧賤何足云，持敬在悠久。", "相對如嘉賓，旁人莫嫌醜。"]'),
('8ce63329-2306-4881-a8bf-9d9ec1742f4d','示兒','蒲壽宬','宋','宋诗','song-poetry','','[]','種穀一歲事，讀書一生期。',120,'全唐诗/poet.song.237000.json','["種穀一歲事，讀書一生期。", "方春不下種，竟歲常餒饑。", "少年不向學，終身成愚癡。", "饑猶一家愁，愚被衆人欺。", "彼蒼念吾父，爾輩得令師。", "欲速成揠苖，計日如耘耔。", "程文國有式，體製須及時。", "弱冠無所聞，出語人見嗤。", "爾勞我則恤，我憂爾奚知。", "中夜不遑寐，作此勸學詩。"]'),
('75c17c0b-e4af-4a31-b84d-cbad3416d2f5','明月篇','蒲壽宬','宋','宋诗','song-poetry','','[]','海賈不愛死，適值驪龍眠。',72,'全唐诗/poet.song.237000.json','["海賈不愛死，適值驪龍眠。", "深淵頃刻命，平地千丈川。", "丈夫豈無志，固爲兒女煎。", "彼美頭上粲，它人口中涎。", "鮫人一滴淚，不肯随漪漣。", "眼見懸珠人，明月幾缺圓。"]'),
('c8fef0b5-4f8c-4191-b724-155e8610e111','拙婦吟','蒲壽宬','宋','宋诗','song-poetry','','[]','生爲矮屋女，本乏超世姿。',132,'全唐诗/poet.song.237000.json','["生爲矮屋女，本乏超世姿。", "苟焉執絲枲，安得組繡奇。", "人各愛厥子，驕養随所宜。", "今晨嫁朱門，裝束弗適時。", "尊嫜不厭拙，鄰曲莫見嗤。", "或有勸我言，學掃長蛾眉。", "妾婦前致辭，拙性不可移。", "誰能事膏沐，随人作妍媸。", "采采南澗蘋，心事澗水知。", "在家盡子職，爲婦盡婦儀。", "如何織錦字，更製迴文詩。"]'),
('6a8b8b8b-6e0e-4247-a753-22ff51346217','和博古直五首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','聖門藹徒衆，幾人得稱賢。',72,'全唐诗/poet.song.237000.json','["聖門藹徒衆，幾人得稱賢。", "美哉全玉人，履行師淵騫。", "寒日辟蘆絮，饑倚負郭田。", "所樂者何事，至道森乎前。", "豈必挾日月，地行即飛仙。", "刀圭儻可覔，何處今赤泉。"]'),
('56d349dd-c7e4-43f3-b7bc-9b352d5f2ea6','和博古直五首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','少壯能幾時，轉盻成白首。',72,'全唐诗/poet.song.237000.json','["少壯能幾時，轉盻成白首。", "俯仰百年中，蠅營復狗苟。", "規規一世士，禮法自繩糾。", "不趁蟻磨旋，空嗟兔株守。", "杞菊爲餱糧，雲山作賓友。", "空泥堅白鳴，夷惠徒可否。"]'),
('583d9cb8-7bca-4cf1-a359-cd095ec6ebe9','和博古直五首  其三','蒲壽宬','宋','宋诗','song-poetry','','[]','涉世思夷塗，理生有常道。',72,'全唐诗/poet.song.237000.json','["涉世思夷塗，理生有常道。", "抱甕灌我園，充盤戒鄰棗。", "秋色何蒼然，愓焉履霜早。", "偉哉騎鯨人，期兹浣花老。", "渺渺無窮門，何由拾瑶草。", "惟愛柴桑翁，稱心固云好。"]'),
('376177c9-0f25-4fde-88c1-7a22ad65322d','和博古直五首  其四','蒲壽宬','宋','宋诗','song-poetry','','[]','迂踈我何有，然諾君不輕。',72,'全唐诗/poet.song.237000.json','["迂踈我何有，然諾君不輕。", "卓爾異衆嗜，矧兹藹文鳴。", "面壁愧空腹，伐木思友生。", "方當與世混，疇能别涇清。", "奚因一簪盍，使此雙眼明。", "欲引萬古脉，賴君辨豨苓。"]'),
('52e4c616-0f80-4aea-9f27-91bb3d3f2db7','和博古直五首  其五','蒲壽宬','宋','宋诗','song-poetry','','[]','曠兹歴億劫，矧此浮雲身。',72,'全唐诗/poet.song.237000.json','["曠兹歴億劫，矧此浮雲身。", "桑樞弗言病，駟馬休笑貧。", "棲棲魯中叟，救世誠艱辛。", "鳥獸豈同羣，由也徒問津。", "人世彈指頃，滄海三揚塵。", "揚塵不可詰，濟川豈無人。"]'),
('d62c3f59-3cd2-47e6-b8f3-1d728699d146','梅陽壬申劭農偶成書呈同官','蒲壽宬','宋','宋诗','song-poetry','','[]','舉酒勸爾農，更爲我儂勸。',156,'全唐诗/poet.song.237000.json','["舉酒勸爾農，更爲我儂勸。", "車笠雖不同，所諧此盂飯。", "或耕在菑畬，或耕在方寸。", "膏雨足一犁，田頭怯呼喚。", "五百維莠驕，胥徒乃蟊患。", "與國充耘耔，勿使地蒿蔓。", "幻體饑渴同，世味甘苦半。", "盤中一粒餐，鋤下幾滴汗。", "光陰駛歴塊，彼此不可玩。", "豈爲許行言，勸課在兹旦。", "老父傾耳聽，童稚繞屏看。", "相顧持我語，取信如執劵。", "安得慵耕人，從今不言倦。"]'),
('f87646ed-8ec8-4511-9b3f-ab6667b3e00f','感興','蒲壽宬','宋','宋诗','song-poetry','','[]','晨起自理髪，握髪雙涙流。',48,'全唐诗/poet.song.237000.json','["晨起自理髪，握髪雙涙流。", "不見結髪人，惆悵空白頭。", "君留白髪種，種作一叚愁。", "茁哉秋蓬根，念此春荑柔。"]'),
('80998928-5ecc-4d6a-8ff1-5a34e742aa99','送使君給事常東軒先生','蒲壽宬','宋','宋诗','song-poetry','','[]','鋒車洛陽道，秋日旌旗光。',144,'全唐诗/poet.song.237000.json','["鋒車洛陽道，秋日旌旗光。", "松陰父老語，何計攀夕郎。", "南泉昔樂土，畫戟深凝香。", "今爲彫瘵區，鹽米憂倉皇。", "一食不遑暇，衆哺安能忘。", "時哉異真倪，心乎愛龔黄。", "報政未期年，丹詔飛十行。", "正陽初繼離，化瑟方再張。", "豈無蘭蕙叢，所思在孤芳。", "履聲到星辰，泰階列寒芒。", "睠懐赤子情，啟齒玉帝旁。", "唐相有遺烈，至今留甘棠。"]'),
('e3a349a9-4e63-41ca-8899-57ed4ba99c91','投後村先生劉尚書','蒲壽宬','宋','宋诗','song-poetry','','[]','采松北山下，日與樵者親。',168,'全唐诗/poet.song.237000.json','["采松北山下，日與樵者親。", "寸尺拾遺墜，時以供炊薪。", "朝躋白雲岡，暮宿芳草濵。", "疏泉溉其本，鏡心澄爾神。", "上有千歲鶴，羽儀何振振。", "清唳返華表，感時懐鳯麟。", "下有千年苓，剥落惟夲真。", "久乃瑩雪玉，服之袪凡塵。", "清風發萬籟，天竅鳴驚人。", "嚴霜肅四宇，玉立古柏身。", "桃李衆自托，六合惟一根。", "梅竹亦有性，歲寒争卜隣。", "蔦蘿爾微彙，願乞青雲津。", "逡巡不敢止，百年在兹辰。"]'),
('af50c691-963c-4c83-9668-1b970507d72b','柬曾梅坡二首音棄  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','終歲不相見，相逢傾肺肝。',48,'全唐诗/poet.song.237000.json','["終歲不相見，相逢傾肺肝。", "堪嗟半生事，安得舊時歡。", "梅蘂先春白，桂華清露寒。", "帽雲行雨意，薄暮倚欄干。"]'),
('0b913874-1444-4df9-8523-7cacb32bbaba','柬曾梅坡二首音棄  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','靡靡秋已駛，眇焉幽思殷。',48,'全唐诗/poet.song.237000.json','["靡靡秋已駛，眇焉幽思殷。", "美人百尺樓，修帽千丈雲。", "白駒古難縶，寒蛩今畏聞。", "得酒且共陶，莫惑紙上文。"]'),
('3596583a-1292-4c32-99cc-a416fd5d89fe','送淮東田制幹回司','蒲壽宬','宋','宋诗','song-poetry','','[]','青青拱把木，人見毫芒時。',204,'全唐诗/poet.song.237000.json','["青青拱把木，人見毫芒時。", "只恐不早種，既種何用疑。", "枝條日已茂，雨露日已滋。", "揺本固不可，爪膚復奚爲。", "驚颷屢欲折，積雪久自支。", "昔日靖郭君，四十餘男兒。", "中有不舉子，其事乃甚奇。", "馳聲自薛起，有誰敢齊窺。", "君今已騎鶴，莫問腰纒資。", "主人今晉公，相量千頃陂。", "溲勃且並用，參苓恐無遺。", "相如諭蜀檄，昌黎從軍詩。", "倘可露一斑，豈無諸公知。", "君來甫兩月，雲霧才一披。", "非敢事偃蹇，禽鹿不可覊。", "勿詫我泉石，恐爲君瑕疵。", "吾且自笑我，人知我爲誰。"]'),
('305cd8a1-be02-4b8f-b8ca-077804266859','寄窺堂莊使君','蒲壽宬','宋','宋诗','song-poetry','','[]','煌煌列戟第，皎皎深衣人。',108,'全唐诗/poet.song.237000.json','["煌煌列戟第，皎皎深衣人。", "菟符藹夙望，駒谷韜絕珍。", "苟不守厥素，曷以當兹晨。", "情敦脊令急，心怛鴻鴈賓。", "餓死甘其薇，至德文其身。", "耿耿抱孤月，悠悠仰蒼旻。", "何時一握臂，漉我頭上巾。", "呼風振我襮，與君爽心神。", "欲洗塵萬斛，何處覔一塵。"]'),
('256d7932-c58f-4db6-b55f-fdf27bbd7d0c','送使君右司趙是齋','蒲壽宬','宋','宋诗','song-poetry','','[]','皦皦惠山泉，脉脉天上潢。',96,'全唐诗/poet.song.237000.json','["皦皦惠山泉，脉脉天上潢。", "中含五色文，時吐千丈光。", "人間塵土腥，聊復褰我裳。", "南州六月暑，千里暍欲狂。", "借此一掬潤，冰雪生肝腸。", "誰起心中炎，奪我腦上凉。", "我願去爲龍，爲雨膏八荒。", "年年刺桐華，樹樹皆甘棠。"]'),
('64dbed4f-7ed7-45dc-832e-908cf3d4b2cd','贈無庵道人風鑑','蒲壽宬','宋','宋诗','song-poetry','','[]','採霞以爲食，搴雲以爲衣。',48,'全唐诗/poet.song.237000.json','["採霞以爲食，搴雲以爲衣。", "飽煖無所爲，騎風去如飛。", "閒將電作鏡，照見人精微。", "欲說不得說，天機本無機。"]'),
('e5a839e9-1809-424e-bc71-98ec59c42348','梅陽寄委順趙君','蒲壽宬','宋','宋诗','song-poetry','','[]','别來柳初茁，今見蘭吐芳。',144,'全唐诗/poet.song.237000.json','["别來柳初茁，今見蘭吐芳。", "懐哉佩蘭人，欲製芙蓉裳。", "山空蕙帳冷，鶴怨秋夜長。", "羣峯暮聳峭，蟻夢猶一場。", "乘傳媿已添，刻意思所償。", "蚩蚩瘴土氓，見此淚欲滂。", "鍼石一時投，若爲起羸尫。", "常恐二豎黠，神被膏與肓。", "欲盡棄其舊，安得師之良。", "夜夢毎插羽，飛到琴冊旁。", "非貪舐鼎事，欲窺枕中方。", "緘縢倘寄翼，寛此百迴腸。"]'),
('08d70c07-4a88-4907-a475-f428b56369b5','寄丘釣磯','蒲壽宬','宋','宋诗','song-poetry','','[]','高丘逺望海，秋思窮渺瀰。',120,'全唐诗/poet.song.237000.json','["高丘逺望海，秋思窮渺瀰。", "苦吟有鬼泣，直釣無人知。", "有時捲龜殻，箕踞食蛤蜊。", "落日明雲霞，狂風舞蛟螭。", "全生带笭箵，聱叟漫奚爲。", "一笑横大江，列岫浮修眉。", "畫圖障我目，隔此天一涯。", "欲携我蓑笠，風雨從所之。", "漁僮緩鼓枻，驚我白鷺鶿。", "我欲從伊人，薄酒分一巵。"]'),
('6d90c790-6cd2-4aa6-8c39-8069cfcaaabf','寄梅坡','蒲壽宬','宋','宋诗','song-poetry','','[]','喬木聳下翠，好鳥鳴嚶嚶。',120,'全唐诗/poet.song.237000.json','["喬木聳下翠，好鳥鳴嚶嚶。", "豈不愛吾廬，感此求友聲。", "獨酌歌停雲，懷人淚如傾。", "昔我柴桑翁，五柳貧亦榮。", "今予富干樹，况有野艇横。", "鱸魚亦可膾，如此夜月明。", "誰諧彼蒼意，澗谷敦孤惸。", "青山只依舊，沽酒尋前盟。", "矯首雲帽人，兩臂羽欲生。", "故人來不來，盤俎無人爭。"]'),
('cddb598b-a852-4703-88f3-d59baf33ad20','與石巖方常簿游白水塘觀龍湫','蒲壽宬','宋','宋诗','song-poetry','','[]','孤燈照不寐，獨起行遶床。',204,'全唐诗/poet.song.237000.json','["孤燈照不寐，獨起行遶床。", "命駕欲千里，千里債已償。", "可憐太拙計，弗學時世粧。", "癖嗜鎸聱牙，拄彼枯腎腸。", "柴桑賦移居，取友勝面墻。", "奇文與疑義，相與窺抑揚。", "願給薪水役，懐此一瓣香。", "自分參也魯，或笑道士狂。", "吁嗟古之人，踽踽而涼凉。", "我不欲富貴，修短由上蒼。", "齊奴爾何事，彭祖今何方。", "莊周蝶體態，淳于蟻侯王。", "龍湫一瞬息，珠琲萬斛強。", "汎汎蓮葉舟，淼淼白水塘。", "薜荔爲我衣，芙蓉爲我裳。", "握石爲我飴，採菊爲我粻。", "興懐自千載，有酒且一觴。"]'),
('1fa9abe5-332c-4817-9ff5-1733d58e466e','己夘六月十一日書石室壁','蒲壽宬','宋','宋诗','song-poetry','','[]','晏坐圖畫出，銀屏列郡山。',60,'全唐诗/poet.song.237000.json','["晏坐圖畫出，銀屏列郡山。", "几案空水接，舟檝窗竇間。", "清風蕩炎瘴，異趣起懦頑。", "夢随白鷗去，静看飛鳥還。", "夜深忽聞笛，何處明月灣。"]'),
('42e584c1-af76-4a6a-8d11-29aa39f92b1d','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','翠節摩秋雲，朱轓映朝彩。',48,'全唐诗/poet.song.237000.json','["翠節摩秋雲，朱轓映朝彩。", "欣欣兩賓主，濟濟衆僚寀。", "此會良已希，斯文固應在。", "寂寞秋後香，今晨有人采。"]'),
('34df92c7-c0b0-4e37-b6bc-a0c2648f871d','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','結彼山下茅，對此山上瀑。',48,'全唐诗/poet.song.237000.json','["結彼山下茅，對此山上瀑。", "白日成蹉跎，長年抱幽獨。", "嚶嚶自禽鳥，踽踽亂樵牧。", "門巷何多車，山中有佳菊。"]'),
('95aeadbc-22e5-4110-9d99-c71ba32f1620','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其三','蒲壽宬','宋','宋诗','song-poetry','','[]','龍山在何許，驅車故城東。',48,'全唐诗/poet.song.237000.json','["龍山在何許，驅車故城東。", "壯遊值佳月，髙懐激清風。", "深知孟萬年，獨有柴桑翁。", "至今佳傳香，索之迷芳叢。"]'),
('12d33b5f-76da-40fa-a02f-e19eae6b3aa1','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其四','蒲壽宬','宋','宋诗','song-poetry','','[]','淡淡暮秋色，行行遶疎籬。',48,'全唐诗/poet.song.237000.json','["淡淡暮秋色，行行遶疎籬。", "最愛重九名，擬和柴桑詩。", "風流足千載，感慨彼一時。", "此日不易得，有酒安可辭。"]'),
('ca7fb9c3-7e95-4ddf-84eb-5d0c672abc7e','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其五','蒲壽宬','宋','宋诗','song-poetry','','[]','白露零髙寒，西風滿原野。',48,'全唐诗/poet.song.237000.json','["白露零髙寒，西風滿原野。", "濁酒歡重持，黄花笑盈把。", "詩句斐莫裁，秋容浩難寫。", "豈爲今日娛，逢之百世下。"]'),
('e812bc5e-0e40-4ecb-988c-8e04e5473cd7','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其六','蒲壽宬','宋','宋诗','song-poetry','','[]','晨策登青霞，衆峯鬱綢繆。',48,'全唐诗/poet.song.237000.json','["晨策登青霞，衆峯鬱綢繆。", "舉目嗟新亭，緬懐憶神州。", "酣觴氣磊磊，感物心悠悠。", "偉哉此二翁，髙風繼前修。"]'),
('782ce5b9-e9dc-428c-8ac7-5966114c874c','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其七','蒲壽宬','宋','宋诗','song-poetry','','[]','南陽有菊水，一掬清且鮮。',48,'全唐诗/poet.song.237000.json','["南陽有菊水，一掬清且鮮。", "滿潭浸秋色，餐英飲寒泉。", "將以壽道脉，非惟制頹年。", "豈不随衆草，正色乃自然。"]'),
('2028dbca-a6ac-444f-9161-30be2ab0c26b','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其八','蒲壽宬','宋','宋诗','song-poetry','','[]','百年豈非長，流光迅飛電。',48,'全唐诗/poet.song.237000.json','["百年豈非長，流光迅飛電。", "月渚愁賓鴻，風簷凄去燕。", "鴻燕胡獨乖，參辰豈相見。", "念此霜中英，良時不妨殿。"]'),
('f3ebf818-b659-4020-af91-bf4878945238','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其九','蒲壽宬','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬詎云逺，日日望翠嵐。',48,'全唐诗/poet.song.237000.json','["匡廬詎云逺，日日望翠嵐。", "黄花裛露掇，薄酒如飴甘。", "迢迢想髙遯，亹亹懐清談。", "緬睇良有以，舊居在其南。"]'),
('b323a5d7-e373-405f-a1e1-15ff521991a8','舶使王會溪太守趙見泰九日領客枉頋山中賦采菊東籬下悠然見南山韻十首  其一○','蒲壽宬','宋','宋诗','song-poetry','','[]','天台赤霞頂，峨眉翠雲間。',48,'全唐诗/poet.song.237000.json','["天台赤霞頂，峨眉翠雲間。", "人物自楚楚，文采何斑斑。", "屈宋豔何摘，陶謝髙可攀。", "咳唾随天風，萬古輝此山。"]'),
('a362765c-8188-4989-9d12-6cc8768baca4','九日簡留松澗','蒲壽宬','宋','宋诗','song-poetry','','[]','瀼瀼白露墜，獨起行遶籬。',120,'全唐诗/poet.song.237000.json','["瀼瀼白露墜，獨起行遶籬。", "豈泥兹晨游，偶諧昔人期。", "白衣已縹緲，幅巾自淋漓。", "舉杯泛寒榮，何以慰所思。", "登山極野望，涕泗空漣洏。", "戚戚霜葉語，鴈過鳴聲悲。", "參軍爾何事，帽側無人知。", "莫輕一時謔，貽此千載嗤。", "餐英飲沆瀣，政坐騷人癡。", "起酹彭澤翁，此意堪語誰。"]'),
('1a54131a-58c3-41f6-94c3-9bef270771fe','心泉','蒲壽宬','宋','宋诗','song-poetry','','[]','山泉不知源，流出石磊砢。',48,'全唐诗/poet.song.237000.json','["山泉不知源，流出石磊砢。", "坎止心維亨，蒙養行必果。", "久視空無塵，静趣自忘我。", "明月知此心，時印夜光顆。"]'),
('ad49f645-c1cd-4c32-8b58-1f641d42fe8c','九日貴客入山地狹不足以容歌舞故作','蒲壽宬','宋','宋诗','song-poetry','','[]','莫歌亂我蛩，莫舞踐我菊。',48,'全唐诗/poet.song.237000.json','["莫歌亂我蛩，莫舞踐我菊。", "歌不入此耳，舞適局汝足。", "蛩吟今古心，菊老貧賤屋。", "斟菊聽我蛩，絕勝人間曲。"]'),
('da3756fb-a1d7-46a3-9ab3-f398e8315c81','和漳浦余明府','蒲壽宬','宋','宋诗','song-poetry','','[]','割鷄薦鸞刀，飛鳬躡仙跡。',60,'全唐诗/poet.song.237000.json','["割鷄薦鸞刀，飛鳬躡仙跡。", "惠與清漳流，名髙魯山石。", "廉謙今所難，吾道幟可赤。", "作縣既有箴，救世豈無策。", "澗水疑鳴琴，中宵起人憶。"]'),
('c69fe2d5-6770-4d92-930a-819c05e10f07','呈大帥侍郎陽巖洪先生','蒲壽宬','宋','宋诗','song-poetry','','[]','猗桐擢新翠，况此當春陽。',132,'全唐诗/poet.song.237000.json','["猗桐擢新翠，况此當春陽。", "靈鳯何髙翔，豈不懐朝光。", "積陰既去屏，先鳴詎能忘。", "腐草倐已化，破柱安所藏。", "聲猷動寰海，偃蹇持孤芳。", "清風肅羽纛，白日成圭璋。", "久期薦清廟，欲與興頽綱。", "恩綸甫雜遝，符采相輝煌。", "元祐心可續，江左脉自長。", "精神夙聚會，賡歌藹明良。", "願整池上翼，繼我文靖梁。"]'),
('d7c2efcb-8320-4ac6-87a0-24881f9fa834','上舶使監丞王會溪','蒲壽宬','宋','宋诗','song-poetry','','[]','抗意欲窺奇，栖潛在郡帙。',108,'全唐诗/poet.song.237000.json','["抗意欲窺奇，栖潛在郡帙。", "猶疑甕爲天，豈信盲問日。", "清晨非夢寐，見此五色筆。", "寒光動斗牛，餘照堕圭蓽。", "目前千古在，吾故一日失。", "至道涵深純，大雅藏僴瑟。", "懐兹泉石心，賁之林野質。", "百年豈不短，萬羡從此畢。", "倘云可與語，敢憚行以膝。"]'),
('d616d219-e2c6-4f03-bd98-e57fd75f7fa2','登師姑巖見城中大閲恍如陣蟻因思舊從戎吏亦其中之一蟻感而遂賦','蒲壽宬','宋','宋诗','song-poetry','','[]','晨起捫層巔，蒼茫見塵市。',156,'全唐诗/poet.song.237000.json','["晨起捫層巔，蒼茫見塵市。", "鼙鼓生逺陴，壺蠭在幽耳。", "遥知細柳屯，于時閲軍士。", "俯彼萬鎧羣，微哉一窖蟻。", "初集如慕羶，俄擁如聚米。", "或圓如旋磨，或方如緣几。", "隠隠床下聲，牛鬬差可擬。", "未熟黄粱間，忽憶大槐裏。", "昔在羣蟻中，不知蟻是已。", "長揖謝孫穰，微笑辭翦起。", "蠻觸胡爲哉，鷄蟲今已矣。", "醉眼未醒時，此真尺與咫。", "更陟最上頭，須彌亦芥子。"]'),
('cda35317-9755-4aac-bae0-94bccc7f1eea','送郭濟叔分教邵陽','蒲壽宬','宋','宋诗','song-poetry','','[]','秋山多爽氣，南楚登修程。',84,'全唐诗/poet.song.237000.json','["秋山多爽氣，南楚登修程。", "豈無離别懐，此别人所榮。", "睠言紫帽秀，翹然碧流英。", "千載木鐸寄，一脉濓泉清。", "無氊不言寒，有道當自鳴。", "采芹發新謡，吟藥生逸情。", "汾陽昔何人，努力加令名。"]'),
('4ac4d6ad-2e53-4494-a881-0c7b8dad3126','古意答胡葦航','蒲壽宬','宋','宋诗','song-poetry','','[]','偃蹇當風松，四望無寧枝。',60,'全唐诗/poet.song.237000.json','["偃蹇當風松，四望無寧枝。", "蔦蘿空自纒，鸞鳳非所覊。", "固乏棟梁具，聊聳巖壑姿。", "豈無深林柯，百尺懸旌麾。", "下有千歲苓，勿使行人知。"]'),
('83e13271-6fcd-4823-a2c7-3c27e0627cf5','送逺曲别葦航','蒲壽宬','宋','宋诗','song-poetry','','[]','驅車晨出門，薄酒持送君。',48,'全唐诗/poet.song.237000.json','["驅車晨出門，薄酒持送君。", "離心一寸鐵，修嶺千重雲。", "遥憐風雨夜，應念霜雪羣。", "猿鶴豈敢怨，所期在斯文。"]'),
('dcf2c68e-8b2d-4b12-9fd3-24319cb734ca','見山臺','蒲壽宬','宋','宋诗','song-poetry','','[]','疊石生幽雲，層臺起脩竹。',60,'全唐诗/poet.song.237000.json','["疊石生幽雲，層臺起脩竹。", "羣山不出門，一日俱在目。", "逺眺極悠悠，男兒豈碌碌。", "寶匣長夜鳴，黄金幾時築。", "此事誰與論，掀髯對雲麓。"]'),
('ace5fd3d-82d1-4f36-964c-be050d48a881','泊舟蘭溪','蒲壽宬','宋','宋诗','song-poetry','','[]','江流萬古意，客遊邁中年。',72,'全唐诗/poet.song.237000.json','["江流萬古意，客遊邁中年。", "茫茫見逺樹，渺渺嘆逝川。", "旅舟泊明月，溪謳出長煙。", "千帆趣各異，萬里愁共煎。", "船頭有美酒，吹火煮小鮮。", "丈夫非無淚，不洒商婦絃。"]'),
('43debe53-70bb-40b7-97ae-c8949c9443fa','登師姑巖懐古十韻','蒲壽宬','宋','宋诗','song-poetry','','[]','郭中愛青山，推窗納青碧。',120,'全唐诗/poet.song.237000.json','["郭中愛青山，推窗納青碧。", "不見山中人，白雲自堆積。", "登睇廓悠悠，此眼亦已窄。", "但見寰中塵，不見塵中客。", "相去詎幾許，恍若萬里隔。", "日暮攀崔嵬，泫然感疇昔。", "蜀道無人行，嵩山絕蹄跡。", "豈無九回腸，安得雙飛翮。", "傾我百壺酒，撫此千丈石。", "不知蠟屐翁，著得幾量屐。"]'),
('9a37002c-2ee7-46f8-841b-64fcf7cb6fc9','仲冬下澣會同僚遊東巖','蒲壽宬','宋','宋诗','song-poetry','','[]','羽人脱屣去，古洞留嵌巖。',168,'全唐诗/poet.song.237000.json','["羽人脱屣去，古洞留嵌巖。", "白雲亦世態，随風蜕其緘。", "石飴已何許，誰能味其甘。", "土偶寂不語，樵牧同此龕。", "坎坎擊石鼓，歸去夸彼談。", "遂使蠟屐人，於此移其貪。", "猗桐植翠蓋，翳翳當薫南。", "琤然激石溜，燕坐心黙參。", "朝暮豈異理，莫誑狙四三。", "暄涼得其適，所訝非瘴嵐。", "梅花對白髪，風前雪鬖鬖。", "揮觴屬同僚，出語諧酸鹹。", "猶拘鐵漢語，飲之不至酣。", "託詩紀曾遊，誰將鐵爲庵。"]'),
('fd4cf95d-0976-49c7-bb80-d3d6621d47e9','寄豫章李明府','蒲壽宬','宋','宋诗','song-poetry','','[]','太白揺芒芒，只在西山陽。',48,'全唐诗/poet.song.237000.json','["太白揺芒芒，只在西山陽。", "常言欲千里，一夜千里長。", "酒盡還磊磈，出匣鳴干將。", "蘭菊猶有秋，白日安可量。"]'),
('18a4dffe-01fa-48fe-ab6c-f5781936870a','亦竹軒','蒲壽宬','宋','宋诗','song-poetry','','[]','娟娟竹上露，泠泠竹間風。',48,'全唐诗/poet.song.237000.json','["娟娟竹上露，泠泠竹間風。", "風露自髙潔，軒窗亦玲瓏。", "明月散清影，獨起行遶叢。", "緬懐愛竹人，氣味千載同。"]'),
('d33669f9-2333-4b84-ae1d-ae0d9f24e6a1','六和塔僧房','蒲壽宬','宋','宋诗','song-poetry','','[]','天風語簷鈴，蒼靄藏古殿。',96,'全唐诗/poet.song.237000.json','["天風語簷鈴，蒼靄藏古殿。", "穿竹逢緇衣，拈花對黄面。", "誰把山水心，爲我露一線。", "推窗古樹隙，空水還匹練。", "山色忽有無，潮來半空濺。", "須臾簸舟楫，木葉飛片片。", "魚鰕恣掀舞，洲渚入𤇊煉。", "山僧寂無言，千帆閲將徧。"]'),
('1833eb76-6914-41d1-8c46-eaec364f5683','送梅峯阮監鎮東歸','蒲壽宬','宋','宋诗','song-poetry','','[]','豪氣宇宙窄，健筆風雷驚。',48,'全唐诗/poet.song.237000.json','["豪氣宇宙窄，健筆風雷驚。", "處禈笑羣蝨，有酒甘步兵。", "半酣百年寄，一嘯千古輕。", "青眼能幾人，白首識此情。"]'),
('30c0135c-6c56-4581-a907-7035f5e19e8c','噴玉布','蒲壽宬','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蒼珉卧偃蹇，飛瓊潄潺湲。',48,'全唐诗/poet.song.237000.json','["蒼珉卧偃蹇，飛瓊潄潺湲。", "東野噴玉布，廬山谷簾泉。", "玉斧敲寒冰，随風走連卷。", "清聲足洗耳，枕流恐徒然。"]'),
('3e2ca8be-6b9d-40c9-b184-dfc68036b394','梅陽郡齋鐵菴梅花五首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','廣平一寸鐵，不信句鍊柔。',48,'全唐诗/poet.song.237000.json','["廣平一寸鐵，不信句鍊柔。", "猶疑雪月競，韜玉無處求。", "神人藐姑射，夜趁嫦娥遊。", "縹緲不可見，天風想琳璆。"]'),
('73d4d882-dc30-43fb-b0f7-3098bdf85c15','梅陽郡齋鐵菴梅花五首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','孤山隱君子，搜索入幻眇。',48,'全唐诗/poet.song.237000.json','["孤山隱君子，搜索入幻眇。", "方且判鴻濛，倐爾得一竅。", "童鶴俱不知，吟成忽自笑。", "翛然脱情塵，髙標立寒峭。"]'),
('b0605961-9207-4d71-a707-2a66ddeef733','梅陽郡齋鐵菴梅花五首  其三','蒲壽宬','宋','宋诗','song-poetry','','[]','江南擅名勝，雅愛陸敬風。',48,'全唐诗/poet.song.237000.json','["江南擅名勝，雅愛陸敬風。", "豈無可以贈，折枝寄郵筒。", "緘香不敢泄，千里一寸衷。", "對雪感歲暮，白頭謾西東。"]'),
('48025396-e3a8-41f9-aeb7-710251fcd6f1','梅陽郡齋鐵菴梅花五首  其四','蒲壽宬','宋','宋诗','song-poetry','','[]','卓哉誠齋老，驅車陟崔嵬。',48,'全唐诗/poet.song.237000.json','["卓哉誠齋老，驅車陟崔嵬。", "清風欲洗瘴，駕言爲花來。", "仰止冰玉人，念彼同根荄。", "思翁不可說，江邊重徘徊。"]'),
('593e5529-ed3f-4621-8743-38e87552c026','梅陽郡齋鐵菴梅花五首  其五','蒲壽宬','宋','宋诗','song-poetry','','[]','枯株類鐵漢，瘴瘧不敢侵。',48,'全唐诗/poet.song.237000.json','["枯株類鐵漢，瘴瘧不敢侵。", "歲寒葉落盡，微見天地心。", "陽和一點力，生意滿故林。", "至仁雨露澤，不覺淪肌深。"]'),
('0c9a6998-5c1f-47cd-90d6-a1ffc265e00e','萬壑清流','蒲壽宬','宋','宋诗','song-poetry','','[]','旨哉哲人語，有道親爲傳。',48,'全唐诗/poet.song.237000.json','["旨哉哲人語，有道親爲傳。", "清流出萬壑，千載此兩賢。", "誰傾六月雪，洗我一片天。", "妙趣不可極，如此山中泉。"]'),
('fbddc8bf-97e4-4ed2-9236-34f98b033fd7','白水巖','蒲壽宬','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山有積霤，坤媪乃善藏。',240,'全唐诗/poet.song.237000.json','["泰山有積霤，坤媪乃善藏。", "何時發靈祕，一脉流膏滂。", "至仁及物意，後世疑濫觴。", "螭蟠久懶卧，辟易離電光。", "豐隆亦豪舉，夜半驅阿香。", "天鼓何處來，大雪驚飄揚。", "飛星雜雨射，怒雹翻飊狂。", "倚欄兩眼眩，應接俱弗遑。", "吕梁三十仭，吾聞老蒙莊。", "行歌不憚險，習坎守故常。", "峨眉有仙伯，佛迹窺荒唐。", "濯足弄海月，戲侮相頡頏。", "堪笑失筯人，氣骨何羸尫。", "醉呼李太白，欲製芙蓉裳。", "此泉願爲酒，萬斛輸滄浪。", "簡寂耿我夢，九疊迂我腸。", "鴈蕩更詭異，龍湫舞堂堂。", "何當寄鵬翼，瞬息天一方。", "仙人笑擘脯，滄海觀種桑。", "人世彈指頃，萬古天地長。"]'),
('f022e0ae-bd41-4534-a522-fab2db82f2ba','戯効浪仙體','蒲壽宬','宋','宋诗','song-poetry','','[]','碌碌復碌碌，世事安可卜。',48,'全唐诗/poet.song.237000.json','["碌碌復碌碌，世事安可卜。", "馬蹶輕四蹄，夔行矜一足。", "知守吾轍難，遑問羊腸曲。", "行行復何之，幽人在空谷。"]'),
('ea3b3437-1834-430b-879d-6cb0a6048c84','書會溪郴陽瀑布圖後三首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','山椒斫寒翠，澗曲披玄圖。',36,'全唐诗/poet.song.237000.json','["山椒斫寒翠，澗曲披玄圖。", "寫此一派潤，化作萬頃腴。", "誰知田中禾，粒粒心上珠。"]'),
('9eaaec14-cc7c-4c91-8a35-b5d6510a4b4a','書會溪郴陽瀑布圖後三首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','楚山亦瘴癘，湘水多幽靈。',36,'全唐诗/poet.song.237000.json','["楚山亦瘴癘，湘水多幽靈。", "髙飈雷電激，盡日霰雪零。", "滌去熱惱腸，清風自泠泠。"]'),
('b39d8d6a-d638-46f1-978a-cfa957caff98','書會溪郴陽瀑布圖後三首  其三','蒲壽宬','宋','宋诗','song-poetry','','[]','千山六月火，可使金石然。',36,'全唐诗/poet.song.237000.json','["千山六月火，可使金石然。", "懐兹水一滴，想彼心千年。", "願君倒天瓢，流澤無中邊。"]'),
('8c5ba601-9039-429a-ba8e-6c701cd649ed','草堂瀑布','蒲壽宬','宋','宋诗','song-poetry','','[]','西瞻香爐氣，北望鍾山英。',96,'全唐诗/poet.song.237000.json','["西瞻香爐氣，北望鍾山英。", "寧如坐巖曲，飛玉光欄楹。", "異哉天地秀，孕此冰雪精。", "梅花立其旁，姑射凌寒清。", "仙帔月耿耿，神珮風琤琤。", "窗户六月冷，草木三冬榮。", "錦水懐少陵，銀河照長庚。", "所嗜固不同，聊復娛吾生。"]'),
('34c8a453-dbfe-47bc-9733-4bc4781806ba','題瀑布圖後','蒲壽宬','宋','宋诗','song-poetry','','[]','平生託游從，林野乃其趣。',192,'全唐诗/poet.song.237000.json','["平生託游從，林野乃其趣。", "出處偶不同，清濁良已忤。", "解組浣我塵，叩門爲君訴。", "方殷岐黄事，何日當展晤。", "欲潄巖下泉，蛩驉念同路。", "黙携照膽鏡，歴歴見情愫。", "韋韠誰爲驅，千林瀉懸布。", "初掛冰一簾，晶晶滴珠露。", "弄電不輟笑，轟谷激電怒。", "玉虬擘重崖，白晝雲雪互。", "震掉若弗容，俄然脱沉痼。", "寂寂霜林鐘，茫茫虎溪渡。", "草堂香山基，興廢今幾度。", "誅茅詎爲晚，千古一旦暮。", "與君共兹圖，濯濯如振鷺。", "登眺晨百回，疇能局髙步。"]'),
('5627c2a7-8b9b-43fd-9511-4f12316be573','中庭步月','蒲壽宬','宋','宋诗','song-poetry','','[]','月光被中庭，竹影弄幽色。',48,'全唐诗/poet.song.237000.json','["月光被中庭，竹影弄幽色。", "瀟瀟一幅素，灑灑數莖墨。", "忽然風動處，惟有月寫得。", "此畫應入神，無言自心識。"]'),
('2fd077ac-1c5f-4709-8c14-f7b9abe532e3','純陽洞讀書和中山陳禮郎韻','蒲壽宬','宋','宋诗','song-poetry','','[]','弄珠寄南海，移文譏北山。',132,'全唐诗/poet.song.237000.json','["弄珠寄南海，移文譏北山。", "出處雖異位，夢覺同一闗。", "純陽有真境，古洞扄林端。", "絕頂象緯逼，六月天氣寒。", "道人討幽勝，誅茆謀盖棺。", "緣深野鷄狎，供罷齋魚閒。", "斗軒適容膝，點勘酬鈆丹。", "理義貴自得，神仙諒非難。", "嗟我久荒索，摧心罹棘艱。", "羞羡鶴俯仰，空悲馬班桓。", "終南在何許，得去何須還。"]'),
('8668f562-5484-41eb-8ef5-2db06c1c25e6','又題純陽洞','蒲壽宬','宋','宋诗','song-poetry','','[]','十里捫藤蘿，千崖插虛碧。',120,'全唐诗/poet.song.237000.json','["十里捫藤蘿，千崖插虛碧。", "仰覺雲漢低，俯見塵市窄。", "小山走委蛇，逺水别支脉。", "身騎鷦鷯枝，目眇大鵬翮。", "更有千載人，幽巖蜕空魄。", "朝躡一片雲，夜嘯百丈石。", "我疑真人去，留此守劍舄。", "道人既無心，何事苦著跡。", "我有一壺酒，起舞酹仙伯。", "松槿雖殊途，宇宙同作客。"]'),
('a1147ba7-3a48-43b0-aa55-c70a3eb3c7e8','枸杞井','蒲壽宬','宋','宋诗','song-poetry','','[]','四時可以採，不採當自榮。',48,'全唐诗/poet.song.237000.json','["四時可以採，不採當自榮。", "青條覆碧甃，見此眼已明。", "目爲仙人杖，其事因長生。", "飲此枸杞水，與結千歲盟。"]'),
('c8da1ee0-cb9e-4c7f-920b-b8a0ff016b6e','山中井','蒲壽宬','宋','宋诗','song-poetry','','[]','乾元肇初氣，坤母乃六之。',120,'全唐诗/poet.song.237000.json','["乾元肇初氣，坤母乃六之。", "誰明爻象意，鑿出混沌奇。", "所以擊壤民，飲水源不知。", "空山有古甃，夜氣方歸時。", "明月照我牖，獨起携軍持。", "一瓢飲沆瀣，凉意生肝脾。", "下以澆丹田，上以滋華池。", "瀟然脱塵土，舉身入希夷。", "神人授我訣，欲以療我饑。", "歸來煮白石，精饌瓊爲糜。"]'),
('4f625508-6102-4cc9-9bfe-50240a2245f2','菊花潭','蒲壽宬','宋','宋诗','song-poetry','','[]','何處無甘菊，何處無清泉。',48,'全唐诗/poet.song.237000.json','["何處無甘菊，何處無清泉。", "菊泉適相值，天地何嘗偏。", "豈但爲九日，可以踰百年。", "願與潭下村，餐英汲潺湲。"]'),
('81ed694f-a03a-4e1d-ade4-fab214fed924','古意','蒲壽宬','宋','宋诗','song-poetry','','[]','梳鬟照寒泚，寒泚知貞胸。',72,'全唐诗/poet.song.237000.json','["梳鬟照寒泚，寒泚知貞胸。", "整鬟摘秋芳，秋芳無冶容。", "平生？偃蹇，今逐梁君鴻。", "既甘布裙績，寧厭短褐舂。", "剔目信已篤，刲耳何所從。", "獨撫箜篌謡，河流自潨潨。"]'),
('d7b68f55-e8ab-4d86-b334-82ba9a40b51d','頭陀成菴主刺血寫法華經','蒲壽宬','宋','宋诗','song-poetry','','[]','丹書何切切，滴心不滴血。',48,'全唐诗/poet.song.237000.json','["丹書何切切，滴心不滴血。", "縱使血可乾，其如心不竭。", "蜀鳥啼作花，至今萬山纈。", "殺身以成仁，遺訓有先哲。"]'),
('62bcfd8f-7d4d-4d71-bc13-dcecce827701','燈蛾','蒲壽宬','宋','宋诗','song-poetry','','[]','出暗亦已顯，傅翼乃不任。',36,'全唐诗/poet.song.237000.json','["出暗亦已顯，傅翼乃不任。", "趨炎弗知止，倐忽遊燧林。", "不見異域傳，乃有噉火禽。"]'),
('9026ae09-c8f6-4a1c-856a-ed49d94816c4','蜜蜂','蒲壽宬','宋','宋诗','song-poetry','','[]','四時有佳卉，兩股不停探。',36,'全唐诗/poet.song.237000.json','["四時有佳卉，兩股不停探。", "花露本清冽，安用如許甘。", "平生事苦口，氣味轉不諳。"]'),
('3d949391-d18b-4e35-913d-832bf483a8a2','蜘蛛','蒲壽宬','宋','宋诗','song-poetry','','[]','輕絲出皤腹，口織不用梭。',36,'全唐诗/poet.song.237000.json','["輕絲出皤腹，口織不用梭。", "前身豈虞人，所食在網羅。", "茆欄亦可罥，如此豸者何。"]'),
('8cbfa103-8ebf-4c9c-8045-77b15cc1079e','促織','蒲壽宬','宋','宋诗','song-poetry','','[]','炎夏居壁根，凉秋噪籬側。',36,'全唐诗/poet.song.237000.json','["炎夏居壁根，凉秋噪籬側。", "安得懶婦名，豈其曠乃職。", "不念作繭勞，徒能促人織。"]'),
('02c2ce9c-d0d4-4056-8671-bafbe857b285','蟻','蒲壽宬','宋','宋诗','song-poetry','','[]','玄駒不可縶，若象寜無端。',36,'全唐诗/poet.song.237000.json','["玄駒不可縶，若象寜無端。", "南柯二十載，夢覺指一彈。", "誰云丘垤微，轉覺天地寛。"]'),
('d715a7d2-3264-4d77-b313-9b0dbccc133a','蠧魚','蒲壽宬','宋','宋诗','song-poetry','','[]','種芸豈辟蠧，無水乃有魚。',36,'全唐诗/poet.song.237000.json','["種芸豈辟蠧，無水乃有魚。", "平生破萬卷，胸次藏石渠。", "何如葉上蟲，篆出先秦書。"]'),
('5625114f-bcff-4359-b273-375140d5b0a6','捫蝨','蒲壽宬','宋','宋诗','song-poetry','','[]','上即居人頭，下即居人身。',36,'全唐诗/poet.song.237000.json','["上即居人頭，下即居人身。", "夙豈爲人食，今乃務食人。", "不必勞爪掐，聊以捫對賓。"]'),
('fa9b2959-fa69-4449-bad6-f2d49be5f422','蚊二首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','白日沿溝渠，中宵隱堂奥。',36,'全唐诗/poet.song.237000.json','["白日沿溝渠，中宵隱堂奥。", "觸處招燎烟，幾人有良幬。", "眶睫知若何，口觜有計暴。"]'),
('d895426c-a828-4ed8-9de0-c5a65bd13f21','蚊二首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','晝伏夜已動，血人謀其生。',108,'全唐诗/poet.song.237000.json','["晝伏夜已動，血人謀其生。", "不作林中虎，而爲帳下虫。", "饑虎有時逢，林密少人行。", "微物不可忽，羣聚成雷轟。", "衆觜錐刀鋩，矮屋甑釜烹。", "膚爪良自忤，扇撲勞迭更。", "下車摶猛虎，一死政自輕。", "纎纎無所詰，長夜不肯明。", "爲我驅蜚廉，么麽一掃清。"]'),
('f81d443b-18d5-406d-9716-2c45c5b878cd','蚤','蒲壽宬','宋','宋诗','song-poetry','','[]','疾跳若幻術，常笑蝨縫拘。',36,'全唐诗/poet.song.237000.json','["疾跳若幻術，常笑蝨縫拘。", "動致磨齒牙，害止搔皮膚。", "纎芥何足云，有人飼於菟。"]'),
('dfb7d229-5b03-4b4c-8d4f-4418fc248dbf','神駿歌送趙委順就漕','宋蒲壽宬','宋','宋诗','song-poetry','','[]','神駿不受羈，豈知日千里。',112,'全唐诗/poet.song.237000.json','["神駿不受羈，豈知日千里。", "小試秋風前，爍爍電光起。", "何須金絡腦，不用珊瑚鞭。", "徐看血汗沫，透出青連錢。", "飛去度赤水，横行抹燕山。", "持歸獻天子，髙列十二閑。", "渴飲水底月，饑餐草頭珠。", "輕揺玉麈尾，側碾青氍毹。", "振鬛長鳴謝伯樂，千秋萬古八駿圗。"]'),
('fda3c168-8267-4857-84a7-096baf474fa9','子别母呈所翁陳先生','宋蒲壽宬','宋','宋诗','song-poetry','','[]','子别母，欲别牽衣意何苦。',112,'全唐诗/poet.song.237000.json','["子别母，欲别牽衣意何苦。", "母有衆兒俱母憐，兒無别母兒誰乳。", "海惡寧匪蛟，山饕莫如虎。", "小大不相棄，髙深自爲扈。", "萬古天地中，何得如母所。", "披絮成踟蹰，履霜正凄楚。", "不見城上烏，相隨八九子。", "反哺何足云，慈烏乃如此。", "引翼且莫髙，短翅將千里。"]'),
('a2f873fe-b95c-4e84-940d-7d23e780adc3','醉歌','宋蒲壽宬','宋','宋诗','song-poetry','','[]','有人八百歲，作鬼三千年。',220,'全唐诗/poet.song.237000.json','["有人八百歲，作鬼三千年。", "如此豈不夭，或者稱其綿。", "大椿一春秋，爲歲各八千。", "久矣摧爲塵，朝菌猶目前。", "燕坐一息頃，直到羲農邊。", "誰謂未來事如漆，未來龜鏡已在先。", "天地一指掌，日月雙跳丸。", "摶沙小兒戯，滄海爲桑田。", "南華達生亦已死，伯倫半醉不是顛。", "讀書堂上眼如月，輪扁釋鑿乃囅然。", "髙車本桎梏，更被繩墨牽。", "利澤苟未諧，仁義空自煎。", "有客區區老山澤，不鳴不食稱神仙。", "呼來飲酒不肯飲，月明騎鶴遊青天。", "舉杯邀明月，舞影各自憐。", "必求至樂何者爲至樂，今也不樂何用空拳拳。"]'),
('5af3437d-fac4-4c63-85e2-46c848adb35e','菊露謡','宋蒲壽宬','宋','宋诗','song-poetry','','[]','清晨採黄菊，露滴露花叢。',52,'全唐诗/poet.song.237000.json','["清晨採黄菊，露滴露花叢。", "黄花泣白露，白露晞秋風。", "秋風莫相試，菊薤心不同。", "薤露明朝落不落，黄華獨老秋風中。"]'),
('e3de88c2-77b1-4309-9cb3-9ca13a8dade4','送劉童子試藝天京','宋蒲壽宬','宋','宋诗','song-poetry','','[]','磽磽頭角出羣玉，炯炯瞳人剪秋漪。',176,'全唐诗/poet.song.237000.json','["磽磽頭角出羣玉，炯炯瞳人剪秋漪。", "神光現作照書月，一覽千古無復遺。", "殊科自可獻上國，况能文藝超等夷。", "河洛圗書識藴奥，更明爻象通神蓍。", "陣分八勢演古法，操弓挾矢動有儀。", "眼前大要固如此，有人頭白俱不知。", "當今所重不在寶，弓旌聘召方四馳。", "豈無古人已成筭，時乖事異難設施。", "秋風邊塵浩無際，綸巾羽扇思見之。", "終軍棄繻繻尚在，劉晏正字字或欹。", "終身願秉清忠節，芳猷可繼大年詩。"]'),
('3002acb9-352c-4ce7-a802-13a07e043681','送沈保叔國諭試藝右庠','宋蒲壽宬','宋','宋诗','song-poetry','','[]','讀書讀心不讀跡，以言易言竟何益。',163,'全唐诗/poet.song.237000.json','["讀書讀心不讀跡，以言易言竟何益。", "射弓射志不射箭，以力假力何足羡。", "因蹄得兔蹄安用，以虎視石虎則中。", "設科取藝良已拘，分毫得失如摴蒱。", "微官况復多繩墨，千里思馳困羈勒。", "生女嫁屬他人屋，生男不出出許國。", "堂堂八尺無創瘢，如斗金印梔蠟顔。", "一條秋水持贈君，腰間願看生風雲。", "君不見唐家將相婁師德，也曾應詔紅抹額。", "撾鐘飲酒皆兒嬉，握拳透爪真男兒。"]'),
('45bf74c1-f402-408e-b503-a7e6b22e7f79','君不來詞寄雲帽上人梅坡翁','宋蒲壽宬','宋','宋诗','song-poetry','','[]','君不來，山中底事堪嫌猜。',56,'全唐诗/poet.song.237000.json','["君不來，山中底事堪嫌猜。", "積雨愁人不可道，至今聲跡何寥哉。", "竹風微動攬衣起，使我一日腸九回。", "君不來，門前日日添蒼苔。"]'),
('bdc5e0b1-ba87-4d9d-bdf9-de460e63a4fe','送林城山歸上饒','宋蒲壽宬','宋','宋诗','song-poetry','','[]','平生喜誦城山句，一誦千回起狂慕。',208,'全唐诗/poet.song.237000.json','["平生喜誦城山句，一誦千回起狂慕。", "夢魂夜夜峨眉巔，峨眉只在家西住。", "照人樓蜃嘘青紅，落筆天虬走雲霧。", "冥搜古髓生潤芳，坐演正聲入韶濩。", "蘭宫璧水俱雋功，金馬玉堂豈迂歩。", "何人爲呌閶闔雲，試使琅玕一披露。", "男兒豈暇謀温飽，丹心要使輝青素。", "水潮方仰昌黎韓，日邊又起長沙傅。", "玉山萬仞髙岧嶤，叢玉琤琤悦朝暮。", "嗟哉精衛愚復愚，海石悠悠力安措。", "傍人齲齒看癡狂，持此癡狂向誰訴。", "古來離别惟有酒，此别情酸酒如醋。", "萍蓬萬里終有家，而今更把家爲路。"]'),
('94993b4f-9854-41bb-beca-a6794343de97','送孫耕山','宋蒲壽宬','宋','宋诗','song-poetry','','[]','梅落癡風寒贔屭，海鴈驚春動歸思。',64,'全唐诗/poet.song.237000.json','["梅落癡風寒贔屭，海鴈驚春動歸思。", "蹇驢石磴空踟蹰，黄犢青山勞夢寐。", "千載休疑潄石訛，幾人堪說種瓜事。", "南州髙士不可攀，俗吏空餐抱深媿。"]'),
('6f95f592-5151-4b97-8dc1-8b543af688b9','贈日者馮鼎山','宋蒲壽宬','宋','宋诗','song-poetry','','[]','馮君胸中爛星斗，測人窮達誰與偶。',160,'全唐诗/poet.song.237000.json','["馮君胸中爛星斗，測人窮達誰與偶。", "得錢便據青旗亭，北斗還堪把漿酒。", "醉來訪我梅花傍，索飲哦詩恣狂吼。", "平生許予皆公侯，大軸長篇玩盈手。", "不言于麓神仙人，泣雨滂沱氣填口。", "與君生長醉鄉國，借箸前籌爲君剖。", "東坡固類韓昌黎，伯倫何如畢吏部。", "何處有酒三百壺，姓字甘書酒人簿。", "畏死安能抱仁義，貪生不解推子午。", "酒星此去住何宫，相從且作糟丘主。"]'),
('1ba85265-f86a-46bd-96fa-acf5fe073ada','濯足瀑下','宋蒲壽宬','宋','宋诗','song-poetry','','[]','石峽轟轟作雷吼，白虹飛趨電光走。',80,'全唐诗/poet.song.237000.json','["石峽轟轟作雷吼，白虹飛趨電光走。", "老蛟攪起陰壑藏，電雪當空射瓊玖。", "禪僧倚錫疑欲飛，兒童驚呼不停口。", "山夫伸足承下沫，陰風凛凛生毛髪。", "雨飛如箭任不知，旁人休猜鐵爲骨。"]'),
('86510a87-79a7-4332-8afa-036d41ab973d','壯哉亭觀龍湫作','宋蒲壽宬','宋','宋诗','song-poetry','','[]','雪車冰柱劉义狂，玉川更與相頡頏。',204,'全唐诗/poet.song.237000.json','["雪車冰柱劉义狂，玉川更與相頡頏。", "車聲羊膓幾盤折，飛冰走雪何茫茫。", "天公矜此老怪物，六丁直下白晝驅阿香。", "豐龍列缺一時起，千車百柱摧靡靡。", "玉蚪銀闕掀霜髯，藥兔蟾宫擣瑶髓。", "濤驚浪駭不可摹，璧碎珠傾詎堪擬。", "長風吹雨一座寒，兒童不敢正面看。", "狂客何心助鼓譟，磽田萬頃思波瀾。", "被髪行歌愜狂想，寶華天雨寧専賞。", "炎天上火下如湯，一派清泠浹隣壤。", "勸君飲酒君莫疑，有酒不飲吾何痴。", "夜光魚目紛紛雜錯烏可辨，眼中如露如電醉來大笑俱不知。"]'),
('5ed5d3c4-3b3b-4073-aa97-48748d79a444','登北山真武觀試泉','宋蒲壽宬','宋','宋诗','song-poetry','','[]','莫誇陽羡茗，在彼山之巔。',238,'全唐诗/poet.song.237000.json','["莫誇陽羡茗，在彼山之巔。", "莫誇惠山溜，試此山之泉。", "不生陸鴻漸，渴死盧玉川。", "且共春風裏，不鬬社雨前。", "雀舌最嫩弱植耳，嘉樹一發如針然。", "靈苗合讓武夷貢，清香不與羅浮専。", "北山古丘神所授，以泉名郡天下傳。", "置郵縱可走千里，不如一掬清且鮮。", "人生適意在所便，物各有産盡隨天。", "蹇驢破帽出近郭，裹茶汲井手自煎。", "泉鮮水活别無法，甌中沸出酥雪妍。", "山中道士不識此，彈口咋舌稱神仙。", "從今决意修茗事，典衣買樹蒔井邊。", "道士且莫顛，古人作善戒所先。", "山中種茶一百頃，不如山下數畆田。", "饑餐渴飲無長物，何患敲門驚晝眠。"]'),
('391291ef-6c69-4f6b-9b6c-09a8c5773f68','遊金山寺呈茂老','宋蒲壽宬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江氣勢何雄雄，波心幻出青蓮宫。',304,'全唐诗/poet.song.237000.json','["長江氣勢何雄雄，波心幻出青蓮宫。", "江流萬古浮不去，疑有根蒂誰能窮。", "遡流逺見一培塿，傳聞壯觀疑談空。", "風帆漸迫驚詭異，金碧還遶深蒙茸。", "小船破浪與客去，繫纜階石穿玲瓏。", "門前筆架水面立，波濤日夕相撞舂。", "重樓複道費登陟，面面奇怪陡不同。", "丹徒西望聳觀閣，淮海大塊居其東。", "倚欄簷外水轉窄，飛鴻没處明雙瞳。", "與僧煮茗話今古，莫窮幻眇窺鴻濛。", "瀛洲方丈在何許，騎牛覔牛休憧憧。", "遥指危檣夜泊處，驚飈飄簸如飛蓬。", "禪闗深閉浪打屋，夜定不動猜遊龍。", "清遊適值九月九，汲泉細摘黄花叢。", "水上登髙復誰信，證明頼有今逺公。", "登堂恍惚見坡印，瓣香起敬仙佛蹤。", "想像形容記言語，涕零心惻生不逢。", "未窮清興下山去，扁舟一瞬在閬風。", "作詩聊復紀遊跡，來尋此跡何時重。"]'),
('36be5a1f-7b08-4ba5-81ea-bc74e71d564f','遊西巖','宋蒲壽宬','宋','宋诗','song-poetry','','[]','誰扇洪爐欲煮鐵，一寸如冰不曾熱。',161,'全唐诗/poet.song.237000.json','["誰扇洪爐欲煮鐵，一寸如冰不曾熱。", "歲寒心事梅花知，炭事如何與冰說。", "西巖結屋煙作罩，斑斑不露如隐豹。", "人生大欲剛斷除，静處生涯乃仁樂。", "碧梧翠竹呈如琅玕，寒泉玉佩鳴珊珊。", "終焉爲計亦不惡，豈知白日生羽翰。", "翻思一夜鐘鳴時，先生髙臥如希夷。", "何人更嗔瘴鬼瘧，及鋒而用皆驚疑。", "薦泉采菊想遺跡，奚其與侣昌黎伯。", "薫蕕已定人所知，聊把曾遊紀巖石。"]'),
('49ecd3da-de0b-45ff-aadf-b6557dac1f42','書草屋壁','宋蒲壽宬','宋','宋诗','song-poetry','','[]','天地無終窮，萬物乃芻狗。',192,'全唐诗/poet.song.237000.json','["天地無終窮，萬物乃芻狗。", "勿誇杏爲梁，何如甕作牖。", "昔聞巢氏民，仁義亦奚有。", "蠢蠢不識知，居居自醇厚。", "今來豐屋士，文法困繩紐。", "力競蝜蝂蟲，計生養狙叟。", "誰家甲第巍入雲，何人鶉衣不掩肘。", "豈知鬼瞰因高明，安得春陽到窮蔀。", "蝸廬能幾何，蠻觸勝亦負。", "憶我柴桑翁，荒宅十餘畝。", "草屋八九間，柴門五株柳。", "野水滋粳𥺌春畦，足葱韮永日。", "爲琴書停雲，念親友儀秦。", "枉饒舌施龍，漫多口白衣。", "蒼狗安可知，不夷不惠自可否。"]'),
('afe4ce20-e5c9-47bf-99b6-3215611eec0b','愁劇忽失笑','宋蒲壽宬','宋','宋诗','song-poetry','','[]','愁劇忽失笑，不覺心夷然。',68,'全唐诗/poet.song.237000.json','["愁劇忽失笑，不覺心夷然。", "量珠成斗笑不賣，鎔金爲海愁不煎。", "蜜蜂與蓼蟲，生死甘苦緣。", "今也不爲樂，人有幾百年。", "士龍莫笑跌落水，水中不著此笑仙。"]'),
('021834bf-4f71-4721-8d1f-c962307882c1','九日','宋蒲壽宬','宋','宋诗','song-poetry','','[]','芙蓉披靡秋水寒，呉姝越艷芳思單。',64,'全唐诗/poet.song.237000.json','["芙蓉披靡秋水寒，呉姝越艷芳思單。", "漫把黄花事佳節，黄花不入歌舞歡。", "昔人戲馬足強健，今我無酒空巑岏。", "黄花無言不可詰，青山落日明歸翰。"]'),
('315ca0dc-05d7-41d3-a0b2-209803b3888e','糾之官莆陽','蒲壽宬','宋','宋诗','song-poetry','','[]','荷槖藹諸孫，英英列戟門。',48,'全唐诗/poet.song.237000.json','["荷槖藹諸孫，英英列戟門。", "能聲家有譜，清識郡無寃。", "松影旌旗道，梅花玉雪村。", "親庭兩驛便，時得問凉暄。"]'),
('0e5e2e60-b9fa-41d0-92c4-ea8669289f3a','歲暮度朋山嶺登山庵追慕先人不勝悲愴因用楊敬夫韻','蒲壽宬','宋','宋诗','song-poetry','','[]','歲寒霜露感，况復度髙深。',48,'全唐诗/poet.song.237000.json','["歲寒霜露感，况復度髙深。", "雲木猶如此，苔磯不忍臨。", "溪流一線碧，門對兩山岑。", "含涕危亭曲，遺言尚可尋。"]'),
('91ba6511-3fb3-4621-97af-ae2fc3964bc5','友人若木余兄告歸詩以送之','蒲壽宬','宋','宋诗','song-poetry','','[]','兩年遊海國，一半在山扉。',48,'全唐诗/poet.song.237000.json','["兩年遊海國，一半在山扉。", "政喜沙鷗狎，忽驚遼鶴歸。", "苦吟黄葉落，凝睇白雲飛。", "志已堅親養，難分薜荔衣。"]'),
('4b727d7c-3ea5-41e5-a1ef-bd5209c38284','寄徑山書記悟上人','蒲壽宬','宋','宋诗','song-poetry','','[]','人間傳妙語，塵外更深藏。',48,'全唐诗/poet.song.237000.json','["人間傳妙語，塵外更深藏。", "寢食因吟廢，形骸欲坐忘。", "瘦林秋見鶴，斷磬夜聞螿。", "出定生幽思，窗虚月在廊。"]'),
('4558c6af-db64-441d-ab0e-852a35fabeb1','寄思溪老藏叟珍上人','蒲壽宬','宋','宋诗','song-poetry','','[]','萬折苕溪水，精廬若箇邊。',48,'全唐诗/poet.song.237000.json','["萬折苕溪水，精廬若箇邊。", "菰菱時入供，包錫暮行船。", "月朗無雲夜，鵰横欲雪天。", "了知身是客，莫負故山緣。"]'),
('c07fc81b-f1fd-495a-a9cd-7c4ae81d9387','寄老溪上人','蒲壽宬','宋','宋诗','song-poetry','','[]','已知山是石，掛起碧笻條。',48,'全唐诗/poet.song.237000.json','["已知山是石，掛起碧笻條。", "家在黄梅樹，門當獨木橋。", "寡交因犬惡，黙坐聽蟬調。", "同道何時過，心慵不見招。"]'),
('287c20b4-68f7-4e01-895a-606fb61bef97','招枯崖悟上人住山','蒲壽宬','宋','宋诗','song-poetry','','[]','山僧如病鶴，意氣獨離羣。',48,'全唐诗/poet.song.237000.json','["山僧如病鶴，意氣獨離羣。", "思共孤峯月，閒分半榻雲。", "井華晨起汲，瀑布夜深聞。", "相向無言說，窗間草木欣。"]'),
('25282838-43ed-4613-ae3b-7722040b9e9c','和胡竹莊韻','蒲壽宬','宋','宋诗','song-poetry','','[]','脱落皮毛盡，而今腸亦無。',48,'全唐诗/poet.song.237000.json','["脱落皮毛盡，而今腸亦無。", "泣非緣楚玉，聲不叶齊竽。", "舉目雲天迥，論心水月孤。", "祇應飲美酒，跳入費公壺。"]'),
('dd57206c-cf22-4d08-8b73-e1d95e917490','次清老弟韻','蒲壽宬','宋','宋诗','song-poetry','','[]','恐負東風約，清唫野歩遲。',48,'全唐诗/poet.song.237000.json','["恐負東風約，清唫野歩遲。", "淡烟楊柳外，微雨海棠時。", "逺寄千杯緑，多情兩鬢絲。", "閒愁須遣盡，蜂蝶不堪覊。"]'),
('f0e36aa5-760f-41c2-85d6-5b54e300aa8e','趙委順寄詩山中因次韻','蒲壽宬','宋','宋诗','song-poetry','','[]','欲言誰與共，冉冉日還斜。',48,'全唐诗/poet.song.237000.json','["欲言誰與共，冉冉日還斜。", "繞郭多春樹，隔江生暮霞。", "滿堤吹柳絮，一舸汎桃花。", "唯愛鯿魚美，垂緡傍古槎。"]'),
('1ff9a3a1-2168-4bf8-a56d-4d603655d58f','題梅窗嘯月圖','蒲壽宬','宋','宋诗','song-poetry','','[]','梅花紙帳夢，耿耿欲宵殘。',48,'全唐诗/poet.song.237000.json','["梅花紙帳夢，耿耿欲宵殘。", "何處幽人嘯，一窗明月寒。", "素光流肺腑，清響動巖巒。", "擁膝無言語，歸來意自歡。"]'),
('7f197043-2f1d-4c94-bcf1-29db60aa50cf','贈隠者','蒲壽宬','宋','宋诗','song-poetry','','[]','自是山林僻，何心與世踈。',48,'全唐诗/poet.song.237000.json','["自是山林僻，何心與世踈。", "土鐺三合米，竹牖半床書。", "月樹迷歸鶴，沙泉數過魚。", "無人覔巢許，不必更深居。"]'),
('1d9f8cfc-5e7e-47cb-b221-da8ec7ac6538','挽吕秘書','蒲壽宬','宋','宋诗','song-poetry','','[]','玉階空憶去，破屋古梅旁。',48,'全唐诗/poet.song.237000.json','["玉階空憶去，破屋古梅旁。", "猶訝黯言直，不磨遷史良。", "葵心猶白髮，槐夢落黄粱。", "最後龍門客，恩深涕泗滂。"]'),
('2bbb9985-6c73-4fd4-9124-2583ea828c19','悼亡','蒲壽宬','宋','宋诗','song-poetry','','[]','百歲期偕老，半生塵夢訛。',48,'全唐诗/poet.song.237000.json','["百歲期偕老，半生塵夢訛。", "方諧委畚事，忍作鼓盆歌。", "野水悲蘋藻，秋風泣薜蘿。", "青燈課子誦，此意念君多。"]'),
('037e3cbd-c264-4acd-a959-ed2c31ce828c','小兒生日','蒲壽宬','宋','宋诗','song-poetry','','[]','今年二十八，細憶始生時。',48,'全唐诗/poet.song.237000.json','["今年二十八，細憶始生時。", "漸喜山多樹，尤憐水滿池。", "相寛吾老大，自教爾童兒。", "佛誕明朝是，然香共展眉。"]'),
('9a640eaf-e03a-4f35-9d79-f9ea771d2d26','贈日者王談天','蒲壽宬','宋','宋诗','song-poetry','','[]','問天天不言，君更欲談天。',48,'全唐诗/poet.song.237000.json','["問天天不言，君更欲談天。", "只且話明日，豈須窮百年。", "已靈機石事，猶夢蟻柯邊。", "爲扣希夷老，如何尚愛眠。"]'),
('29d76608-58d4-4626-b9da-80f2bed0a7d6','阿助守歲誦杜工部四十明朝是之句請足成','蒲壽宬','宋','宋诗','song-poetry','','[]','四十明朝是，瞻天祇乞閒。',48,'全唐诗/poet.song.237000.json','["四十明朝是，瞻天祇乞閒。", "自慙身計拙，早覺鬢毛斑。", "守歲從兒喜，攙春借酒顔。", "盍簪喧馬意，清夢五雲間。"]'),
('d68d9050-95d0-405f-98ce-6ed8b691a597','送枯崖悟上人省覲三山','蒲壽宬','宋','宋诗','song-poetry','','[]','遍踏長松影，行吟入畫屏。',48,'全唐诗/poet.song.237000.json','["遍踏長松影，行吟入畫屏。", "秋江一葉渡，落日數峯青。", "白髪干新夢，黄花制晚齡。", "片雲何日會，重約在林扄。"]'),
('1fd9420a-ba40-4966-931f-5329e23e57f7','即事','蒲壽宬','宋','宋诗','song-poetry','','[]','江樓人臥病，寂寞更誰憐。',48,'全唐诗/poet.song.238000.json','["江樓人臥病，寂寞更誰憐。", "有子常離抱，無家可祝先。", "雕墻笑茅屋，滄海幻桑田。", "昨聽東鄰訃，浮華亦夢然。"]'),
('b7a0c514-1a4f-450f-8d2e-21d9b9503f31','約趙委順北山試泉','蒲壽宬','宋','宋诗','song-poetry','','[]','擬尋青竹杖，同訪白雲龕。',48,'全唐诗/poet.song.238000.json','["擬尋青竹杖，同訪白雲龕。", "野茗春深苦，山泉雨後甘。", "鳥聲塵夢醒，花事午風酣。", "静趣期心會，逢人勿費談。"]'),
('a6378a1c-ce81-400c-8575-3f08e3ce7421','春陰偶成柬枯崖','蒲壽宬','宋','宋诗','song-poetry','','[]','砌蘚頻侵緑，野花相避紅。',48,'全唐诗/poet.song.238000.json','["砌蘚頻侵緑，野花相避紅。", "不知昏與晝，惟見雨和風。", "有酒爲寒盡，無詩非景窮。", "地爐煨芋火，時約老僧同。"]'),
('a8446f0a-d009-49cd-882e-9a30643d8822','友人余兄歸小詩寄胡葦航','蒲壽宬','宋','宋诗','song-poetry','','[]','别去又梅時，夷塗豈倦馳。',48,'全唐诗/poet.song.238000.json','["别去又梅時，夷塗豈倦馳。", "能存二頃事，寧畏十年遲。", "耐冷心如鐵，因吟鬢欲絲。", "猶嫌夜來夢，不解說相思。"]'),
('1c523ce2-4eb4-4db2-a1ff-c21f07cdfe33','寄胡葦航料院','蒲壽宬','宋','宋诗','song-poetry','','[]','别來梅正謝，愁坐柳成陰。',48,'全唐诗/poet.song.238000.json','["别來梅正謝，愁坐柳成陰。", "救世有何策，圗名非本心。", "萬言難復古，一語儻醫今。", "已向山中老，因風懐所欽。"]'),
('eae890df-a1cf-422a-9337-de6c568c0956','九月九日登山','蒲壽宬','宋','宋诗','song-poetry','','[]','日月百年寛，良辰天不慳。',48,'全唐诗/poet.song.238000.json','["日月百年寛，良辰天不慳。", "秋來常對菊，情適便登山。", "户外無塵鞅，籬邊有酒顔。", "當時老彭澤，幽事獨相闗。"]'),
('29ec0d61-0f92-4ee5-bb96-c74e00f38aa5','題江心寺詩','蒲壽宬','宋','宋诗','song-poetry','','[]','聞說東甌勝，茲遊心頗降。',48,'全唐诗/poet.song.238000.json','["聞說東甌勝，茲遊心頗降。", "江心浮一寺，水面立雙幢。", "路絕帆當户，潮回月漾窗。", "悠悠懐古思，把酒酹漁釭。"]'),
('c65f4fe5-5df2-4b69-9250-a573267c0d18','七夕前二日與窺堂莊使君江横觀水望霓悵然','蒲壽宬','宋','宋诗','song-poetry','','[]','倚闌人不識，懐古尚心驚。',48,'全唐诗/poet.song.238000.json','["倚闌人不識，懐古尚心驚。", "坐想瀰漫意，臥聞鞺鞳聲。", "浪翻京口寺，潮打石頭城。", "莫說南柯事，相寛老大情。"]'),
('9770e3b3-11e4-4420-b8b8-a66c0abf4f86','溪堂春日即事','蒲壽宬','宋','宋诗','song-poetry','','[]','抵是此溪山，須將舊眼看。',48,'全唐诗/poet.song.238000.json','["抵是此溪山，須將舊眼看。", "鷗飛緑不染，鳥没翠如攅。", "雨過巖巒浄，潮來天地寛。", "莫浮茅屋去，犬吠拍欄干。"]'),
('bb329233-48a2-460b-b5cc-b17d17509b1e','八月十三夜道士湖汎月','蒲壽宬','宋','宋诗','song-poetry','','[]','萬事廓悠悠，因貧得縱遊。',48,'全唐诗/poet.song.238000.json','["萬事廓悠悠，因貧得縱遊。", "天慳一様月，人有幾中秋。", "短笛芙蓉浦，芳尊杜若洲。", "清狂欠拘束，誰恕道家流。"]'),
('1c5a5c2c-e295-47b1-9db5-b20f037756d8','寒山暮景','蒲壽宬','宋','宋诗','song-poetry','','[]','青山寒似削，黄葉掃仍飛。',48,'全唐诗/poet.song.238000.json','["青山寒似削，黄葉掃仍飛。", "落日行人急，癡風過翼稀。", "老鷄尋舊杙，野犬吠緇衣。", "獨倚枯藤立，柴門候牧歸。"]'),
('8077cbcd-a62b-4dfc-9ad9-dda714a2963e','三疊泉廬山簡寂觀十五里一名擷泉','蒲壽宬','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','此豈凡間物，神人疑屬饜。',48,'全唐诗/poet.song.238000.json','["此豈凡間物，神人疑屬饜。", "踏翻雲母碓，放出水精簾。", "娥女愁遺珮，冰虬或弄髯。", "鮫綃一百丈，織出浪紋纎。"]'),
('f6ea5f33-b6b6-4e37-a8d6-d237ba312c7d','題純陽洞','蒲壽宬','宋','宋诗','song-poetry','','[]','路入松蘿去，閒眠石頂雲。',48,'全唐诗/poet.song.238000.json','["路入松蘿去，閒眠石頂雲。", "半宵忽聞虎，六月不飛蚊。", "煙郭多年畫，晴疇破衲紋。", "世無俱絕粒，持鉢不如耘。"]'),
('4bdfe36a-2975-4f5d-b848-e0cb336be495','重陽','蒲壽宬','宋','宋诗','song-poetry','','[]','黄花渾似舊，白髪忽驚新。',48,'全唐诗/poet.song.238000.json','["黄花渾似舊，白髪忽驚新。", "争說參軍帽，誰憐處士巾。", "折腰寧不辱，有酒未爲貧。", "絕愛南山色，相看意轉真。"]'),
('5f5c80ac-69e0-4891-82ef-75a4d786480e','題海雲樓下一碧萬頃亭','蒲壽宬','宋','宋诗','song-poetry','','[]','倚闌心目浄，萬頃一磨銅。',48,'全唐诗/poet.song.238000.json','["倚闌心目浄，萬頃一磨銅。", "欲畫畫不得，託言言更窮。", "陰晴山逺近，日夜水西東。", "此意知誰會，鷗邊獨釣翁。"]'),
('0c1d280c-2ff8-4182-8da3-0e719bc49e3c','心泉','蒲壽宬','宋','宋诗','song-poetry','','[]','來尋萬古意，聊結此生緣。',48,'全唐诗/poet.song.238000.json','["來尋萬古意，聊結此生緣。", "久視都無物，中間只見天。", "靈根何處覔，露液曉初鮮。", "白髪今如此，捫松憶少年。"]'),
('545da14c-2740-4e83-9df6-7d66457129ed','石潭觀魚','蒲壽宬','宋','宋诗','song-poetry','','[]','拂石搘頤久，閒心寂似初。',48,'全唐诗/poet.song.238000.json','["拂石搘頤久，閒心寂似初。", "不知渾是水，寧覺我非魚。", "欲數猶疑幻，相看若在虚。", "星星雙鬢影，何事入方諸。"]'),
('d6ca5fe5-623c-4b59-b4c1-2082992130b6','題金粟洞','蒲壽宬','宋','宋诗','song-poetry','','[]','天風吹絕頂，小立思生豪。',48,'全唐诗/poet.song.238000.json','["天風吹絕頂，小立思生豪。", "遥海望無際，衆風疑避髙。", "龍留神骨去，犀斂夜光韜。", "惟愛瑶池水，尋雲學種桃。"]'),
('3e44e771-74d3-46e6-95aa-107757160f9d','種麥','蒲壽宬','宋','宋诗','song-poetry','','[]','荒林僻左地，時已及來牟。',48,'全唐诗/poet.song.238000.json','["荒林僻左地，時已及來牟。", "頗學鴉種麥，可憐人代牛。", "莫言耒耜苦，且願甲兵休。", "來歲如旋磨，機輪向瀑流。"]'),
('48af22fa-2ad0-4de5-82e3-3a12751212e0','委順趙君見遺千里小景鵶鵲圗有詩将之用韻爲謝','蒲壽宬','宋','宋诗','song-poetry','','[]','朝拂扶桑影，暮尋明月枝。',48,'全唐诗/poet.song.238000.json','["朝拂扶桑影，暮尋明月枝。", "羣飛心共逺，三匝意猶遲。", "相向無聲裏，應思落筆時。", "寸程千里闊，惟可與君知。"]'),
('20b883c2-2129-4718-9198-5ef3c0a0fefb','送清老弟歸荆湖幕','蒲壽宬','宋','宋诗','song-poetry','','[]','驅車出閩嶠，微宦歷江湖。',48,'全唐诗/poet.song.238000.json','["驅車出閩嶠，微宦歷江湖。", "沙塞馬蹄疾，水天鴻影孤。", "楚天時臥鼓，蜀道日飛芻。", "萬里戎旃客，何當表丈夫。"]'),
('164f1743-a73d-42f6-9acb-ef071242492a','聞蟋蟀有感','蒲壽宬','宋','宋诗','song-poetry','','[]','煎煎促誰織，機杼咽空林。',48,'全唐诗/poet.song.238000.json','["煎煎促誰織，機杼咽空林。", "何處露藂下，入人秋思深。", "清燈一綫淚，孤枕百年心。", "此意知誰會，悠然太古音。"]'),
('3e64e7e5-c627-48bd-9800-f0b884e98710','挽仁山楊先生','蒲壽宬','宋','宋诗','song-poetry','','[]','滴盡艱難淚，肝腸鐵似頑。',48,'全唐诗/poet.song.238000.json','["滴盡艱難淚，肝腸鐵似頑。", "忍教師道絕，還向我翁澘。", "命也吾何憾，天乎識固慳。", "平生修潔意，千載此西山。"]'),
('7ea61a9d-e517-46c4-81ae-7bd3bd9c6093','用翁雪舟送春韻三首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','錦衣年少不知愁，風雨無端惱客遊。',64,'全唐诗/poet.song.238000.json','["錦衣年少不知愁，風雨無端惱客遊。", "萬點殘紅空過眼，一番新緑又從頭。", "夕陽細草堪横笛，野渡垂楊可繫舟。", "三百六旬渾是醉，餞春何用苦綢繆。"]'),
('21433d8e-9c67-485e-8899-dffe8a61a024','用翁雪舟送春韻三首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','隙駒如箭未堪憐，晴雨悲歡付自然。',64,'全唐诗/poet.song.238000.json','["隙駒如箭未堪憐，晴雨悲歡付自然。", "九十春光能幾日，一番花信又明年。", "殘紅數點心終在，垂柳千絲意許妍。", "說與游人莫惆悵，綠陰幽草一般天。"]'),
('ff8ac079-f4de-4505-a9f2-45509a2578ee','用翁雪舟送春韻三首  其三','蒲壽宬','宋','宋诗','song-poetry','','[]','底事黄鸝喚不休，出門欣見綠陰稠。',64,'全唐诗/poet.song.238000.json','["底事黄鸝喚不休，出門欣見綠陰稠。", "殘花滿地無人掃，芳草連天起客愁。", "淚落田間聞牧笛，醉歸江上問漁舟。", "杜鵑也合催春去，何處而今孟浪遊。"]'),
('9a73e6e1-ee09-44f5-9b2b-e70df9c17714','送擇齋先生徐大監赴建倉','蒲壽宬','宋','宋诗','song-poetry','','[]','帝命元臣選外臺，南州聲望久崔嵬。',64,'全唐诗/poet.song.238000.json','["帝命元臣選外臺，南州聲望久崔嵬。", "倉箱早辦九年集，原隰欣迎四牡來。", "父老此時方見日，吏饕平晝忽驚雷。", "錦衣翠節鄉邦重，耿耿文星照上台。"]'),
('6c7e90aa-908d-4484-a9fe-246c83d3a315','用老竹與子晦韻','蒲壽宬','宋','宋诗','song-poetry','','[]','冰清玉潔好風襟，老屋凄凉興味深。',64,'全唐诗/poet.song.238000.json','["冰清玉潔好風襟，老屋凄凉興味深。", "身世已非塵外蹟，語言猶是竹邊音。", "且陪此日鶯花樂，休憶當年燈火心。", "白髪相看能幾許，樽前須要惜光陰。"]'),
('55ad0825-9a5e-422d-b6cc-1bf1b1b206b3','和楊芸齋送枯崖住興福韻','蒲壽宬','宋','宋诗','song-poetry','','[]','一夜春光到竹門，東風拂拂動閒雲。',64,'全唐诗/poet.song.238000.json','["一夜春光到竹門，東風拂拂動閒雲。", "鉗鎚粗了人間債，缾錫蹔抛林下羣。", "烟塔忽驚當户立，霜鐘猶記舊山聞。", "髙談亹亹天花落，老衲廊頭意自欣。"]'),
('0a75b6d5-91a2-4af0-8201-fd470b569133','寄石隠老嶼上人','蒲壽宬','宋','宋诗','song-poetry','','[]','已約巖頭同數宿，如何消息竟茫然。',64,'全唐诗/poet.song.238000.json','["已約巖頭同數宿，如何消息竟茫然。", "抱琴有意彈明月，采藥無心到絕巓。", "不過虎溪安得笑，偶逢醉石便欹眠。", "山林此樂而今少，一日相從是宿緣。"]'),
('47d4bd66-9834-45b2-9196-87d9b00cb7c5','和倪梅村','蒲壽宬','宋','宋诗','song-poetry','','[]','偶携琴冊傍林泉，坐對梅花記往年。',64,'全唐诗/poet.song.238000.json','["偶携琴冊傍林泉，坐對梅花記往年。", "鴻燕何心成巧避，夔蚿無語自相憐。", "才唫瘦影黄昬月，又見殘紅細雨天。", "擬把楚騷重載酒，掀髯抵掌話前緣。"]'),
('060e3ebe-2e6a-4120-a0f9-57c50ac2b3ec','再用韻和葦航','蒲壽宬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江不直一杯寛，自笑狂生筆力慳。',64,'全唐诗/poet.song.238000.json','["長江不直一杯寛，自笑狂生筆力慳。", "有酒何須誇戱馬，遶籬豈必强登山。", "世無劉表誰知已，人說淵明我厚顔。", "風雨滿城都過了，多簪黄菊出松闗。"]'),
('9d8339df-32fe-4acc-9cdc-3ee3f9df496d','與小兒助子遊江横作','蒲壽宬','宋','宋诗','song-poetry','','[]','葺荷偶憶湘纍句，築屋還尋杜若汀。',64,'全唐诗/poet.song.238000.json','["葺荷偶憶湘纍句，築屋還尋杜若汀。", "孤樹每留殘日白，片帆徐度逺山青。", "海鷗知我斷機慮，漁父與誰分醉醒。", "何處扁舟横短笛，月明風裊不堪聽。"]'),
('b2fabf4b-2c84-4b9e-9941-88368ac86712','江横暮景','蒲壽宬','宋','宋诗','song-poetry','','[]','獨倚闌干對落霞，垂楊古渡欲棲鴉。',64,'全唐诗/poet.song.238000.json','["獨倚闌干對落霞，垂楊古渡欲棲鴉。", "漁翁何處烟藏浦，白鷺成羣月浸沙。", "淚落西風呌黄鵠，酒闌深夜聽琵琶。", "誰人得似鴟夷子，一葉浮雲總是家。"]'),
('f982989b-dde3-48e4-8f3a-2edae0ff13bc','再題江横','蒲壽宬','宋','宋诗','song-poetry','','[]','一榻虚明懐抱幽，水天無際望悠悠。',64,'全唐诗/poet.song.238000.json','["一榻虚明懐抱幽，水天無際望悠悠。", "潮來不覺沙洲没，浪打只疑茅屋浮。", "何處漁人横短笛，有時嫠婦泣孤舟。", "忘機何必曾相狎，說與江邊羣白鷗。"]'),
('31f65f8e-2fe2-421e-b452-75282b4ee828','遊鼓山題天風海濤亭','蒲壽宬','宋','宋诗','song-poetry','','[]','翛翛白髪倚欄干，笑仰髙峯巾袂仙。',64,'全唐诗/poet.song.238000.json','["翛翛白髪倚欄干，笑仰髙峯巾袂仙。", "但見烟霞相逺近，不知宇宙有中邊。", "宦途人在非凡境，客裏身遊極樂天。", "自歎情懐今潦倒，重來未識是何年。"]'),
('fbe6530b-d8e6-4705-b96c-b9989df8d9c2','送使君趙寺丞泰先生','蒲壽宬','宋','宋诗','song-poetry','','[]','别郡安知寄此州，攀轅合借我公留。',64,'全唐诗/poet.song.238000.json','["别郡安知寄此州，攀轅合借我公留。", "求仁而得又何怨，蔽美豈其爲好修。", "花逕怕風宜落絮，秧田足雨恐妨牟。", "春歸誰識春心苦，才說思春欲白頭。"]'),
('196ec5c4-1e3a-4f60-b938-0a53eebae609','寄何我軒','蒲壽宬','宋','宋诗','song-poetry','','[]','十年不見此髯翁，笑我而今鬢亦蓬。',64,'全唐诗/poet.song.238000.json','["十年不見此髯翁，笑我而今鬢亦蓬。", "幾度因詩親水部，一迴看劍泣山公。", "無心塵世雲移岫，極目仙壺浪拍空。", "痛飲劇談非是夢，寸丹長與荔枝紅。"]'),
('def389b4-7f8a-4381-9f57-8725e92b1174','閒坐海觀興致悠然是時月白如晝','蒲壽宬','宋','宋诗','song-poetry','','[]','一笑靈龜尾曵塗，扁舟聊復寄菰蒲。',64,'全唐诗/poet.song.238000.json','["一笑靈龜尾曵塗，扁舟聊復寄菰蒲。", "潮生潮落帆來去，雲卷雲舒山有無。", "風定若教胥怒息，月明空憶蠡遊孤。", "漁翁不識人間事，白髪青蓑酒滿壺。"]'),
('df6e3289-16ec-4661-b832-bddb7fb5c12f','嶺後山莊','蒲壽宬','宋','宋诗','song-poetry','','[]','感慨重來歲月深，手栽松柏已成林。',64,'全唐诗/poet.song.238000.json','["感慨重來歲月深，手栽松柏已成林。", "萬山自此無南北，一水長流不古今。", "先訓丁寧猶在耳，老吾寂寞自沾襟。", "君恩已遂祈閒請，莘野歸耕是本心。"]'),
('4132d3bf-5a5b-4ac5-8b38-9f76efd95c76','回謁藍主簿道傍見梅偶成','蒲壽宬','宋','宋诗','song-poetry','','[]','誰家一樹銕斜欹，的皪踈花出短籬。',64,'全唐诗/poet.song.238000.json','["誰家一樹銕斜欹，的皪踈花出短籬。", "黄葉久隨風捲地，幽姿當與雪同時。", "白頭朔漠窮蘇武，瘦骨西山餓伯夷。", "三嗅清芬一杯水，徘徊無語笑掀眉。"]'),
('b91c397e-6c44-42ec-b144-c86c60c26afe','題深省庵','蒲壽宬','宋','宋诗','song-poetry','','[]','結草爲庵寄一枝，鐘魚聊復事清規。',64,'全唐诗/poet.song.238000.json','["結草爲庵寄一枝，鐘魚聊復事清規。", "野蔬入供無人識，古柏爲香有佛知。", "頻去飲泉非爲渴，偶來坐石忽忘饑。", "常談且接頭陀伴，欲說上乘空費辭。"]'),
('00489bee-3a97-4a33-877e-d31ae8ece4ef','依韻寄呈林城山','蒲壽宬','宋','宋诗','song-poetry','','[]','隣蛩深夜語幽幽，猶此塵埃一敝裘。',64,'全唐诗/poet.song.238000.json','["隣蛩深夜語幽幽，猶此塵埃一敝裘。", "甘菊已荒歸栗里，蒲萄堪醉勝涼州。", "知心海上千年鶴，極目雲間五色樓。", "白髪正殷松柏念，不因泉石老斯丘。"]'),
('d1466032-c2cc-4046-9f68-6ae314258399','即席用委順聽甘師琴韻','蒲壽宬','宋','宋诗','song-poetry','','[]','獨抱琴聲感歲年，捜趣外欲無絃。',64,'全唐诗/poet.song.238000.json','["獨抱琴聲感歲年，捜趣外欲無絃。", "廣陵寂寂嵇生去，秋木幽幽鳴犢賢。", "一點山泉巖竇雨，數聲瑶佩泬寥天。", "音徽千載何人會，願和薫風殿閣前。"]'),
('7fbe915f-0278-4dcd-a460-038bd511945d','與興福老枯崖乘月觀濤','蒲壽宬','宋','宋诗','song-poetry','','[]','無心携起碧笻條，偶爾來從漁父招。',64,'全唐诗/poet.song.238000.json','["無心携起碧笻條，偶爾來從漁父招。", "山色多情似呉越，濤聲牽夢到金焦。", "魚龍一任風雲便，鷗鷺不知天海遥。", "共倚欄干秋月白，豈期真樂在今宵。"]'),
('082e79e4-53b4-4bbf-842f-7fc693cb4ca2','西巖','蒲壽宬','宋','宋诗','song-poetry','','[]','石路層層碧蘚花，矮窗低户足烟霞。',64,'全唐诗/poet.song.238000.json','["石路層層碧蘚花，矮窗低户足烟霞。", "愁聞獨鶴悲寒角，静閱羣蜂凑晚衙。", "野菜旋挑奚待糝，石泉新汲自煎茶。", "爐熏銷盡抛書卷，閒倚闌干看日斜。"]'),
('255169cd-e4d0-41d5-8a0d-3370233e6876','贈洪都髙士蕭野鶴','蒲壽宬','宋','宋诗','song-poetry','','[]','自從華表去蹁蹮，縠頂丹深不計年。',64,'全唐诗/poet.song.238000.json','["自從華表去蹁蹮，縠頂丹深不計年。", "萬里孤光中夜月，一聲清唳九重天。", "偶然夢覺思遼海，不是饑驅向野田。", "赤壁秋髙風露下，無心曾喚老坡仙。"]'),
('8a8fb0c9-6c56-48ed-9c55-efcf371d8507','贈呉仰雲','蒲壽宬','宋','宋诗','song-poetry','','[]','雲巾羽扇得真如，不用羞慙非故吾。',64,'全唐诗/poet.song.238000.json','["雲巾羽扇得真如，不用羞慙非故吾。", "入手千般休說巧，轉頭一著不爲愚。", "塵中羈絆無還有，物外逍遥有若無。", "我若忘機曾悟此，烟波鷗鷺是吾徒。"]'),
('723d62f4-5e34-428b-9f12-052911823cf2','歲旦勉田隣','蒲壽宬','宋','宋诗','song-poetry','','[]','歲律從新泰道亨，出門欣見麥青青。',64,'全唐诗/poet.song.238000.json','["歲律從新泰道亨，出門欣見麥青青。", "已無闗外石壕吏，遥望城頭紫氣星。", "往事莫追由世數，寛恩頻下爲生靈。", "而今頗覺農爲重，說與村村父老聽。"]'),
('d87f7d36-4fe1-4fd8-a4fe-fbe511e40834','端午','蒲壽宬','宋','宋诗','song-poetry','','[]','鬢符腰艾去紛紛，荷葉荷花匝水濵。',64,'全唐诗/poet.song.238000.json','["鬢符腰艾去紛紛，荷葉荷花匝水濵。", "思逺樓前雖有曲，若邪溪畔豈無人。", "莫將楚恨悲兒女，聊把騷章託鬼神。", "濁酒滿壺漁父笑，江邊鷗鷺正相親。"]'),
('af630db7-0066-4691-91cc-b49de470d3c9','山園芍藥忽有花喜而賦','蒲壽宬','宋','宋诗','song-poetry','','[]','披草籬根問舊花，一番春事又萌芽。',64,'全唐诗/poet.song.238000.json','["披草籬根問舊花，一番春事又萌芽。", "非因老態逢時感，祗怨昏瞳作霧遮。", "何處而今尋爛熳，不圗於此見英華。", "翻階自合流芳詠，可惜飄零野客家。"]'),
('5ac37408-81ed-40e1-8d8b-6390a813638e','夢故人郭推官元用詩以奠之','蒲壽宬','宋','宋诗','song-poetry','','[]','鷄絮才陳淚已傾，故人旌旐尚禪扄。',64,'全唐诗/poet.song.238000.json','["鷄絮才陳淚已傾，故人旌旐尚禪扄。", "塵中愧我頭空白，夢裏逢君眼更青。", "束髪論交真意氣，傷心無語負幽冥。", "求銘敢後朋儕事，况復原頭有鶺鴒。"]'),
('328f651a-d855-4999-b5a2-d813881cf4be','夜聞隣笛','蒲壽宬','宋','宋诗','song-poetry','','[]','幽夢初回漏未央，起聞隣笛倍凄凉。',64,'全唐诗/poet.song.238000.json','["幽夢初回漏未央，起聞隣笛倍凄凉。", "不知何處石崖裂，忽送一聲江水長。", "短棹清風懐赤壁，斷垣斜月隠山陽。", "猶疑吹到梅花落，不見梅花空攪腸。"]'),
('cc07e2ee-2b80-4299-829d-a47ad5f04a45','風雨終夜獨坐不寐','蒲壽宬','宋','宋诗','song-poetry','','[]','風雨瀟瀟到夜終，夜寒一室坐虚空。',64,'全唐诗/poet.song.238000.json','["風雨瀟瀟到夜終，夜寒一室坐虚空。", "何當樂與二三子，免使凄其六一翁。", "老大自甘爲老大，窮通休苦較窮通。", "此心不作窺園想，流水落花春夢中。"]'),
('0bf13ca9-fb2a-4a14-9603-d4ffb1767937','田園秋興','蒲壽宬','宋','宋诗','song-poetry','','[]','草屋柴門風露凉，寒瓜收蔓力鋤荒。',64,'全唐诗/poet.song.238000.json','["草屋柴門風露凉，寒瓜收蔓力鋤荒。", "新栽莙薘恰逢雨，欲剪芹藍猶待霜。", "牧竪歸來煨芋熟，田翁相就潑醅香。", "里胥偶報徴苖急，自闢閒畦早築場。"]'),
('c5ecbeb7-e8a1-439e-8d3f-d013186c35d1','郊行有感','蒲壽宬','宋','宋诗','song-poetry','','[]','鷄犬不鳴何處村，頽簷破壁問誰門。',64,'全唐诗/poet.song.238000.json','["鷄犬不鳴何處村，頽簷破壁問誰門。", "蓬蒿滿地田園在，瓦礫如山井臼存。", "青草髑髏疑是夢，白頭老父泣無言。", "諮諏隣舊多爲鬼，倚杖徘徊堪斷魂。"]'),
('437225a0-7893-4734-9bd4-584b4f36e1bb','近重陽作','蒲壽宬','宋','宋诗','song-poetry','','[]','滿城風雨近重陽，梧竹蕭蕭欲斷腸。',64,'全唐诗/poet.song.238000.json','["滿城風雨近重陽，梧竹蕭蕭欲斷腸。", "敢望白衣來送酒，擬將黄菊去爲糧。", "繫茰安得山堪避，落帽豈無人在旁。", "千載風流心獨會，飲泉亦足慰凄凉。"]'),
('10861a2f-8448-458e-abf6-c8993b537625','賦枸杞','蒲壽宬','宋','宋诗','song-poetry','','[]','神草如蓬世不知，壁間墻角自離離。',64,'全唐诗/poet.song.238000.json','["神草如蓬世不知，壁間墻角自離離。", "辛盤空芼仙人杖，藥斧惟尋地骨皮。", "千歲未逢朱孺子，四時堪供陸天隨。", "霜晨忽訝春櫻熟，閒摘殷紅遶斷籬。"]'),
('0c10878a-e9d5-4d90-a518-4cc4d0cd1879','畫船','蒲壽宬','宋','宋诗','song-poetry','','[]','世路羊腸姑已之，扁舟我欲問冰夷。',64,'全唐诗/poet.song.238000.json','["世路羊腸姑已之，扁舟我欲問冰夷。", "祗因吏部酷好酒，豈是鷄林要售詩。", "萬事不如潮有信，寸心唯頼月相知。", "斜風細雨休歸去，此政老翁沉醉時。"]'),
('5eec41ea-3b16-466f-9a5e-9247aff3eb88','遊武夷九曲','蒲壽宬','宋','宋诗','song-poetry','','[]','紫縵紅裀事有根，緑函金鎻蜕猶存。',64,'全唐诗/poet.song.238000.json','["紫縵紅裀事有根，緑函金鎻蜕猶存。", "無緣得到千巖頂，試問而今幾代孫。", "漢祀昔曾陳玉脯，晉人方始識桃源。", "不因大隠屏中老，未易抽簪扣洞門。"]'),
('36f4f15c-6428-4f39-b583-21bee7a1a74c','寄石隠','蒲壽宬','宋','宋诗','song-poetry','','[]','閉門十日雨，破屋砌生苔。',24,'全唐诗/poet.song.238000.json','["閉門十日雨，破屋砌生苔。", "此意何人會，抱琴來不来。"]'),
('af822285-1671-4354-8097-983aa61f1db2','題葉寄楊芸夫','蒲壽宬','宋','宋诗','song-poetry','','[]','吟得秋風老，敲窗意轉深。',24,'全唐诗/poet.song.238000.json','["吟得秋風老，敲窗意轉深。", "憑將林下事，爲寄與知音。"]'),
('d1670e43-ab3c-487d-a1b4-f829c354510f','心泉二首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','涓涓萬古意，湛湛一塵無。',24,'全唐诗/poet.song.238000.json','["涓涓萬古意，湛湛一塵無。", "明月來窺鏡，宵寒露滴珠。"]'),
('2c1106a9-e8f0-4a42-b06d-d8ec3fb89b89','心泉二首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','驟来驚辟易，久視益虛無。',24,'全唐诗/poet.song.238000.json','["驟来驚辟易，久視益虛無。", "咫尺星堪摘，波揺又走珠。"]'),
('91eeb5a1-51e5-4815-8747-1762baf79061','菊泉','蒲壽宬','宋','宋诗','song-poetry','','[]','疏泉得古髓，種菊蒙秋潭。',24,'全唐诗/poet.song.238000.json','["疏泉得古髓，種菊蒙秋潭。", "願與村中人，一瓢共清甘。"]'),
('f83ec837-cb77-43ef-92ad-54967306d52f','聞泉','蒲壽宬','宋','宋诗','song-poetry','','[]','山椒一雨過，石罅百泉鳴。',24,'全唐诗/poet.song.238000.json','["山椒一雨過，石罅百泉鳴。", "應接都不暇，更兼秋月明。"]'),
('36ab889f-7953-4db1-bd6e-2686f67a1a59','澗亭麈尾泉','蒲壽宬','宋','宋诗','song-poetry','','[]','泉揮玉麈尾，岫擁翠雲裘。',24,'全唐诗/poet.song.238000.json','["泉揮玉麈尾，岫擁翠雲裘。", "盡日看不足，倚闌生古愁。"]'),
('77f7a0c9-08f6-4615-840f-f43fc8bc0554','江横信筆','蒲壽宬','宋','宋诗','song-poetry','','[]','潮汐有贏縮，江横無古今。',24,'全唐诗/poet.song.238000.json','["潮汐有贏縮，江横無古今。", "魚龍任掀舞，孤月在天心。"]'),
('2f46604d-1c69-45f0-838e-1d571a460dbc','書滴翠巖壁','蒲壽宬','宋','宋诗','song-poetry','','[]','蘿衣濕寒翠，苔錦上嶙峋。',24,'全唐诗/poet.song.238000.json','["蘿衣濕寒翠，苔錦上嶙峋。", "一榻千峯裡，因詩憶古人。"]'),
('88c0e380-ba94-4872-a4c8-ef36b0ab1ea9','書香爐瀑布圖後','蒲壽宬','宋','宋诗','song-poetry','','[]','飛流三百丈，日射碧琉璃。',24,'全唐诗/poet.song.238000.json','["飛流三百丈，日射碧琉璃。", "一氣何終極，淋漓自不知。"]'),
('ba2ae4d3-bd7a-4f8c-a687-c754edbe827c','青霞西亭','蒲壽宬','宋','宋诗','song-poetry','','[]','長松被薜荔，怪石生煙霞。',24,'全唐诗/poet.song.238000.json','["長松被薜荔，怪石生煙霞。", "簷牙木杪見，上有山人家。"]'),
('339cf5f6-f516-40ba-91f4-ed3ab330881e','滄浪亭','蒲壽宬','宋','宋诗','song-poetry','','[]','曉色桃蒸霞，春陰柳垂霧。',24,'全唐诗/poet.song.238000.json','["曉色桃蒸霞，春陰柳垂霧。", "爲問橋下船，沿流到何處。"]'),
('b7c259c9-7d1b-47ed-bae9-951d9716b6a6','心泉','蒲壽宬','宋','宋诗','song-poetry','','[]','冷冷一澗泉，炯炯千樹雪。',24,'全唐诗/poet.song.238000.json','["冷冷一澗泉，炯炯千樹雪。", "歲寒鐵石心，山中玩芳潔。"]'),
('49b64601-f140-4573-a1d4-3180a6aac2d9','讀可翁閒坐偈','蒲壽宬','宋','宋诗','song-poetry','','[]','夜久風浪息，驪龍弄頷珠。',24,'全唐诗/poet.song.238000.json','["夜久風浪息，驪龍弄頷珠。", "水怪不敢動，明月滿江湖。"]'),
('a0e2e782-e37d-4cab-892e-1de351897add','白鬚','蒲壽宬','宋','宋诗','song-poetry','','[]','月照當襟雪，終剪施摩詰。',24,'全唐诗/poet.song.238000.json','["月照當襟雪，終剪施摩詰。", "我作白鬚行，而得飬生術。"]'),
('69dc879e-cdca-4a77-aba7-530392149cd4','題石','蒲壽宬','宋','宋诗','song-poetry','','[]','巖石多意氣，松樹留髙齡。',24,'全唐诗/poet.song.238000.json','["巖石多意氣，松樹留髙齡。", "倚仗眇雲濤，天風吹泠泠。"]'),
('ce576974-5e06-4864-8bde-e136b46cae0f','怡雲','蒲壽宬','宋','宋诗','song-poetry','','[]','把作一片畫，晴陰渾不同。',24,'全唐诗/poet.song.238000.json','["把作一片畫，晴陰渾不同。", "不知誰是畫，佇立意無窮。"]'),
('9d149120-7d65-4bcd-b76d-1f2acc6e4649','寒食有感','蒲壽宬','宋','宋诗','song-poetry','','[]','杏粥因懷舊，榆羮豈爲春。',24,'全唐诗/poet.song.238000.json','["杏粥因懷舊，榆羮豈爲春。", "憑將禁火事，說與乞墦人。"]'),
('f7c12f9b-a004-4dec-b1ca-74325230cac7','郊意','蒲壽宬','宋','宋诗','song-poetry','','[]','清晨起搔頭，荷鋤出門去。',24,'全唐诗/poet.song.238000.json','["清晨起搔頭，荷鋤出門去。", "露濕野草花，香來不知處。"]'),
('4765712c-7010-47ab-8b67-685d85d03e14','題畫竹扇寄友','蒲壽宬','宋','宋诗','song-poetry','','[]','明月二千里，清風一萬竿。',24,'全唐诗/poet.song.238000.json','["明月二千里，清風一萬竿。", "相思寫不得，寫出夢来看。"]'),
('3578674f-32d1-400d-8ba1-69533a7c6cfb','春日聞禽戯題寓廨','蒲壽宬','宋','宋诗','song-poetry','','[]','隔墻聽幽哢，入坐春融融。',24,'全唐诗/poet.song.238000.json','["隔墻聽幽哢，入坐春融融。", "午夢恬不成，始知身在籠。"]'),
('f32f512f-8af5-48f7-814c-0f06195442e2','棹歌','蒲壽宬','宋','宋诗','song-poetry','','[]','鼓枻歸去来，蓑風鳴策策。',24,'全唐诗/poet.song.238000.json','["鼓枻歸去来，蓑風鳴策策。", "明月傾我壺，滄浪天一碧。"]'),
('5e8ee7fa-0289-4ba7-838e-14f915b06ff0','牧童歌十首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','荷笠小蒼頭，犢裩乘水牛。',24,'全唐诗/poet.song.238000.json','["荷笠小蒼頭，犢裩乘水牛。", "揚鞭自叱咤，度隴復憑溝。"]'),
('4d576421-2171-4d9f-b9b1-63792d0628f4','牧童歌十首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','軟坡便佇犢，凉蔭聚羣髫。',24,'全唐诗/poet.song.238000.json','["軟坡便佇犢，凉蔭聚羣髫。", "一竪忽然起，恐牛殘荳苖。"]'),
('4f1ce549-6d11-46f6-865c-dfad4c9a7264','牧童歌十首  其三','蒲壽宬','宋','宋诗','song-poetry','','[]','隔溪騎度水，浮去似鴟夷。',24,'全唐诗/poet.song.238000.json','["隔溪騎度水，浮去似鴟夷。", "莫話五湖事，且看牛背兒。"]'),
('09ffe145-fd25-4311-81ab-00cd3a234978','牧童歌十首  其四','蒲壽宬','宋','宋诗','song-poetry','','[]','倦来牛背卧，一覺度前岡。',24,'全唐诗/poet.song.238000.json','["倦来牛背卧，一覺度前岡。", "牛飽兒呼餒，歸来煨芋香。"]'),
('200d7a06-3ada-409a-b7f6-b9a5194318eb','牧童歌十首  其五','蒲壽宬','宋','宋诗','song-poetry','','[]','前山飛暮雨，牛上展青蓑。',24,'全唐诗/poet.song.238000.json','["前山飛暮雨，牛上展青蓑。", "回首牛呼犢，哀音兒唱歌。"]'),
('f7ceda62-807b-4e31-a5ea-2c13aa5f1275','牧童歌十首  其六','蒲壽宬','宋','宋诗','song-poetry','','[]','斜陽歸處險，路熟了無疑。',24,'全唐诗/poet.song.238000.json','["斜陽歸處險，路熟了無疑。", "結草爲衣著，圏葭作竹吹。"]'),
('16a16060-acfa-4219-9f4e-f6ca79028b59','牧童歌十首  其七','蒲壽宬','宋','宋诗','song-poetry','','[]','野花簮短笠，露濕蔓青青。',24,'全唐诗/poet.song.238000.json','["野花簮短笠，露濕蔓青青。", "莫笑兒童小，人間河鼓星。"]'),
('bba22912-1c58-45b8-950b-2925d20df77d','牧童歌十首  其八','蒲壽宬','宋','宋诗','song-poetry','','[]','老翁分社酒，匕箸小孩提。',24,'全唐诗/poet.song.238000.json','["老翁分社酒，匕箸小孩提。", "黄犢今堪駕，明年學把犂。"]'),
