('6b0f6ac8-ffc4-44f1-9e97-d8d059dde69c','漁父詞十三首  其一一','蒲壽宬','宋','宋诗','song-poetry','','[]','琉璃爲地水精天，一葉漁舟浪滿顛。',32,'全唐诗/poet.song.238000.json','["琉璃爲地水精天，一葉漁舟浪滿顛。", "風肅肅，露姢姢。", "家在蘆花何處邉。"]'),
('fc2d3901-8f32-4c7e-9f17-3b98123d0dbb','漁父詞十三首  其一二','蒲壽宬','宋','宋诗','song-poetry','','[]','江上浪花飛灑天，拍階鞺鞳屋如船。',32,'全唐诗/poet.song.238000.json','["江上浪花飛灑天，拍階鞺鞳屋如船。", "月不夜，水無邉。", "何處笛聲人未眠。"]'),
('5c111496-aedc-48cf-ade8-895d443bbc29','漁父詞十三首  其一三','蒲壽宬','宋','宋诗','song-poetry','','[]','逺入茫茫無盡邉，漁舟來往似行天。',32,'全唐诗/poet.song.238000.json','["逺入茫茫無盡邉，漁舟來往似行天。", "欹枕看，不成眠。", "誰識人間太乙仙。"]'),
('9432e40b-0b2e-494c-becf-29b6e54403cc','又漁父詞二首  其一','蒲壽宬','宋','宋诗','song-poetry','','[]','白水塘邉白鷺飛，龍湫山下鯽魚肥。',32,'全唐诗/poet.song.238000.json','["白水塘邉白鷺飛，龍湫山下鯽魚肥。", "欹雨笠，着雲衣。", "玄真不見又空歸。"]'),
('7e6a8080-f72c-40fe-8eb4-71bc0516badc','又漁父詞二首  其二','蒲壽宬','宋','宋诗','song-poetry','','[]','巖下無心雲自飛，塘邉足雨水初肥。',32,'全唐诗/poet.song.238000.json','["巖下無心雲自飛，塘邉足雨水初肥。", "龜曵尾，緑毛衣。", "荷盤無数爾安歸。"]'),
('f0bd1c73-f884-4c77-9761-11008a4219fc','欸乃詞','蒲壽宬','宋','宋诗','song-poetry','','[]','白頭翁，白頭翁，江海爲田魚作糧。',32,'全唐诗/poet.song.238000.json','["白頭翁，白頭翁，江海爲田魚作糧。", "相逢祇可唤劉四，不受人呼劉四郎。"]'),
('f3779d5b-f0cf-4a88-ad7e-9bad66d1def3','南村','蒲壽宬','宋','宋诗','song-poetry','','[]','每懷淵明老，昔欲居南村。',48,'全唐诗/poet.song.238000.json','["每懷淵明老，昔欲居南村。", "誅茅結矮屋，種桑蔭前軒。", "嘉蔬不盈掬，濁酒時一尊。", "客至如許行，惟看神農言。"]'),
('3955b94f-b45f-43a0-b474-6f5fd265891c','句  其一','歐良','宋','宋诗','song-poetry','','[]','璧固君所寄，鏡亦妾所惜。',24,'全唐诗/poet.song.238000.json','["璧固君所寄，鏡亦妾所惜。", "乍可返君璧，妾鏡不可得。"]'),
('2f57adbd-8d2c-41a9-8a9c-5287d020dd75','句  其二','歐良','宋','宋诗','song-poetry','','[]','紅黄冬樹葉，紫翠夕陽山。',12,'全唐诗/poet.song.238000.json','["紅黄冬樹葉，紫翠夕陽山。"]'),
('de2484e2-1e5c-47e9-9847-377763abf511','挽文文山','鄧剡','宋','宋诗','song-poetry','','[]','憶公淚懸河，九地無此事瀉。',241,'全唐诗/poet.song.238000.json','["憶公淚懸河，九地無此事瀉。", "想公騎赤龍，請命蒼梧野。", "世人醉生死，翻笑獨醒者。", "焉知千載英，精爽皎不夜。", "義士無廢興，時運有代謝。", "念昔喪亂初，公騎使君馬。", "奮袂起勤王，忼慨淚盈把。", "須臾三萬衆，如自九天下。", "燈棋書檄交，笑語雜悲咤。", "捧土障洪河，一繩維大廈。", "至哉朝宗性，百折終不舍。", "身北冠自南，血碧心肯化。", "顔鉤凜忠勁，杜詩蔚騷雅。", "晉陽骨肉冤，東市刀兵解。", "精誠揭天日，氣魄動夷夏。", "丈夫如此何，一死尤足怕。", "田橫老賓客，白髮餘息假。", "有時夢巖電，意悟當飄灑。", "非無中丞傳，殺青自誰寫。", "魂歸哀江南，千秋俎鄉社。"]'),
('aecf572c-1bf5-4084-bba3-f7f3b132bdb7','文文山畫像贊','鄧剡','宋','宋诗','song-poetry','','[]','目煌煌兮疏星曉寒，氣英英兮晴雷殷山。',44,'全唐诗/poet.song.238000.json','["目煌煌兮疏星曉寒，氣英英兮晴雷殷山。", "頭碎柱而璧完，血化碧而心丹。", "嗚呼，誰謂斯人不在世間。"]'),
('b424be0d-8207-47dd-8de6-025b55b6141a','挽李行甫','鄧剡','宋','宋诗','song-poetry','','[]','落倘使平生馬少游，不將鄉里博封侯。',65,'全唐诗/poet.song.238000.json','["落倘使平生馬少游，不將鄉里博封侯。", "肯緣兒輩斷屐齒，誰憶平生醉杖頭。", "老去焉知堯壤力，亂來初識楚天憂。", "新墳似與歐阡近，許見衣冠夜月遊。"]'),
('e3309c35-b0ff-4e72-947d-8f5f6527f907','挽唐如晦二首  其一','鄧剡','宋','宋诗','song-poetry','','[]','戰藝時人北，受書吾道東。',48,'全唐诗/poet.song.238000.json','["戰藝時人北，受書吾道東。", "俊圖開熟路，怒翼礙回風。", "勇往千人廢，豪來一世空。", "深山埋玉氣，得失付雞蟲。"]'),
('3001aabb-0eb3-491e-a009-463c02544402','挽唐如晦二首  其二','鄧剡','宋','宋诗','song-poetry','','[]','法護何妨短，元龍故自豪。',48,'全唐诗/poet.song.238000.json','["法護何妨短，元龍故自豪。", "交情如水淡，義氣與秋高。", "貧不霑三釜，年方見二毛。", "魂兮如可返，通飲讀離騷。"]'),
('9089a714-2eec-4ae0-8e98-44514ae04d37','挽文魁母齊魏國夫人三首  其一','鄧剡','宋','宋诗','song-poetry','','[]','客談剪髻德，鄰識斷機心。',48,'全唐诗/poet.song.238000.json','["客談剪髻德，鄰識斷機心。", "梭壁風雲早，諼春雨露深。", "安輿神物相，歸旐路足欽。", "滂母猶難比，生兒振古今。"]'),
('f1a3fa93-fb63-4a25-998e-49c36366b8bd','挽文魁母齊魏國夫人三首  其二','鄧剡','宋','宋诗','song-poetry','','[]','色養從予季，全忠付伯兮。',48,'全唐诗/poet.song.238000.json','["色養從予季，全忠付伯兮。", "一心陵事漢，數語賈興齊。", "海嶺太多幸，崦嵫日遽西。", "猶憐兼國命，鸞誥濕金泥。"]'),
('f93ef195-b0de-4344-8acb-938080a91193','挽文魁母齊魏國夫人三首  其三','鄧剡','宋','宋诗','song-poetry','','[]','兩公兄弟我，我亦母夫人。',48,'全唐诗/poet.song.238000.json','["兩公兄弟我，我亦母夫人。", "侍疾番禺藥，行封海道綸。", "孤窮空後死，俯仰欲誰親。", "不盡西州淚，陶阡杳去塵。"]'),
('8b084655-af24-4884-83c8-19c46b7e2213','鷓鴣','鄧剡','宋','宋诗','song-poetry','','[]','行不得也哥哥。',46,'全唐诗/poet.song.238000.json','["行不得也哥哥。", "瘦妻弱子羸牸馱，天長地闊多網羅。", "南音漸少北音多，肉飛不起可奈何。", "行不得也哥哥。"]'),
('5f6f954c-0590-4a83-bc27-306c0b811905','步月  其一','鄧剡','宋','宋诗','song-poetry','','[]','皓月流華光，微霄曖虛碧。',72,'全唐诗/poet.song.238000.json','["皓月流華光，微霄曖虛碧。", "空庭四無人，及此美□夕。", "霏微弄香霧，淡蕩舒玉色。", "離離花影斜，梢梢蘭露滴。", "頹然意忘倦，欲起還自惜。", "春情諒難得，後夜空相憶。"]'),
('e2c65c4f-a837-46f8-bd37-b942f22a31ea','步月  其二','鄧剡','宋','宋诗','song-poetry','','[]','盈盈當春月，含情隔幽櫺。',71,'全唐诗/poet.song.238000.json','["盈盈當春月，含情隔幽櫺。", "好懷自制，起坐可一庭。", "娟娟吐微雲，迢迢映華星。", "不寢步芳陰，裴回惜娉娉。", "百蟲未敢怨，卉木正葱青。", "餘光散草露，乃復似秋螢。"]'),
('c011ebc6-7984-438f-81f9-22f563bd191a','曉逕','鄧剡','宋','宋诗','song-poetry','','[]','曉風吹衆綠，中含露氣清。',72,'全唐诗/poet.song.238000.json','["曉風吹衆綠，中含露氣清。", "振袂起行散，逍遙覺身輕。", "愛彼薝蔔香，淡然無世情。", "依稀龐家女，提籃映籬行。", "雖無膏沐意，皓質玉雪明。", "相看味禪悅，何必話無生。"]'),
('d2cba8c7-e850-4465-bb07-f6d693158feb','暑夕','鄧剡','宋','宋诗','song-poetry','','[]','暑夕不能寐，起坐林間亭。',72,'全唐诗/poet.song.238000.json','["暑夕不能寐，起坐林間亭。", "齧鼠欺黑月，流螢亂飛星。", "星河光淡泊，不辨草樹青。", "泥泥涼露下，稍稍殘夢醒。", "幽蟲故兒女，私語如相譍。", "鄰鐘自何來，迢迢入孤聽。"]'),
('1410b78c-8fa0-4bcb-b92d-2336d006c268','夜聞風聲歸思浩然','鄧剡','宋','宋诗','song-poetry','','[]','西風響高樹，鄉夢去帆前。',48,'全唐诗/poet.song.238000.json','["西風響高樹，鄉夢去帆前。", "稚子衡門下，先塋亂葉邊。", "老來多一出，歸去恰經年。", "海燕巢何晚，秋期落爾先。"]'),
('4a9bca3d-d878-4d33-855f-55782caf7300','礱山','鄧剡','宋','宋诗','song-poetry','','[]','斜陽客如畫，路轉叢薄間。',24,'全唐诗/poet.song.238000.json','["斜陽客如畫，路轉叢薄間。", "驚禽忽衝起，似石投前山。"]'),
('6a54dfc3-0835-434b-835c-27874f9b7821','午坐後亭','鄧剡','宋','宋诗','song-poetry','','[]','隔簾遲日午風微，社燕驚寒未肯歸。',32,'全唐诗/poet.song.238000.json','["隔簾遲日午風微，社燕驚寒未肯歸。", "讀了丹經成默坐，時時一片杏花飛。"]'),
('370e786e-4778-4f6e-90aa-94962fac3191','望夫山','鄧剡','宋','宋诗','song-poetry','','[]','朝望夫，暮望夫，一夕化作山石枯。',28,'全唐诗/poet.song.238000.json','["朝望夫，暮望夫，一夕化作山石枯。", "潮水去却回，行人來不來。"]'),
('089bc27b-2b0d-4a2b-886a-f559113d90be','簡寂觀','鄧剡','宋','宋诗','song-poetry','','[]','一逕兩山合，迢迢入青空。',108,'全唐诗/poet.song.238000.json','["一逕兩山合，迢迢入青空。", "前橫交劍流，後倚疊雲屏。", "平生三笑圖，此日丹元庭。", "雙瀑隱如畫，可玩不可聽。", "東瀑更飄灑，珠璣落青冥。", "丹井久湮蕪，蛻骨何由靈。", "何年老鶴歸，松檜語丁寧。", "苦竹不肯筍，知此味甘馨。", "秋深石壇冷，液液枕參橫。"]'),
('47208b8a-c81f-446b-8880-70e81ab7bb00','報先寺','鄧剡','宋','宋诗','song-poetry','','[]','我是人間未了僧，蒼崖如夢昔經行。',64,'全唐诗/poet.song.238000.json','["我是人間未了僧，蒼崖如夢昔經行。", "爐中香願猶餘燼，石上精魂又一生。", "絕嶂猿啼驚犬吠，四山屏合護鐘聲。", "何當緣業人間滿，孤擁秋衾坐五更。"]'),
('8f18d91e-a653-423f-b76a-85b3a1b660a5','書烏龍山','鄧剡','宋','宋诗','song-poetry','','[]','歲云暮矣可奈何，雲愁雨濕陰風多。',64,'全唐诗/poet.song.238000.json','["歲云暮矣可奈何，雲愁雨濕陰風多。", "林壑摧殘海驚波，慘淡一色無山河。", "哀鳴嗷嗷舊枝柯，飛天不容憂虞羅。", "深山短景孤鳥過，會看明午風日和。"]'),
('f29b2682-654b-488d-a133-78f04d9b7938','跋劉敏叔畫楊誠齋先生探梅圖','鄧剡','宋','宋诗','song-poetry','','[]','夜起詩翁吟骨健，雪寒梅瘦月初生。',32,'全唐诗/poet.song.238000.json','["夜起詩翁吟骨健，雪寒梅瘦月初生。", "誰教霜月閑描畫，景物和人成五清。"]'),
('f3242f6a-98ee-4667-b2b5-5ab1998446d9','題龍山鐘','鄧剡','宋','宋诗','song-poetry','','[]','豐山背後鐘，霜月平原定。',48,'全唐诗/poet.song.238000.json','["豐山背後鐘，霜月平原定。", "夜半響鯨音，隱隱天地應。", "山靈鶴夢醒，獨聽還獨詠。", "蕭蕭蓬蒿中，收入杜陵徑。"]'),
('b492574d-db94-47e3-be7c-61822a5f228c','避亂至烏巖山贈承節趙公','鄧剡','宋','宋诗','song-poetry','','[]','流水桃花又避秦，誅茅西崦結爲鄰。',64,'全唐诗/poet.song.238000.json','["流水桃花又避秦，誅茅西崦結爲鄰。", "如公尚友浮丘伯，顧我早師梅子真。", "棋酒從容新里社，衣冠蕭散古遺民。", "他年史傳收芳跡，應許牽聯作隱人。"]'),
('47adc72b-34f6-408a-a106-828b0ee4b696','洛思山','徐天祐','宋','宋诗','song-poetry','','[]','歸去蹉跎歲月深，羈愁無示故鄉心。',32,'全唐诗/poet.song.238000.json','["歸去蹉跎歲月深，羈愁無示故鄉心。", "人生畢竟俱懷土，莊舄當時自越吟。"]'),
('70e510c3-18b1-42fb-8565-35429b13965c','許詢園','徐天祐','宋','宋诗','song-poetry','','[]','高棲不受鶴書招，北幹家園久寂寥。',32,'全唐诗/poet.song.238000.json','["高棲不受鶴書招，北幹家園久寂寥。", "明月空懷人姓許，故山猶自岫名蕭。"]'),
('c14ddc2d-47eb-4d0e-a910-917b30dab5e5','簞醪河','徐天祐','宋','宋诗','song-poetry','','[]','往事悠悠逝水知，臨流尚想報吳時。',32,'全唐诗/poet.song.238000.json','["往事悠悠逝水知，臨流尚想報吳時。", "一壺能遣三軍醉，不比商家酒作池。"]'),
('f8426069-7732-4cfa-ac3e-ae5eb091a77b','錢王祠','徐天祐','宋','宋诗','song-poetry','','[]','石檻山前結駟遊，故鄉霞錦遍林丘。',32,'全唐诗/poet.song.238000.json','["石檻山前結駟遊，故鄉霞錦遍林丘。", "祇今東府空遺廟，露立唐碑老樹秋。"]'),
('5d03ca70-6b03-4600-8a21-62ae46f16368','方干島','徐天祐','宋','宋诗','song-poetry','','[]','平生心事白歐知，一卷雲菴處士詩。',32,'全唐诗/poet.song.238000.json','["平生心事白歐知，一卷雲菴處士詩。", "占得鏡中奇絕處，祇緣身值廣明時。"]'),
('a9dc580b-cdb0-464d-9a5d-0b30b7c89aed','白樓亭','徐天祐','宋','宋诗','song-poetry','','[]','江左名流共往還，白樓何許只青山。',32,'全唐诗/poet.song.238000.json','["江左名流共往還，白樓何許只青山。", "不須商略閑今古，物換星移俯仰間。"]'),
('d625edd6-2081-4e9b-9a45-bea8ebb5cc76','孺子亭','宗必經','宋','宋诗','song-poetry','','[]','連天大廈莫容身，小向潰湖邊一問津。',64,'全唐诗/poet.song.238000.json','["連天大廈莫容身，小向潰湖邊一問津。", "心事說知林郭，姓名誤入府中陳。", "半篙綠水三間屋，一榻清風百世人。", "只有青青堤上柳，至今猶是漢時春。"]'),
('e52c941d-f40c-4b70-b8fb-73d4a8f77855','滕王閣','宗必經','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6ed5\u738b\u9601"]','高閣連城十二欄，西風領客共躋攀。',64,'全唐诗/poet.song.238000.json','["高閣連城十二欄，西風領客共躋攀。", "半簾煙雨長江外，千里湖山咫尺間。", "雁带秋聲歸別浦，鶯分春色過巴山。", "當年蛺蝶知誰畫，一夢莊周去不還。"]'),
('373e2590-0c81-48dd-88d0-2c1b82cefe3d','南浦','宗必經','宋','宋诗','song-poetry','','[]','江到南關古渡頭，旁分一曲入溪流。',64,'全唐诗/poet.song.238000.json','["江到南關古渡頭，旁分一曲入溪流。", "垂楊夾道三千戶，遶郭連檣數萬舟。", "春水綠波芳草渡，秋風明月白蘋洲。", "滔滔出舍紅塵派，一棹中流萬頃秋。"]'),
('a2a474c6-4c5e-4d85-94f9-7e3fb100a06b','句  其一','宗必經','宋','宋诗','song-poetry','','[]','睡晨方知前是夢，落花難上舊來枝。',16,'全唐诗/poet.song.238000.json','["睡晨方知前是夢，落花難上舊來枝。"]'),
('bd521921-96ae-4ca2-b60d-5d20cd9a6652','句  其二','宗必經','宋','宋诗','song-poetry','','[]','不覺授書冬再易，我思暴霸欲消魂。',16,'全唐诗/poet.song.238000.json','["不覺授書冬再易，我思暴霸欲消魂。"]'),
('a3f3bd89-651a-422d-b557-950de706edb2','費拾遺書堂','江景春','宋','宋诗','song-poetry','','[]','投閒深感聖君恩，放浪華山酒滿樽。',64,'全唐诗/poet.song.238000.json','["投閒深感聖君恩，放浪華山酒滿樽。", "高下數峯撐日月，東南一柱壯乾坤。", "雁拖秋色迷漁浦，鴉背斜陽過洞門。", "偶聽山中風水響，恐疑仙樂和朝垣。"]'),
('7d496eea-027b-40ab-bfa0-274a8ccdb03c','疎齋以舊作題淵明歸來圖詩見贈依韻奉和','潘從大','宋','宋诗','song-poetry','','[]','公歸豈爲三徑松，取節荆軻讎祖龍。',144,'全唐诗/poet.song.238000.json','["公歸豈爲三徑松，取節荆軻讎祖龍。", "平生大義要其終，遁身甘混田舍翁。", "肯隨一世皆尚同，言言易水詩見志。", "撫卷陡覺辭深雄，誰知筆補造化工。", "寓懷麯糵匪轢醉，孤忠耿耿蟠心胸。", "紆轡幾許塵埃中，柴桑不與車馬通。", "八表同昏雨濛濛，皦日行天西復東。", "當年榮木隨時窮，黄花今猶傲秋風。", "拜公遺像讀公傳，眼高千載爲之空。"]'),
('64d7a718-74f9-4076-9ddb-3ac5ed636bbd','疎齋用前韻記響山之遊依韻奉答','潘從大','宋','宋诗','song-poetry','','[]','空山在昔森萬松，兩賢曾此登虬龍。',143,'全唐诗/poet.song.238000.json','["空山在昔森萬松，兩賢曾此登虬龍。", "流風餘韻無時終，我來寒棲鬢成翁。", "人生出處何心同，夢破邯鄲幾富貴。", "戰退蠻觸相長雄，靜定要與山爭功。", "繡衣光華照巖壑，豁然納我雲夢胸。", "羣峯飛翠匏樽中，仙源還□漁舟通。", "須臾煙霏散空濛，樓觀隱約孤城東。", "感慨千古思無窮，嘯歌抵掌生英風。", "黄金易求此樂少，野人何計瓢空。"]'),
('03424b54-8aee-4ab6-881d-ea26d7832ba8','贈無菴沈相師','潘從大','宋','宋诗','song-poetry','','[]','喜見人間百歲翁，青鞋藜杖步如風。',64,'全唐诗/poet.song.238000.json','["喜見人間百歲翁，青鞋藜杖步如風。", "一菴無處知身幻，四海行來覺眼空。", "論相又看新進士，挑詩多識舊名公。", "承平往事誰知得，閑聽高談夢寐同。"]'),
('41b1dbf1-9030-47b1-affc-8033d04fa66e','謝張御史見訪','潘從大','宋','宋诗','song-poetry','','[]','綠滿山人屐齒苔，蓬門長日爲誰開。',32,'全唐诗/poet.song.238000.json','["綠滿山人屐齒苔，蓬門長日爲誰開。", "那知御史秋霜筆，携得春風滿袖來。"]'),
('286fae07-0209-45cc-91d1-0091577d4c18','謝人惠魚米','潘從大','宋','宋诗','song-poetry','','[]','讀書干祿不醫貧，饌厭寒葅甑欲塵。',64,'全唐诗/poet.song.238000.json','["讀書干祿不醫貧，饌厭寒葅甑欲塵。", "自笑凄涼彈鋏客，欣逢慷慨指囷人。", "江南縮項鮮堪鱠，浙右長腰色勝銀。", "盂飯杯羹飽捫腹，鬢邁歲事又從新。"]'),
('69723e7d-6f38-45da-a81f-6b1fa4354eb9','劉龍洲祠','凌萬頃','宋','宋诗','song-poetry','','[]','嘗隨薦鶚上天閽，肯信荒山泣斷魂。',64,'全唐诗/poet.song.238000.json','["嘗隨薦鶚上天閽，肯信荒山泣斷魂。", "百歲光陰隨酒盡，一生氣概祇詩存。", "冢傾平地藤蘿合，碑倚空巖霧雨昏。", "縱是紙灰那得到，落花寒食不開門。"]'),
('708d8f91-5b8e-43ca-91e0-dcbd8ef05a3e','題汪水雲詩卷','李嘉龍','宋','宋诗','song-poetry','','[]','江湖牢落歎蘧年，說着乾淳淚泫然。',64,'全唐诗/poet.song.238000.json','["江湖牢落歎蘧年，說着乾淳淚泫然。", "折桂昔爲天上客，餐松今作洞中仙。", "南窗寄傲陶元亮，東海歸來魯仲連。", "紫鳳天吳顛倒褐，抱琴又泛楚江船。"]'),
('0838e2a1-5ce2-4d90-b6fd-3be8fce9222f','大滌洞','王煓','宋','宋诗','song-poetry','','[]','軋軋籃輿松徑間，晚風吹雨逼人寒。',64,'全唐诗/poet.song.238000.json','["軋軋籃輿松徑間，晚風吹雨逼人寒。", "斷崖蹲虎停雲濕，一水飛蛟醉眼看。", "空翠萬重藏絕景，夜光千丈浴神丹。", "青鞋布襪吾能辦，未覺丹軀羽化難。"]'),
('3aba7e21-f8f6-4f0b-8a80-d7561ef7b9aa','賈師憲望海樓成次韻  其一','陳宜中','宋','宋诗','song-poetry','','[]','名與山高千古重，恩如海闊一身輕。',32,'全唐诗/poet.song.238000.json','["名與山高千古重，恩如海闊一身輕。", "門下少年初幕府，格隨諸吏上崢嶸。"]'),
('7de1aca0-d96d-42db-bfa9-6687fe92d233','賈師憲望海樓成次韻  其二','陳宜中','宋','宋诗','song-poetry','','[]','功歸再造金甌好，歲已三登玉燭調。',32,'全唐诗/poet.song.238000.json','["功歸再造金甌好，歲已三登玉燭調。", "昨是倚筇平地看，一如石壁望松寥。"]'),
('50fde0af-2201-44d1-85c0-8efcf0a64269','如占城經吳川極浦亭','陳宜中','宋','宋诗','song-poetry','','[]','顛風吹雨過吳川，極浦亭前望遠天。',64,'全唐诗/poet.song.238000.json','["顛風吹雨過吳川，極浦亭前望遠天。", "有路可通環嶼外，無山堪並首陽巓。", "溪雲起處潮初長，夜月高時人未助。", "異日北歸須記取，平蕪盡處一峯圓。"]'),
('41d755b9-70ea-4e2f-b8ba-6ed5631f169b','題浮玉山居圖','錢選','宋','宋诗','song-poetry','','[]','瞻彼南山岑，白雲何翩翩。',72,'全唐诗/poet.song.238000.json','["瞻彼南山岑，白雲何翩翩。", "下有幽棲人，嘯歌樂徂年。", "叢石映清泚，嘉木澹芳妍。", "日月無終極，陵谷從變遷。", "神襟軼寥廓，興寄揮五絃。", "塵彯一以絕，招隱奚足言。"]'),
('18e6185e-7701-4438-a1a8-7bbc9bb3827e','題桃源圖','錢選','宋','宋诗','song-poetry','','[]','始信桃源隔幾秦，後來無復問津人。',32,'全唐诗/poet.song.238000.json','["始信桃源隔幾秦，後來無復問津人。", "武陵不是花開晚，流到人間却暮春。"]'),
('f2343b8a-56c2-4121-a2bb-462188f3968b','題金碧山水卷  其一','錢選','宋','宋诗','song-poetry','','[]','目窮千里筆不到，自是餘生坐太凡。',32,'全唐诗/poet.song.238000.json','["目窮千里筆不到，自是餘生坐太凡。", "一日興來何可遏，開窗寫出碧巖巖。"]'),
('9fc0699c-cbf9-4b55-92da-a2df474bfc60','題金碧山水卷  其二','錢選','宋','宋诗','song-poetry','','[]','江南北苑出奇才，千里溪山筆底回。',32,'全唐诗/poet.song.238000.json','["江南北苑出奇才，千里溪山筆底回。", "不管六朝興廢事，一樽且向畫圖開。"]'),
('38bb24ae-0a1f-46ba-a319-7e7bdf647ade','題金碧山水卷  其三','錢選','宋','宋诗','song-poetry','','[]','煙雲出沒有無間，半在空虛半在山。',32,'全唐诗/poet.song.238000.json','["煙雲出沒有無間，半在空虛半在山。", "我亦閒中消日月，幽林深處聽潺湲。"]'),
('c43a3505-61e3-4b9b-a65c-1fa7996da410','題金碧山水卷  其四','錢選','宋','宋诗','song-poetry','','[]','胸中得酒出孱顔，木葉森森歲暮殘。',32,'全唐诗/poet.song.238000.json','["胸中得酒出孱顔，木葉森森歲暮殘。", "落墨不隨嵐氣暝，幾重山色幾重瀾。"]'),
('a1550ea5-341a-4849-bb61-950f28d42a21','題洪崖先生像','錢選','宋','宋诗','song-poetry','','[]','神駕馭倒景，太虛時總轡。',48,'全唐诗/poet.song.238000.json','["神駕馭倒景，太虛時總轡。", "玄道不可分，直悟天人際。", "羣從皆成仙，玩世不計年。", "何當事神遊，許我笑拍肩。"]'),
('3e67a15b-764c-4a2b-b895-f74b5d479778','題竹林七賢圖','錢選','宋','宋诗','song-poetry','','[]','昔人好沈酣，人事不復理。',48,'全唐诗/poet.song.238000.json','["昔人好沈酣，人事不復理。", "但進杯中物，應世聊爾爾。", "悠悠天地間，媮樂本無愧。", "諸賢各有心，流俗毋輕議。"]'),
('4a9744bc-2487-4e29-ba41-86a32cade715','題仇書圖','錢選','宋','宋诗','song-poetry','','[]','兩兩挾策遊康衢，聚戲不異同隊魚。',32,'全唐诗/poet.song.238000.json','["兩兩挾策遊康衢，聚戲不異同隊魚。", "忽然兒態起爭競，捐棄篋笥仇詩書。"]'),
('03139883-89e6-45cb-be75-fb864a8ae782','題復州裂本蘭亭','錢選','宋','宋诗','song-poetry','','[]','鼠鬚注硯寫流觴，一入書林久復藏。',32,'全唐诗/poet.song.238000.json','["鼠鬚注硯寫流觴，一入書林久復藏。", "二十八行經進字，回頭不比在塵樑。"]'),
('d62e2c66-ae59-4dc1-b37e-4922573b7d5d','題孤山圖','錢選','宋','宋诗','song-poetry','','[]','一童一鶴兩相隨，閒步梅邊賦小詩。',32,'全唐诗/poet.song.238000.json','["一童一鶴兩相隨，閒步梅邊賦小詩。", "疎影暗香真絕句，至今誰復繼新辭。"]'),
('9db821bb-5bd9-4756-8146-53e369945385','題戲嬰圖','錢選','宋','宋诗','song-poetry','','[]','殿閣森森氣自清，不知人世有蓬瀛。',32,'全唐诗/poet.song.238000.json','["殿閣森森氣自清，不知人世有蓬瀛。", "日長無事宮中樂，閒與諸姬伴戲嬰。"]'),
('d1b0f8ed-2c8b-4ffc-9992-d50e15ac60cd','題水仙卷','錢選','宋','宋诗','song-poetry','','[]','帝子不沈湘，亭亭絕世妝。',48,'全唐诗/poet.song.238000.json','["帝子不沈湘，亭亭絕世妝。", "曉煙橫薄袂，秋瀨韻明璫。", "洛浦應求友，姚家合讓王。", "殷勤歸水部，雅意在分香。"]'),
('36fd2e41-1f99-4f3c-aa9f-ffd56adb82bb','題雪霽望弁山圖  其一','錢選','宋','宋诗','song-poetry','','[]','弁山之陽冠吳興，峮嶙巀嶭望不平。',64,'全唐诗/poet.song.238000.json','["弁山之陽冠吳興，峮嶙巀嶭望不平。", "煥然僊宫隠其下，衆山所仰青復青。", "雪花夜積山如換，乘興行舟須放緩。", "平生不識五老峰，且冩吾鄉一竒觀。"]'),
('52211903-9932-45a2-8a8e-67814e9b008a','題雪霽望弁山圖  其二','錢選','宋','宋诗','song-poetry','','[]','夜來天雨雪，萬木同一變。',48,'全唐诗/poet.song.238000.json','["夜來天雨雪，萬木同一變。", "饑鴉覺余起，觀覽立須儼。", "遥山瓊成積，平田玉如碾。", "老夫醒眼看，樹樹何其燦。"]'),
('95a70c1d-74c8-447f-ab75-54e08ca5e7da','題雪霽望弁山圖  其三','錢選','宋','宋诗','song-poetry','','[]','城市我所居，遥看弁山雄。',84,'全唐诗/poet.song.238000.json','["城市我所居，遥看弁山雄。", "積雪最先見，皓影照諸峰。", "我今逺城市，薄逰留此中。", "忽焉歲云暮，更覺樽屡空。", "開門未然燭，飛花舞廻風。", "萬木同一縞，四野變其容。", "恨無登山屐，幽討何由窮。"]'),
('301dbb05-aa13-4d3e-84eb-6fdbd12160ad','題雪霽望弁山圖  其四','錢選','宋','宋诗','song-poetry','','[]','倚天蒼弁獨崔嵬，仙闕逰遨愧不才。',64,'全唐诗/poet.song.238000.json','["倚天蒼弁獨崔嵬，仙闕逰遨愧不才。", "攬鏡頻嗟雙鬢改，推窗三見六花開。", "山中酒户衝寒去，城裏行人踏雪來。", "安得時晴風日好，竹林深處且啣杯。"]');
